// Do not edit by hand — regenerate with scripts/generate-bible.

const book: BibleBook = {
  id: 'exodus',
  name: 'Êxodo',
  englishName: 'Exodus',
  testament: 'old',
  chapters: {
    1: [
      { v: 1, en: 'Now these are the names of the sons of Israel, who came into Egypt (every man and his household came with Jacob):', pt: 'Ora, estes são os nomes dos filhos de Israel, que entraram no Egito; entraram com Jacó, cada um com a sua família:' },
      { v: 2, en: 'Reuben, Simeon, Levi, and Judah,', pt: 'Rúben, Simeão, Levi, e Judá;' },
      { v: 3, en: 'Issachar, Zebulun, and Benjamin,', pt: 'Issacar, Zebulom e Benjamim;' },
      { v: 4, en: 'Dan and Naphtali, Gad and Asher.', pt: 'Dã e Naftali, Gade e Aser.' },
      { v: 5, en: 'All the souls who came out of Jacob’s body were seventy souls, and Joseph was in Egypt already.', pt: 'Todas as almas, pois, que procederam da coxa de Jacó, foram setenta; José, porém, já estava no Egito.' },
      { v: 6, en: 'Joseph died, as did all his brothers, and all that generation.', pt: 'Morreu, pois, José, e todos os seus irmãos, e toda aquela geração.' },
      { v: 7, en: 'The children of Israel were fruitful, and increased abundantly, and multiplied, and grew exceedingly mighty; and the land was filled with them.', pt: 'Depois os filhos de Israel frutificaram e aumentaram muito, multiplicaram-se e tornaram-se sobremaneira fortes, de modo que a terra se encheu deles.' },
      { v: 8, en: 'Now there arose a new king over Egypt, who didn’t know Joseph.', pt: 'Entrementes se levantou sobre o Egito um novo rei, que não conhecera a José.' },
      { v: 9, en: 'He said to his people, “Behold, the people of the children of Israel are more and mightier than we.', pt: 'Disse ele ao seu povo: Eis que o povo de Israel é mais numeroso e mais forte do que nos.' },
      { v: 10, en: 'Come, let us deal wisely with them, lest they multiply, and it happen that when any war breaks out, they also join themselves to our enemies, and fight against us, and escape out of the land.”', pt: 'Eia, usemos de astúcia para com ele, para que não se multiplique, e aconteça que, vindo guerra, ele também se ajunte com os nossos inimigos, e peleje contra nós e se retire da terra.' },
      { v: 11, en: 'Therefore they set taskmasters over them to afflict them with their burdens. They built storage cities for Pharaoh: Pithom and Raamses.', pt: 'Portanto puseram sobre eles feitores, para os afligirem com suas cargas. Assim os israelitas edificaram para Faraó cidades armazéns, Pitom e Ramessés.' },
      { v: 12, en: 'But the more they afflicted them, the more they multiplied and the more they spread out. They were grieved because of the children of Israel.', pt: 'Mas quanto mais os egípcios afligiam o povo de Israel, tanto mais este se multiplicava e se espalhava; de maneira que os egípcios se enfadavam por causa dos filhos de Israel.' },
      { v: 13, en: 'The Egyptians ruthlessly made the children of Israel serve,', pt: 'Por isso os egípcios faziam os filhos de Israel servir com dureza;' },
      { v: 14, en: 'and they made their lives bitter with hard service, in mortar and in brick, and in all kinds of service in the field, all their service, in which they ruthlessly made them serve.', pt: 'assim lhes amarguravam a vida com pesados serviços em barro e em tijolos, e com toda sorte de trabalho no campo, enfim com todo o seu serviço, em que os faziam servir com dureza.' },
      { v: 15, en: 'The king of Egypt spoke to the Hebrew midwives, of whom the name of the one was Shiphrah, and the name of the other Puah,', pt: 'Falou o rei do Egito às parteiras das hebréias, das quais uma se chamava Sifrá e a outra Puá,' },
      { v: 16, en: 'and he said, “When you perform the duty of a midwife to the Hebrew women, and see them on the birth stool; if it is a son, then you shall kill him; but if it is a daughter, then she shall live.”', pt: 'dizendo: Quando ajudardes no parto as hebréias, e as virdes sobre os assentos, se for filho, matá-lo-eis; mas se for filha, viverá.' },
      { v: 17, en: 'But the midwives feared God, and didn’t do what the king of Egypt commanded them, but saved the baby boys alive.', pt: 'As parteiras, porém, temeram a Deus e não fizeram como o rei do Egito lhes ordenara, antes conservavam os meninos com vida.' },
      { v: 18, en: 'The king of Egypt called for the midwives, and said to them, “Why have you done this thing, and have saved the boys alive?”', pt: 'Pelo que o rei do Egito mandou chamar as parteiras e as interrogou: Por que tendes feito isto e guardado os meninos com vida?' },
      { v: 19, en: 'The midwives said to Pharaoh, “Because the Hebrew women aren’t like the Egyptian women; for they are vigorous, and give birth before the midwife comes to them.”', pt: 'Responderam as parteiras a Faraó: É que as mulheres hebréias não são como as egípcias; pois são vigorosas, e já têm dado à luz antes que a parteira chegue a elas.' },
      { v: 20, en: 'God dealt well with the midwives, and the people multiplied, and grew very mighty.', pt: 'Portanto Deus fez bem às parteiras. E o povo se aumentou, e se fortaleceu muito.' },
      { v: 21, en: 'Because the midwives feared God, he gave them families.', pt: 'Também aconteceu que, como as parteiras temeram a Deus, ele lhes estabeleceu as casas.' },
      { v: 22, en: 'Pharaoh commanded all his people, saying, “You shall cast every son who is born into the river, and every daughter you shall save alive.”', pt: 'Então ordenou Faraó a todo o seu povo, dizendo: A todos os filhos que nascerem lançareis no rio, mas a todas as filhas guardareis com vida.' },
    ],
    2: [
      { v: 1, en: 'A man of the house of Levi went and took a daughter of Levi as his wife.', pt: 'Foi-se um homem da casa de Levi e casou com uma filha de Levi.' },
      { v: 2, en: 'The woman conceived, and bore a son. When she saw that he was a fine child, she hid him three months.', pt: 'A mulher concebeu e deu à luz um filho; e, vendo que ele era formoso, escondeu-o três meses.' },
      { v: 3, en: 'When she could no longer hide him, she took a papyrus basket for him, and coated it with tar and with pitch. She put the child in it, and laid it in the reeds by the river’s bank.', pt: 'Não podendo, porém, escondê-lo por mais tempo, tomou para ele uma arca de juncos, e a revestiu de betume e pez; e, pondo nela o menino, colocou-a entre os juncos a margem do rio.' },
      { v: 4, en: 'His sister stood far off, to see what would be done to him.', pt: 'E sua irmã postou-se de longe, para saber o que lhe aconteceria.' },
      { v: 5, en: 'Pharaoh’s daughter came down to bathe at the river. Her maidens walked along by the riverside. She saw the basket among the reeds, and sent her servant to get it.', pt: 'A filha de Faraó desceu para banhar-se no rio, e as suas criadas passeavam à beira do rio. Vendo ela a arca no meio os juncos, mandou a sua criada buscá-la.' },
      { v: 6, en: 'She opened it, and saw the child, and behold, the baby cried. She had compassion on him, and said, “This is one of the Hebrews’ children.”', pt: 'E abrindo-a, viu a criança, e eis que o menino chorava; então ela teve compaixão dele, e disse: Este é um dos filhos dos hebreus.' },
      { v: 7, en: 'Then his sister said to Pharaoh’s daughter, “Should I go and call a nurse for you from the Hebrew women, that she may nurse the child for you?”', pt: 'Então a irmã do menino perguntou à filha de Faraó: Queres que eu te vá chamar uma ama dentre as hebréias, para que crie este menino para ti?' },
      { v: 8, en: 'Pharaoh’s daughter said to her, “Go.” The young woman went and called the child’s mother.', pt: 'Respondeu-lhe a filha de Faraó: Vai. Foi, pois, a moça e chamou a mãe do menino.' },
      { v: 9, en: 'Pharaoh’s daughter said to her, “Take this child away, and nurse him for me, and I will give you your wages.” The woman took the child, and nursed it.', pt: 'Disse-lhe a filha de Faraó: Leva este menino, e cria-mo; eu te darei o teu salário. E a mulher tomou o menino e o criou.' },
      { v: 10, en: 'The child grew, and she brought him to Pharaoh’s daughter, and he became her son. She named him Moses, and said, “Because I drew him out of the water.”', pt: 'Quando, pois, o menino era já grande, ela o trouxe à filha de Faraó, a qual o adotou; e lhe chamou Moisés, dizendo: Porque das águas o tirei.' },
      { v: 11, en: 'In those days, when Moses had grown up, he went out to his brothers, and looked at their burdens. He saw an Egyptian striking a Hebrew, one of his brothers.', pt: 'Ora, aconteceu naqueles dias que, sendo Moisés já homem, saiu a ter com seus irmãos e atentou para as suas cargas; e viu um egípcio que feria a um hebreu dentre, seus irmãos.' },
      { v: 12, en: 'He looked this way and that way, and when he saw that there was no one, he killed the Egyptian, and hid him in the sand.', pt: 'Olhou para um lado e para outro, e vendo que não havia ninguém ali, matou o egipcio e escondeu-o na areia.' },
      { v: 13, en: 'He went out the second day, and behold, two men of the Hebrews were fighting with each other. He said to him who did the wrong, “Why do you strike your fellow?”', pt: 'Tornou a sair no dia seguinte, e eis que dois hebreus contendiam; e perguntou ao que fazia a injustiça: Por que feres a teu próximo?' },
      { v: 14, en: 'He said, “Who made you a prince and a judge over us? Do you plan to kill me, as you killed the Egyptian?” Moses was afraid, and said, “Surely this thing is known.”', pt: 'Respondeu ele: Quem te constituiu a ti príncipe e juiz sobre nós? Pensas tu matar-me, como mataste o egípcio? Temeu, pois, Moisés e disse: Certamente o negócio já foi descoberto.' },
      { v: 15, en: 'Now when Pharaoh heard this thing, he sought to kill Moses. But Moses fled from the face of Pharaoh, and lived in the land of Midian, and he sat down by a well.', pt: 'E quando Faraó soube disso, procurou matar a Moisés. Este, porém, fugiu da presença de Faraó, e foi habitar na terra de Midiã; e sentou-se junto a um poço.' },
      { v: 16, en: 'Now the priest of Midian had seven daughters. They came and drew water, and filled the troughs to water their father’s flock.', pt: 'O sacerdote de Midiã tinha sete filhas, as quais vieram tirar água, e encheram os tanques para dar de beber ao rebanho de seu pai.' },
      { v: 17, en: 'The shepherds came and drove them away; but Moses stood up and helped them, and watered their flock.', pt: 'Então vieram os pastores, e as expulsaram dali; Moisés, porém, levantou-se e as defendeu, e deu de beber ao rebanho delas.' },
      { v: 18, en: 'When they came to Reuel, their father, he said, “How is it that you have returned so early today?”', pt: 'Quando elas voltaram a Reuel, seu pai, este lhes perguntou: como é que hoje voltastes tão cedo?' },
      { v: 19, en: 'They said, “An Egyptian delivered us out of the hand of the shepherds, and moreover he drew water for us, and watered the flock.”', pt: 'Responderam elas: um egípcio nos livrou da mão dos pastores; e ainda tirou água para nós e deu de beber ao rebanho.' },
      { v: 20, en: 'He said to his daughters, “Where is he? Why is it that you have left the man? Call him, that he may eat bread.”', pt: 'E ele perguntou a suas filhas: Onde está ele; por que deixastes lá o homem? chamai-o para que coma pão.' },
      { v: 21, en: 'Moses was content to dwell with the man. He gave Moses Zipporah, his daughter.', pt: 'Então Moisés concordou em marar com aquele homem, o qual lhe deu sua filha Zípora.' },
      { v: 22, en: 'She bore a son, and he named him Gershom, for he said, “I have lived as a foreigner in a foreign land.”', pt: 'E ela deu à luz um filho, a quem ele chamou Gérson, porque disse: Peregrino sou em terra estrangeira.' },
      { v: 23, en: 'In the course of those many days, the king of Egypt died, and the children of Israel sighed because of the bondage, and they cried, and their cry came up to God because of the bondage.', pt: 'No decorrer de muitos dias, morreu o rei do Egito; e os filhos de Israel gemiam debaixo da servidão; pelo que clamaram, e subiu a Deus o seu clamor por causa dessa servidão.' },
      { v: 24, en: 'God heard their groaning, and God remembered his covenant with Abraham, with Isaac, and with Jacob.', pt: 'Então Deus, ouvindo-lhes os gemidos, lembrou-se do seu pacto com Abraão, com Isaque e com Jacó.' },
      { v: 25, en: 'God saw the children of Israel, and God was concerned about them.', pt: 'E atentou Deus para os filhos de Israel; e Deus os conheceu.' },
    ],
    3: [
      { v: 1, en: 'Now Moses was keeping the flock of Jethro, his father-in-law, the priest of Midian, and he led the flock to the back of the wilderness, and came to God’s mountain, to Horeb.', pt: 'Ora, Moisés estava apascentando o rebanho de Jetro, seu sogro, sacerdote de Midiã; e levou o rebanho para trás do deserto, e chegou a Horebe, o monte de Deus.' },
      { v: 2, en: 'Yahweh’s angel appeared to him in a flame of fire out of the middle of a bush. He looked, and behold, the bush burned with fire, and the bush was not consumed.', pt: 'E apareceu-lhe o anjo do Senhor em uma chama de fogo do meio duma sarça. Moisés olhou, e eis que a sarça ardia no fogo, e a sarça não se consumia;' },
      { v: 3, en: 'Moses said, “I will go now, and see this great sight, why the bush is not burned.”', pt: 'pelo que disse: Agora me virarei para lá e verei esta maravilha, e por que a sarça não se queima.' },
      { v: 4, en: 'When Yahweh saw that he came over to see, God called to him out of the middle of the bush, and said, “Moses! Moses!” He said, “Here I am.”', pt: 'E vendo o Senhor que ele se virara para ver, chamou-o do meio da sarça, e disse: Moisés, Moisés! Respondeu ele: Eis-me aqui.' },
      { v: 5, en: 'He said, “Don’t come close. Take off your sandals, for the place you are standing on is holy ground.”', pt: 'Prosseguiu Deus: Não te chegues para cá; tira os sapatos dos pés; porque o lugar em que tu estás é terra santa.' },
      { v: 6, en: 'Moreover he said, “I am the God of your father, the God of Abraham, the God of Isaac, and the God of Jacob.” Moses hid his face; for he was afraid to look at God.', pt: 'Disse mais: Eu sou o Deus de teu pai, o Deus de Abraão, o Deus de Isaque, e o Deus de Jacó. E Moisés escondeu o rosto, porque temeu olhar para Deus.' },
      { v: 7, en: 'Yahweh said, “I have surely seen the affliction of my people who are in Egypt, and have heard their cry because of their taskmasters, for I know their sorrows.', pt: 'Então disse o Senhor: Com efeito tenho visto a aflição do meu povo, que está no Egito, e tenho ouvido o seu clamor por causa dos seus exatores, porque conheço os seus sofrimentos;' },
      { v: 8, en: 'I have come down to deliver them out of the hand of the Egyptians, and to bring them up out of that land to a good and large land, to a land flowing with milk and honey; to the place of the Canaanite, the Hittite, the Amorite, the Perizzite, the Hivite, and the Jebusite.', pt: 'e desci para o livrar da mão dos egípcios, e para o fazer subir daquela terra para uma terra boa e espaçosa, para uma terra que mana leite e mel; para o lugar do cananeu, do heteu, do amorreu, do perizeu, do heveu e do jebuseu.' },
      { v: 9, en: 'Now, behold, the cry of the children of Israel has come to me. Moreover I have seen the oppression with which the Egyptians oppress them.', pt: 'E agora, ei s que o clamor dos filhos de Israel é vindo a mim; e também tenho visto a opressão com que os egípcios os oprimem.' },
      { v: 10, en: 'Come now therefore, and I will send you to Pharaoh, that you may bring my people, the children of Israel, out of Egypt.”', pt: 'Agora, pois, vem e eu te enviarei a Faraó, para que tireis do Egito o meu povo, os filhos de Israel.' },
      { v: 11, en: 'Moses said to God, “Who am I, that I should go to Pharaoh, and that I should bring the children of Israel out of Egypt?”', pt: 'Então Moisés disse a Deus: Quem sou eu, para que vá a Faraó e tire do Egito os filhos de Israel?' },
      { v: 12, en: 'He said, “Certainly I will be with you. This will be the token to you, that I have sent you: when you have brought the people out of Egypt, you shall serve God on this mountain.”', pt: 'Respondeu-lhe Deus: Certamente eu serei contigo; e isto te será por sinal de que eu te enviei: Quando houveres tirado do Egito o meu povo, servireis a Deus neste monte.' },
      { v: 13, en: 'Moses said to God, “Behold, when I come to the children of Israel, and tell them, ‘The God of your fathers has sent me to you;’ and they ask me, ‘What is his name?’ What should I tell them?”', pt: 'Então disse Moisés a Deus: Eis que quando eu for aos filhos de Israel, e lhes disser: O Deus de vossos pais me enviou a vós; e eles me perguntarem: Qual é o seu nome? Que lhes direi?' },
      { v: 14, en: 'God said to Moses, “I AM WHO I AM,” and he said, “You shall tell the children of Israel this: ‘I AM has sent me to you.’”', pt: 'Respondeu Deus a Moisés: EU SOU O QUE SOU. Disse mais: Assim dirás aos olhos de Israel: EU SOU me enviou a vós.' },
      { v: 15, en: 'God said moreover to Moses, “You shall tell the children of Israel this, ‘Yahweh, the God of your fathers, the God of Abraham, the God of Isaac, and the God of Jacob, has sent me to you.’ This is my name forever, and this is my memorial to all generations.', pt: 'E Deus disse mais a Moisés: Assim dirás aos filhos de Israel: O Senhor, o Deus de vossos pais, o Deus de Abraão, o Deus de Isaque, e o Deus de Jacó, me enviou a vós; este é o meu nome eternamente, e este é o meu memorial de geração em geração.' },
      { v: 16, en: 'Go and gather the elders of Israel together, and tell them, ‘Yahweh, the God of your fathers, the God of Abraham, of Isaac, and of Jacob, has appeared to me, saying, “I have surely visited you, and seen that which is done to you in Egypt;', pt: 'Vai, ajunta os anciãos de Israel e dize-lhes: O Senhor, o Deus de vossos pais, o Deus de Abraão, de Isaque e de Jacó, apareceu-me, dizendo: certamente vos tenho visitado e visto o que vos tem sido feito no Egito;' },
      { v: 17, en: 'and I have said, I will bring you up out of the affliction of Egypt to the land of the Canaanite, the Hittite, the Amorite, the Perizzite, the Hivite, and the Jebusite, to a land flowing with milk and honey.”’', pt: 'e tenho dito: Far-vos-ei subir da aflição do Egito para a terra do cananeu, do heteu, do amorreu, do perizeu, do heveu e do jebuseu, para uma terra que mana leite e mel.' },
      { v: 18, en: 'They will listen to your voice, and you shall come, you and the elders of Israel, to the king of Egypt, and you shall tell him, ‘Yahweh, the God of the Hebrews, has met with us. Now please let us go three days’ journey into the wilderness, that we may sacrifice to Yahweh, our God.’', pt: 'E ouvirão a tua voz; e ireis, tu e os anciãos de Israel, ao rei do Egito, e dir-lhe-eis: O Senhor, o Deus dos hebreus, encontrou-nos. Agora, pois, deixa-nos ir caminho de três dias para o deserto para que ofereçamos sacrifícios ao Senhor nosso Deus.' },
      { v: 19, en: 'I know that the king of Egypt won’t give you permission to go, no, not by a mighty hand.', pt: 'Eu sei, porém, que o rei do Egito não vos deixará ir, a não ser por uma forte mão.' },
      { v: 20, en: 'I will reach out my hand and strike Egypt with all my wonders which I will do among them, and after that he will let you go.', pt: 'Portanto estenderei a minha mão, e ferirei o Egito com todas as minhas maravilhas que farei no meio dele. Depois vos deixará ir.' },
      { v: 21, en: 'I will give this people favor in the sight of the Egyptians, and it will happen that when you go, you shall not go empty-handed.', pt: 'E eu darei graça a este povo aos olhos dos egípcios; e acontecerá que, quando sairdes, não saireis vazios.' },
      { v: 22, en: 'But every woman shall ask of her neighbor, and of her who visits her house, jewels of silver, jewels of gold, and clothing; and you shall put them on your sons, and on your daughters. You shall plunder the Egyptians.”', pt: 'Porque cada mulher pedirá à sua vizinha e à sua hóspeda jóias de prata e jóias de ouro, bem como vestidos, os quais poreis sobre vossos filhos e sobre vossas filhas; assim despojareis os egípcios.' },
    ],
    4: [
      { v: 1, en: 'Moses answered, “But, behold, they will not believe me, nor listen to my voice; for they will say, ‘Yahweh has not appeared to you.’”', pt: 'Então respondeu Moisés: Mas eis que não me crerão, nem ouvirão a minha voz, pois dirão: O Senhor não te apareceu.' },
      { v: 2, en: 'Yahweh said to him, “What is that in your hand?” He said, “A rod.”', pt: 'Ao que lhe perguntou o Senhor: Que é isso na tua mão. Disse Moisés: uma vara.' },
      { v: 3, en: 'He said, “Throw it on the ground.” He threw it on the ground, and it became a snake; and Moses ran away from it.', pt: 'Ordenou-lhe o Senhor: Lança-a no chão. Ele a lançou no chão, e ela se tornou em cobra; e Moisés fugiu dela.' },
      { v: 4, en: 'Yahweh said to Moses, “Stretch out your hand, and take it by the tail.” He stretched out his hand, and took hold of it, and it became a rod in his hand.', pt: 'Então disse o Senhor a Moisés: Estende a mão e pega-lhe pela cauda (estendeu ele a mão e lhe pegou, e ela se tornou em vara na sua mão);' },
      { v: 5, en: '“That they may believe that Yahweh, the God of their fathers, the God of Abraham, the God of Isaac, and the God of Jacob, has appeared to you.”', pt: 'para que eles creiam que te apareceu o Senhor, o Deus de seus pais, o Deus de Abraão, o Deus de Isaque e o Deus de Jacó.' },
      { v: 6, en: 'Yahweh said furthermore to him, “Now put your hand inside your cloak.” He put his hand inside his cloak, and when he took it out, behold, his hand was leprous, as white as snow.', pt: 'Disse-lhe mais o Senhor: Mete agora a mão no seio. E meteu a mão no seio. E quando a tirou, eis que a mão estava leprosa, branca como a neve.' },
      { v: 7, en: 'He said, “Put your hand inside your cloak again.” He put his hand inside his cloak again, and when he took it out of his cloak, behold, it had turned again as his other flesh.', pt: 'Disse-lhe ainda: Torna a meter a mão no seio. (E tornou a meter a mão no seio; depois tirou-a do seio, e eis que se tornara como o restante da sua carne.)' },
      { v: 8, en: '“It will happen, if they will not believe you or listen to the voice of the first sign, that they will believe the voice of the latter sign.', pt: 'E sucederá que, se eles não te crerem, nem atentarem para o primeiro sinal, crerão ao segundo sinal.' },
      { v: 9, en: 'It will happen, if they will not believe even these two signs or listen to your voice, that you shall take of the water of the river, and pour it on the dry land. The water which you take out of the river will become blood on the dry land.”', pt: 'E se ainda não crerem a estes dois sinais, nem ouvirem a tua voz, então tomarás da água do rio, e a derramarás sobre a terra seca; e a água que tomares do rio tornar-se-á em sangue sobre a terra seca.' },
      { v: 10, en: 'Moses said to Yahweh, “O Lord, I am not eloquent, neither before now, nor since you have spoken to your servant; for I am slow of speech, and of a slow tongue.”', pt: 'Então disse Moisés ao Senhor: Ah, Senhor! eu não sou eloqüente, nem o fui dantes, nem ainda depois que falaste ao teu servo; porque sou pesado de boca e pesado de língua.' },
      { v: 11, en: 'Yahweh said to him, “Who made man’s mouth? Or who makes one mute, or deaf, or seeing, or blind? Isn’t it I, Yahweh?', pt: 'Ao que lhe replicou o Senhor: Quem faz a boca do homem? ou quem faz o mudo, ou o surdo, ou o que vê, ou o cego?. Não sou eu, o Senhor?' },
      { v: 12, en: 'Now therefore go, and I will be with your mouth, and teach you what you shall speak.”', pt: 'Vai, pois, agora, e eu serei com a tua boca e te ensinarei o que hás de falar.' },
      { v: 13, en: 'He said, “Oh, Lord, please send someone else.”', pt: 'Ele, porém, respondeu: Ah, Senhor! envia, peço-te, por mão daquele a quem tu hás de enviar.' },
      { v: 14, en: 'Yahweh’s anger burned against Moses, and he said, “What about Aaron, your brother, the Levite? I know that he can speak well. Also, behold, he comes out to meet you. When he sees you, he will be glad in his heart.', pt: 'Então se acendeu contra Moisés a ira do Senhor, e disse ele: Não é Arão, o levita, teu irmão? eu sei que ele pode falar bem. Eis que ele também te sai ao encontro, e vendo-te, se alegrará em seu coração.' },
      { v: 15, en: 'You shall speak to him, and put the words in his mouth. I will be with your mouth, and with his mouth, and will teach you what you shall do.', pt: 'Tu, pois, lhe falarás, e porás as palavras na sua boca; e eu serei com a tua boca e com a dele, e vos ensinarei o que haveis de fazer.' },
      { v: 16, en: 'He will be your spokesman to the people; and it will happen, that he will be to you a mouth, and you will be to him as God.', pt: 'E ele falará por ti ao povo; assim ele te será por boca, e tu lhe serás por Deus.' },
      { v: 17, en: 'You shall take this rod in your hand, with which you shall do the signs.”', pt: 'Tomarás, pois, na tua mão esta vara, com que hás de fazer os sinais.' },
      { v: 18, en: 'Moses went and returned to Jethro his father-in-law, and said to him, “Please let me go and return to my brothers who are in Egypt, and see whether they are still alive.” Jethro said to Moses, “Go in peace.”', pt: 'Então partiu Moisés, e voltando para Jetro, seu sogro, disse-lhe: Deixa-me, peço-te, voltar a meus irmãos, que estão no Egito, para ver se ainda vivem. Disse, pois, Jetro a Moisés: Vai-te em paz.' },
      { v: 19, en: 'Yahweh said to Moses in Midian, “Go, return into Egypt; for all the men who sought your life are dead.”', pt: 'Disse também o Senhor a Moisés em Midiã: Vai, volta para o Egito; porque morreram todos os que procuravam tirar-te a vida.' },
      { v: 20, en: 'Moses took his wife and his sons, and set them on a donkey, and he returned to the land of Egypt. Moses took God’s rod in his hand.', pt: 'Tomou, pois, Moisés sua mulher e seus filhos, e os fez montar num jumento e tornou à terra do Egito; e Moisés levou a vara de Deus na sua mão.' },
      { v: 21, en: 'Yahweh said to Moses, “When you go back into Egypt, see that you do before Pharaoh all the wonders which I have put in your hand, but I will harden his heart and he will not let the people go.', pt: 'Disse ainda o Senhor a Moisés: Quando voltares ao Egito, vê que faças diante de Faraó todas as maravilhas que tenho posto na tua mão; mas eu endurecerei o seu coração, e ele não deixará ir o povo.' },
      { v: 22, en: 'You shall tell Pharaoh, ‘Yahweh says, Israel is my son, my firstborn,', pt: 'Então dirás a Faraó: Assim diz o Senhor: Israel é meu filho, meu primogênito;' },
      { v: 23, en: 'and I have said to you, “Let my son go, that he may serve me”; and you have refused to let him go. Behold, I will kill your son, your firstborn.’”', pt: 'e eu te tenho dito: Deixa ir: meu filho, para que me sirva. mas tu recusaste deixá-lo ir; eis que eu matarei o teu filho, o teu primogênito.' },
      { v: 24, en: 'On the way at a lodging place, Yahweh met Moses and wanted to kill him.', pt: 'Ora, sucedeu no caminho, numa estalagem, que o Senhor o encontrou, e quis matá-lo.' },
      { v: 25, en: 'Then Zipporah took a flint, and cut off the foreskin of her son, and cast it at his feet; and she said, “Surely you are a bridegroom of blood to me.”', pt: 'Então Zípora tomou uma faca de pedra, circuncidou o prepúcio de seu filho e, lançando-o aos pés de Moisés, disse: Com efeito, és para mim um esposo sanguinário.' },
      { v: 26, en: 'So he let him alone. Then she said, “You are a bridegroom of blood,” because of the circumcision.', pt: 'O Senhor, pois, o deixou. Ela disse: Esposo sanguinário, por causa da circuncisão.' },
      { v: 27, en: 'Yahweh said to Aaron, “Go into the wilderness to meet Moses.” He went, and met him on God’s mountain, and kissed him.', pt: 'Disse o Senhor a Arão: Vai ao deserto, ao encontro de Moisés. E ele foi e, encontrando-o no monte de Deus, o beijou:' },
      { v: 28, en: 'Moses told Aaron all Yahweh’s words with which he had sent him, and all the signs with which he had instructed him.', pt: 'E relatou Moisés a Arão todas as palavras com que o Senhor o enviara e todos os sinais que lhe mandara.' },
      { v: 29, en: 'Moses and Aaron went and gathered together all the elders of the children of Israel.', pt: 'Então foram Moisés e Arão e ajuntaram todos os anciãos dos filhos de Israel;' },
      { v: 30, en: 'Aaron spoke all the words which Yahweh had spoken to Moses, and did the signs in the sight of the people.', pt: 'e Arão falou todas as palavras que o Senhor havia dito a Moisés e fez os sinais perante os olhos do povo.' },
      { v: 31, en: 'The people believed, and when they heard that Yahweh had visited the children of Israel, and that he had seen their affliction, then they bowed their heads and worshiped.', pt: 'E o povo creu; e quando ouviram que o Senhor havia visitado os filhos de Israel e que tinha visto a sua aflição, inclinaram-se, e adoraram.' },
    ],
    5: [
      { v: 1, en: 'Afterward Moses and Aaron came, and said to Pharaoh, “This is what Yahweh, the God of Israel, says, ‘Let my people go, that they may hold a feast to me in the wilderness.’”', pt: 'Depois foram Moisés e Arão e disseram a Faraó: Assim diz o Senhor, o Deus de Israel: Deixa ir o meu povo, para que me celebre uma festa no deserto.' },
      { v: 2, en: 'Pharaoh said, “Who is Yahweh, that I should listen to his voice to let Israel go? I don’t know Yahweh, and moreover I will not let Israel go.”', pt: 'Mas Faraó respondeu: Quem é o Senhor, para que eu ouça a sua voz para deixar ir Israel? Não conheço o Senhor, nem tampouco deixarei ir Israel.' },
      { v: 3, en: 'They said, “The God of the Hebrews has met with us. Please let us go three days’ journey into the wilderness, and sacrifice to Yahweh, our God, lest he fall on us with pestilence, or with the sword.”', pt: 'Então eles ainda falaram: O Deus dos hebreus nos encontrou; portanto deixa-nos, pedimos-te, ir caminho de três dias ao deserto, e oferecer sacrifícios ao Senhor nosso Deus, para que ele não venha sobre nós com pestilência ou com espada.' },
      { v: 4, en: 'The king of Egypt said to them, “Why do you, Moses and Aaron, take the people from their work? Get back to your burdens!”', pt: 'Respondeu-lhes de novo o rei do Egito: Moisés e Arão, por que fazeis o povo cessar das suas obras? Ide às vossas cargas.' },
      { v: 5, en: 'Pharaoh said, “Behold, the people of the land are now many, and you make them rest from their burdens.”', pt: 'Disse mais Faraó: Eis que o povo da terra já é muito, e vós os fazeis abandonar as suas cargas.' },
      { v: 6, en: 'The same day Pharaoh commanded the taskmasters of the people, and their officers, saying,', pt: 'Naquele mesmo dia Faraó deu ordem aos exatores do povo e aos seus oficiais, dizendo:' },
      { v: 7, en: '“You shall no longer give the people straw to make brick, as before. Let them go and gather straw for themselves.', pt: 'Não tornareis a dar, como dantes, palha ao povo, para fazer tijolos; vão eles mesmos, e colham palha para si.' },
      { v: 8, en: 'The number of the bricks, which they made before, you require from them. You shall not diminish anything of it, for they are idle; therefore they cry, saying, ‘Let us go and sacrifice to our God.’', pt: 'Também lhes imporeis a conta dos tijolos que dantes faziam; nada diminuireis dela; porque eles estão ociosos; por isso clamam, dizendo: Vamos, sacrifiquemos ao nosso Deus.' },
      { v: 9, en: 'Let heavier work be laid on the men, that they may labor in it; and don’t let them pay any attention to lying words.”', pt: 'Agrave-se o serviço sobre esses homens, para que se ocupem nele e não dêem ouvidos a palavras mentirosas.' },
      { v: 10, en: 'The taskmasters of the people went out, and their officers, and they spoke to the people, saying, “This is what Pharaoh says: ‘I will not give you straw.', pt: 'Então saíram os exatores do povo e seus oficiais, e disseram ao povo: Assim diz Faraó: Eu não vos darei palha;' },
      { v: 11, en: 'Go yourselves, get straw where you can find it, for nothing of your work shall be diminished.’”', pt: 'ide vós mesmos, e tomai palha de onde puderdes achá-la; porque nada se diminuirá de vosso serviço.' },
      { v: 12, en: 'So the people were scattered abroad throughout all the land of Egypt to gather stubble for straw.', pt: 'Então o povo se espalhou por toda parte do Egito a colher restolho em lugar de palha.' },
      { v: 13, en: 'The taskmasters were urgent saying, “Fulfill your work quota daily, as when there was straw!”', pt: 'E os exatores os apertavam, dizendo: Acabai a vossa obra, a tarefa do dia no seu dia, como quando havia palha.' },
      { v: 14, en: 'The officers of the children of Israel, whom Pharaoh’s taskmasters had set over them, were beaten, and demanded, “Why haven’t you fulfilled your quota both yesterday and today, in making brick as before?”', pt: 'E foram açoitados os oficiais dos filhos de Israel, postos sobre eles pelos exatores de Faraó, que reclamavam: Por que não acabastes nem ontem nem hoje a vossa tarefa, fazendo tijolos como dantes?' },
      { v: 15, en: 'Then the officers of the children of Israel came and cried to Pharaoh, saying, “Why do you deal this way with your servants?', pt: 'Pelo que os oficiais dos filhos de Israel foram e clamaram a Faraó, dizendo: Porque tratas assim a teus servos?' },
      { v: 16, en: 'No straw is given to your servants, and they tell us, ‘Make brick!’ and behold, your servants are beaten; but the fault is in your own people.”', pt: 'Palha não se dá a teus servos, e nos dizem: Fazei tijolos; e eis que teus servos são açoitados; porém o teu povo é que tem a culpa.' },
      { v: 17, en: 'But he said, “You are idle! You are idle! Therefore you say, ‘Let us go and sacrifice to Yahweh.’', pt: 'Mas ele respondeu: Estais ociosos, estais ociosos; por isso dizeis: vamos, sacrifiquemos ao Senhor.' },
      { v: 18, en: 'Go therefore now, and work, for no straw shall be given to you, yet you shall deliver the same number of bricks!”', pt: 'Portanto, ide, trabalhai; palha, porém, não se vos dará; todavia, dareis a conta dos tijolos.' },
      { v: 19, en: 'The officers of the children of Israel saw that they were in trouble, when it was said, “You shall not diminish anything from your daily quota of bricks!”', pt: 'Então os oficiais dos filhos de Israel viram-se em aperto, porquanto se lhes dizia: Nada diminuireis dos vossos tijolos, da tarefa do dia no seu dia.' },
      { v: 20, en: 'They met Moses and Aaron, who stood in the way, as they came out from Pharaoh:', pt: 'Ao saírem da presença de Faraó depararam com Moisés e Arão que vinham ao encontro deles,' },
      { v: 21, en: 'and they said to them, “May Yahweh look at you, and judge, because you have made us a stench to be abhorred in the eyes of Pharaoh, and in the eyes of his servants, to put a sword in their hand to kill us.”', pt: 'e disseram-lhes: Olhe o Senhor para vós, e julgue isso, porquanto fizestes o nosso caso repelente diante de Faraó e diante de seus servos, metendo-lhes nas mãos uma espada para nos matar.' },
      { v: 22, en: 'Moses returned to Yahweh, and said, “Lord, why have you brought trouble on this people? Why is it that you have sent me?', pt: 'Então, tornando-se Moisés ao Senhor, disse: Senhor! por que trataste mal a este povo? por que me enviaste?' },
      { v: 23, en: 'For since I came to Pharaoh to speak in your name, he has brought trouble on this people; and you have not rescued your people at all.”', pt: 'Pois desde que me apresentei a Faraó para falar em teu nome, ele tem maltratado a este povo; e de nenhum modo tens livrado o teu povo.' },
    ],
    6: [
      { v: 1, en: 'Yahweh said to Moses, “Now you shall see what I will do to Pharaoh, for by a strong hand he shall let them go, and by a strong hand he shall drive them out of his land.”', pt: 'Então disse o Senhor a Moisés: Agora verás o que hei de fazer a Faraó; pois por uma poderosa mão os deixará ir, sim, por uma poderosa mão os lançará de sua terra.' },
      { v: 2, en: 'God spoke to Moses, and said to him, “I am Yahweh;', pt: 'Falou mais Deus a Moisés, e disse-lhe: Eu sou Jeová.' },
      { v: 3, en: 'and I appeared to Abraham, to Isaac, and to Jacob, as God Almighty; but by my name Yahweh I was not known to them.', pt: 'Apareci a Abraão, a Isaque e a Jacó, como o Deus Todo-Poderoso; mas pelo meu nome Jeová, não lhes fui conhecido.' },
      { v: 4, en: 'I have also established my covenant with them, to give them the land of Canaan, the land of their travels, in which they lived as aliens.', pt: 'Estabeleci o meu pacto com eles para lhes dar a terra de Canaã, a terra de suas peregrinações, na qual foram peregrinos.' },
      { v: 5, en: 'Moreover I have heard the groaning of the children of Israel, whom the Egyptians keep in bondage, and I have remembered my covenant.', pt: 'Ademais, tenho ouvido o gemer dos filhos de Israel, aos quais os egípcios vêm escravizando; e lembrei-me do meu pacto.' },
      { v: 6, en: 'Therefore tell the children of Israel, ‘I am Yahweh, and I will bring you out from under the burdens of the Egyptians, and I will rid you out of their bondage, and I will redeem you with an outstretched arm, and with great judgments:', pt: 'Portanto dize aos filhos de Israel: Eu sou Jeová; eu vos tirarei de debaixo das cargas dos egípcios, livrar-vos-ei da sua servidão, e vos resgatarei com braço estendido e com grandes juízos.' },
      { v: 7, en: 'and I will take you to me for a people, and I will be to you a God; and you shall know that I am Yahweh your God, who brings you out from under the burdens of the Egyptians.', pt: 'Eu vos tomarei por meu povo e serei vosso Deus; e vós sabereis que eu sou Jeová vosso Deus, que vos tiro de debaixo das cargas dos egípcios.' },
      { v: 8, en: 'I will bring you into the land which I swore to give to Abraham, to Isaac, and to Jacob; and I will give it to you for a heritage: I am Yahweh.’”', pt: 'Eu vos introduzirei na terra que jurei dar a Abraão, a Isaque e a Jacó; e vo-la darei por herança. Eu sou Jeová.' },
      { v: 9, en: 'Moses spoke so to the children of Israel, but they didn’t listen to Moses for anguish of spirit, and for cruel bondage.', pt: 'Assim falou Moisés aos filhos de Israel, mas eles não lhe deram ouvidos, por causa da angústia de espírito e da dura servidão.' },
      { v: 10, en: 'Yahweh spoke to Moses, saying,', pt: 'Falou mais o Senhor a Moisés, dizendo:' },
      { v: 11, en: '“Go in, speak to Pharaoh king of Egypt, that he let the children of Israel go out of his land.”', pt: 'Vai, fala a Faraó, rei do Egito, que deixe sair os filhos de Israel da sua terra.' },
      { v: 12, en: 'Moses spoke before Yahweh, saying, “Behold, the children of Israel haven’t listened to me. How then shall Pharaoh listen to me, who am of uncircumcised lips?”', pt: 'Moisés, porém, respondeu perante o Senhor, dizendo: Eis que os filhos de Israel não me têm ouvido: como, pois, me ouvirá Faraó a mim, que sou incircunciso de lábios?' },
      { v: 13, en: 'Yahweh spoke to Moses and to Aaron, and gave them a command to the children of Israel, and to Pharaoh king of Egypt, to bring the children of Israel out of the land of Egypt.', pt: 'Todavia o Senhor falou a Moisés e a Arão, e deu-lhes mandamento para os filhos de Israel, e para Faraó, rei do Egito, a fim de tirarem os filhos de Israel da terra do Egito..' },
      { v: 14, en: 'These are the heads of their fathers’ houses. The sons of Reuben the firstborn of Israel: Hanoch, and Pallu, Hezron, and Carmi; these are the families of Reuben.', pt: 'Estes são os cabeças das casas de seus pais: Os filhos de Rúben o primogênito de Israel: Hanoque e Palu, Hezrom e Carmi; estas são as famílias de Rúben.' },
      { v: 15, en: 'The sons of Simeon: Jemuel, and Jamin, and Ohad, and Jachin, and Zohar, and Shaul the son of a Canaanite woman; these are the families of Simeon.', pt: 'E os filhos de Simeão: Jemuel, Jamim, Oade, Jaquim, Zoar e Saul, filho de uma cananéia; estas são as famílias de Simeão.' },
      { v: 16, en: 'These are the names of the sons of Levi according to their generations: Gershon, and Kohath, and Merari; and the years of the life of Levi were one hundred thirty-seven years.', pt: 'E estes são os nomes dos filhos de Levi, segundo as suas gerações: Gérson, Coate e Merári; e os anos da vida de Levi foram cento e trinta e sete anos.' },
      { v: 17, en: 'The sons of Gershon: Libni and Shimei, according to their families.', pt: 'Os filhos de Gérson: Líbni e Simei, segundo as suas famílias.' },
      { v: 18, en: 'The sons of Kohath: Amram, and Izhar, and Hebron, and Uzziel; and the years of the life of Kohath were one hundred thirty-three years.', pt: 'Os filhos de Coate: Anrão, Izar, Hebrom e Uziel; e os anos da vida de Coate foram cento e trinta e três anos.' },
      { v: 19, en: 'The sons of Merari: Mahli and Mushi. These are the families of the Levites according to their generations.', pt: 'Os filhos de Merári: Mali e Musi; estas são as famílias de Levi, segundo as suas gerações.' },
      { v: 20, en: 'Amram took Jochebed his father’s sister to himself as wife; and she bore him Aaron and Moses: and the years of the life of Amram were a hundred and thirty-seven years.', pt: 'Ora, Anrão tomou por mulher a Joquebede, sua tia; e ela lhe deu Arão e Moisés; e os anos da vida de Anrão foram cento e trinta e sete anos.' },
      { v: 21, en: 'The sons of Izhar: Korah, and Nepheg, and Zichri.', pt: 'Os filhos de Izar: Corá, Nofegue e Zicri.' },
      { v: 22, en: 'The sons of Uzziel: Mishael, and Elzaphan, and Sithri.', pt: 'Os filhos de Uziel: Misael, Elzafã e Sitri.' },
      { v: 23, en: 'Aaron took Elisheba, the daughter of Amminadab, the sister of Nahshon, as his wife; and she bore him Nadab and Abihu, Eleazar and Ithamar.', pt: 'Arão tomou por mulher a Eliseba, filha de Aminadabe, irmã de Nasom; e ela lhe deu Nadabe, Abiú, Eleazar e Itamar.' },
      { v: 24, en: 'The sons of Korah: Assir, and Elkanah, and Abiasaph; these are the families of the Korahites.', pt: 'Os filhos de Corá: Assir, Elcana e Abiasafe; estas são as famílias dos coraítas.' },
      { v: 25, en: 'Eleazar Aaron’s son took one of the daughters of Putiel as his wife; and she bore him Phinehas. These are the heads of the fathers’ houses of the Levites according to their families.', pt: 'Eleazar, filho de Arão, tomou por mulher uma das filhas de Putiel; e ela lhe deu Finéias; estes são os chefes das casa, paternas dos levitas, segundo as suas famílias.' },
      { v: 26, en: 'These are that Aaron and Moses, to whom Yahweh said, “Bring out the children of Israel from the land of Egypt according to their armies.”', pt: 'Estes são Arão e Moisés, aos quais o Senhor disse: Tirai os filhos de Israel da terra do Egito, segundo os seus exércitos.' },
      { v: 27, en: 'These are those who spoke to Pharaoh king of Egypt, to bring out the children of Israel from Egypt. These are that Moses and Aaron.', pt: 'Foram eles os que falaram a Faraó, rei do Egito, a fim de tirarem do Egito os filhos de Israel; este Moisés e este Arão.' },
      { v: 28, en: 'On the day when Yahweh spoke to Moses in the land of Egypt,', pt: 'No dia em que o Senhor falou a Moisés na terra do Egito,' },
      { v: 29, en: 'Yahweh spoke to Moses, saying, “I am Yahweh. Speak to Pharaoh king of Egypt all that I speak to you.”', pt: 'disse o Senhor a Moisés: Eu sou Jeová; dize a Faraó, rei do Egito, tudo quanto eu te digo.' },
      { v: 30, en: 'Moses said before Yahweh, “Behold, I am of uncircumcised lips, and how shall Pharaoh listen to me?”', pt: 'Respondeu Moisés perante o Senhor: Eis que eu sou incircunciso de lábios; como, pois, me ouvirá Faraó;' },
    ],
    7: [
      { v: 1, en: 'Yahweh said to Moses, “Behold, I have made you as God to Pharaoh; and Aaron your brother shall be your prophet.', pt: 'Então disse o Senhor a Moisés: Eis que te tenho posto como Deus a Faraó, e Arão, teu irmão, será o teu profeta.' },
      { v: 2, en: 'You shall speak all that I command you; and Aaron your brother shall speak to Pharaoh, that he let the children of Israel go out of his land.', pt: 'Tu falarás tudo o que eu te mandar; e Arão, teu irmão, falará a Faraó, que deixe ir os filhos de Israel da sua terra.' },
      { v: 3, en: 'I will harden Pharaoh’s heart, and multiply my signs and my wonders in the land of Egypt.', pt: 'Eu, porém, endurecerei o coração de Faraó e multiplicarei na terra do Egito os meus sinais e as minhas maravilhas.' },
      { v: 4, en: 'But Pharaoh will not listen to you, and I will lay my hand on Egypt, and bring out my armies, my people the children of Israel, out of the land of Egypt by great judgments.', pt: 'Mas Faraó não vos ouvirá; e eu porei minha mão sobre o Egito, e tirarei os meus exércitos, o meu povo, os filhos de Israel, da terra do Egito, com grandes juízos.' },
      { v: 5, en: 'The Egyptians shall know that I am Yahweh, when I stretch out my hand on Egypt, and bring out the children of Israel from among them.”', pt: 'E os egípcios saberão que eu sou o Senhor, quando estender a minha mão sobre o Egito, e tirar os filhos de Israel do meio deles.' },
      { v: 6, en: 'Moses and Aaron did so. As Yahweh commanded them, so they did.', pt: 'Assim fizeram Moisés e Arão; como o Senhor lhes ordenara, assim fizeram.' },
      { v: 7, en: 'Moses was eighty years old, and Aaron eighty-three years old, when they spoke to Pharaoh.', pt: 'Tinha Moisés oitenta anos, e Arão oitenta e três, quando falaram a Faraó.' },
      { v: 8, en: 'Yahweh spoke to Moses and to Aaron, saying,', pt: 'Falou, pois, o Senhor a Moisés e Arão:' },
      { v: 9, en: '“When Pharaoh speaks to you, saying, ‘Perform a miracle!’ then you shall tell Aaron, ‘Take your rod, and cast it down before Pharaoh, that it become a serpent.’”', pt: 'Quando Faraó vos disser: Apresentai da vossa parte algum milagre; diras a Arão: Toma a tua vara, e lança-a diante de Faraó, para que se torne em serpente.' },
      { v: 10, en: 'Moses and Aaron went in to Pharaoh, and they did so, as Yahweh had commanded: and Aaron cast down his rod before Pharaoh and before his servants, and it became a serpent.', pt: 'Então Moisés e Arão foram ter com Faraó, e fizeram assim como o Senhor ordenara. Arão lançou a sua vara diante de Faraó e diante dos seus servos, e ela se tornou em serpente.' },
      { v: 11, en: 'Then Pharaoh also called for the wise men and the sorcerers. They also, the magicians of Egypt, did the same thing with their enchantments.', pt: 'Faraó também mandou vir os sábios e encantadores; e eles, os magos do Egito, também fizeram o mesmo com os seus encantamentos.' },
      { v: 12, en: 'For they each cast down their rods, and they became serpents: but Aaron’s rod swallowed up their rods.', pt: 'Pois cada um deles lançou a sua vara, e elas se tornaram em serpentes; mas a vara de Arão tragou as varas deles.' },
      { v: 13, en: 'Pharaoh’s heart was hardened, and he didn’t listen to them; as Yahweh had spoken.', pt: 'Endureceu-se, porém, o coração de Faraó, e ele não os ouviu, como o Senhor tinha dito.' },
      { v: 14, en: 'Yahweh said to Moses, “Pharaoh’s heart is stubborn. He refuses to let the people go.', pt: 'Então disse o Senhor a Moisés: Obstinou-se o coração de Faraó; ele recusa deixar ir o povo.' },
      { v: 15, en: 'Go to Pharaoh in the morning. Behold, he goes out to the water; and you shall stand by the river’s bank to meet him; and the rod which was turned to a serpent you shall take in your hand.', pt: 'Vai ter com Faraó pela manhã; eis que ele sairá às águas; pôr-te-ás à beira do rio para o encontrar, e tomarás na mão a vara que se tomou em serpente.' },
      { v: 16, en: 'You shall tell him, ‘Yahweh, the God of the Hebrews, has sent me to you, saying, “Let my people go, that they may serve me in the wilderness:” and behold, until now you haven’t listened.', pt: 'E lhe dirás: O Senhor, o Deus dos hebreus, enviou-me a ti para dizer-te: Deixa ir o meu povo, para que me sirva no deserto; porém eis que até agora não o tens ouvido.' },
      { v: 17, en: 'Yahweh says, “In this you shall know that I am Yahweh. Behold, I will strike with the rod that is in my hand on the waters which are in the river, and they shall be turned to blood.', pt: 'Assim diz o Senhor: Nisto saberás que eu sou o Senhor: Eis que eu, com esta vara que tenho na mão, ferirei as águas que estão no rio, e elas se tornarão em sangue.' },
      { v: 18, en: 'The fish that are in the river shall die, and the river shall become foul; and the Egyptians shall loathe to drink water from the river.”’”', pt: 'E os peixes que estão no rio morrerão, e o rio cheirará mal; e os egípcios terão nojo de beber da água do rio.' },
      { v: 19, en: 'Yahweh said to Moses, “Tell Aaron, ‘Take your rod, and stretch out your hand over the waters of Egypt, over their rivers, over their streams, and over their pools, and over all their ponds of water, that they may become blood; and there shall be blood throughout all the land of Egypt, both in vessels of wood and in vessels of stone.’”', pt: 'Disse mais o Senhor a Moisés: Dize a Arão: Toma a tua vara, e estende a mão sobre as águas do Egito, sobre as suas correntes, sobre os seus rios, e sobre as suas lagoas e sobre todas as suas águas empoçadas, para que se tornem em sangue; e haverá sangue por toda a terra do Egito, assim nos vasos de madeira como nos de pedra.' },
      { v: 20, en: 'Moses and Aaron did so, as Yahweh commanded; and he lifted up the rod, and struck the waters that were in the river, in the sight of Pharaoh, and in the sight of his servants; and all the waters that were in the river were turned to blood.', pt: 'Fizeram Moisés e Arão como lhes ordenara o Senhor; Arão, levantando a vara, feriu as águas que estavam no rio, diante dos olhos de Faraó, e diante dos olhos de seus servos; e todas as águas do rio se tornaram em sangue.' },
      { v: 21, en: 'The fish that were in the river died; and the river became foul, and the Egyptians couldn’t drink water from the river; and the blood was throughout all the land of Egypt.', pt: 'De modo que os peixes que estavam no rio morreram, e o rio cheirou mal, e os egípcios não podiam beber da água do rio; e houve sangue por toda a terra do Egito.' },
      { v: 22, en: 'The magicians of Egypt did the same thing with their enchantments; and Pharaoh’s heart was hardened, and he didn’t listen to them; as Yahweh had spoken.', pt: 'Mas o mesmo fizeram também os magos do Egito com os seus encantamentos; de maneira que o coração de Faraó se endureceu, e não os ouviu, como o Senhor tinha dito.' },
      { v: 23, en: 'Pharaoh turned and went into his house, and he didn’t even take this to heart.', pt: 'Virou-se Faraó e entrou em sua casa, e nem ainda a isto tomou a sério.' },
      { v: 24, en: 'All the Egyptians dug around the river for water to drink; for they couldn’t drink the river water.', pt: 'Todos os egípcios, pois, cavaram junto ao rio, para achar água que beber; porquanto não podiam beber da água do rio.' },
      { v: 25, en: 'Seven days were fulfilled, after Yahweh had struck the river.', pt: 'Assim se passaram sete dias, depois que o Senhor ferira o rio.' },
    ],
    8: [
      { v: 1, en: 'Yahweh spoke to Moses, Go in to Pharaoh, and tell him, “This is what Yahweh says, ‘Let my people go, that they may serve me.', pt: 'Então disse o Senhor a Moisés: Vai a Faraó, e dize-lhe: Assim diz o Senhor: Deixa ir o meu povo, para que me sirva.' },
      { v: 2, en: 'If you refuse to let them go, behold, I will plague all your borders with frogs:', pt: 'Mas se recusares deixá-lo ir, eis que ferirei com rãs todos os teus termos.' },
      { v: 3, en: 'and the river shall swarm with frogs, which shall go up and come into your house, and into your bedroom, and on your bed, and into the house of your servants, and on your people, and into your ovens, and into your kneading troughs:', pt: 'O rio produzirá rãs em abundância, que subirão e virão à tua casa, e ao teu dormitório, e sobre a tua cama, e às casas dos teus servos, e sobre o teu povo, e aos teus fornos, e às tuas amassadeiras.' },
      { v: 4, en: 'and the frogs shall come up both on you, and on your people, and on all your servants.’”', pt: 'Sim, as rãs subirão sobre ti, e sobre o teu povo, e sobre todos os teus servos.' },
      { v: 5, en: 'Yahweh said to Moses, “Tell Aaron, ‘Stretch out your hand with your rod over the rivers, over the streams, and over the pools, and cause frogs to come up on the land of Egypt.’”', pt: 'Disse mais o Senhor a Moisés: Dize a Arão: Estende a tua mão com a vara sobre as correntes, e sobre os rios, e sobre as lagoas, e faze subir rãs sobre a terra do Egito.' },
      { v: 6, en: 'Aaron stretched out his hand over the waters of Egypt; and the frogs came up, and covered the land of Egypt.', pt: 'Arão, pois, estendeu a mão sobre as águas do Egito, e subiram rãs, que cobriram a terra do Egito.' },
      { v: 7, en: 'The magicians did the same thing with their enchantments, and brought up frogs on the land of Egypt.', pt: 'Então os magos fizeram o mesmo com os seus encantamentos, e fizeram subir rãs sobre a terra do Egito.' },
      { v: 8, en: 'Then Pharaoh called for Moses and Aaron, and said, “Entreat Yahweh, that he take away the frogs from me, and from my people; and I will let the people go, that they may sacrifice to Yahweh.”', pt: 'Chamou, pois, Faraó a Moisés e a Arão, e disse: Rogai ao Senhor que tire as rãs de mim e do meu povo; depois deixarei ir o povo, para que ofereça sacrifícios ao Senhor.' },
      { v: 9, en: 'Moses said to Pharaoh, “I give you the honor of setting the time that I should pray for you, and for your servants, and for your people, that the frogs be destroyed from you and your houses, and remain in the river only.”', pt: 'Respondeu Moisés a Faraó: Digna-te dizer-me quando é que hei de rogar por ti, e pelos teus servos, e por teu povo, para tirar as rãs de ti, e das tuas casas, de sorte que fiquem somente no rio?.' },
      { v: 10, en: 'He said, “Tomorrow.” He said, “Be it according to your word, that you may know that there is no one like Yahweh our God.', pt: 'Disse Faraó: Amanhã. E Moisés disse: Seja conforme a tua palavra, para que saibas que ninguém há como o Senhor nosso Deus.' },
      { v: 11, en: 'The frogs shall depart from you, and from your houses, and from your servants, and from your people. They shall remain in the river only.”', pt: 'As rãs, pois, se apartarão de ti, e das tuas casas, e dos teus servos, e do teu povo; ficarão somente no rio.' },
      { v: 12, en: 'Moses and Aaron went out from Pharaoh, and Moses cried to Yahweh concerning the frogs which he had brought on Pharaoh.', pt: 'Então saíram Moisés e Arão da presença de Faraó; e Moisés clamou ao Senhor por causa das rãs que tinha trazido sobre Faraó.' },
      { v: 13, en: 'Yahweh did according to the word of Moses, and the frogs died out of the houses, out of the courts, and out of the fields.', pt: 'O Senhor, pois, fez conforme a palavra de Moisés; e as rãs morreram nas casas, nos pátios, e nos campos.' },
      { v: 14, en: 'They gathered them together in heaps, and the land stank.', pt: 'E ajuntaram-nas em montes, e a terra, cheirou mal.' },
      { v: 15, en: 'But when Pharaoh saw that there was a respite, he hardened his heart, and didn’t listen to them, as Yahweh had spoken.', pt: 'Mas vendo Faraó que havia descanso, endureceu o seu coração, e não os ouviu, como o Senhor tinha dito.' },
      { v: 16, en: 'Yahweh said to Moses, “Tell Aaron, ‘Stretch out your rod, and strike the dust of the earth, that it may become lice throughout all the land of Egypt.’”', pt: 'Disse mais o Senhor a Moisés: Dize a Arão: Estende a tua vara, e fere o pó da terra, para que se torne em piolhos por toda a terra do Egito.' },
      { v: 17, en: 'They did so; and Aaron stretched out his hand with his rod, and struck the dust of the earth, and there were lice on man, and on animal; all the dust of the earth became lice throughout all the land of Egypt.', pt: 'E assim fizeram. Arão estendeu a sua mão com a vara, e feriu o pó da terra, e houve piolhos nos homens e nos animais; todo o pó da terra se tornou em piolhos em toda a terra do Egito.' },
      { v: 18, en: 'The magicians tried with their enchantments to produce lice, but they couldn’t. There were lice on man, and on animal.', pt: 'Também os magos fizeram assim com os seus encantamentos para produzirem piolhos, mas não puderam. E havia piolhos, nos homens e nos animais.' },
      { v: 19, en: 'Then the magicians said to Pharaoh, “This is God’s finger:” and Pharaoh’s heart was hardened, and he didn’t listen to them; as Yahweh had spoken.', pt: 'Então disseram os magos a Faraó: Isto é o dedo de Deus. No entanto o coração de Faraó se endureceu, e não os ouvia, como o Senhor tinha dito:.' },
      { v: 20, en: 'Yahweh said to Moses, “Rise up early in the morning, and stand before Pharaoh; behold, he comes out to the water; and tell him, ‘This is what Yahweh says, “Let my people go, that they may serve me.', pt: 'Disse mais o Senhor a Moisés: levanta-te pela manhã cedo e põe-te diante de Faraó:; eis que ele sairá às águas; e dize-lhe: Assim diz o Senhor: Deixa ir o meu povo, para que me sirva.' },
      { v: 21, en: 'Else, if you will not let my people go, behold, I will send swarms of flies on you, and on your servants, and on your people, and into your houses: and the houses of the Egyptians shall be full of swarms of flies, and also the ground whereon they are.', pt: 'Porque se não deixares ir o meu povo., eis que enviarei enxames de moscas sobre ti, e sobre os teus servos, e sobre o teu povo, e nas tuas casas; e as casas dos egípcios se encherão destes enxames, bem como a terra em que eles estiverem.' },
      { v: 22, en: 'I will set apart in that day the land of Goshen, in which my people dwell, that no swarms of flies shall be there; to the end you may know that I am Yahweh on the earth.', pt: 'Mas naquele dia separarei a terra de Gósem em que o meu povo habita, a fim de que nela não haja enxames de moscas, para que saibas que eu sou o Senhor no meio desta terra.' },
      { v: 23, en: 'I will put a division between my people and your people: by tomorrow shall this sign be.”’”', pt: 'Assim farei distinção entre o meu povo e o teu povo; amanhã se fará este milagre.' },
      { v: 24, en: 'Yahweh did so; and there came grievous swarms of flies into the house of Pharaoh, and into his servants’ houses: and in all the land of Egypt the land was corrupted by reason of the swarms of flies.', pt: 'O Senhor, pois, assim fez. Entraram grandes enxames de moscas na casa de Faraó e nas casas dos seus servos; e em toda parte do Egito a terra foi assolada pelos enxames de moscas.' },
      { v: 25, en: 'Pharaoh called for Moses and for Aaron, and said, “Go, sacrifice to your God in the land!”', pt: 'Então chamou Faraó a Moisés e a Arão, e disse: Ide, e oferecei sacrifícios ao vosso Deus nesta terra.' },
      { v: 26, en: 'Moses said, “It isn’t appropriate to do so; for we shall sacrifice the abomination of the Egyptians to Yahweh our God. Behold, shall we sacrifice the abomination of the Egyptians before their eyes, and won’t they stone us?', pt: 'Respondeu Moisés: Não convém que assim se faça, porque é abominação aos egípcios o que havemos de oferecer ao Senhor nosso Deus. Sacrificando nós a abominação dos egípcios perante os seus olhos, não nos apedrejarão eles?' },
      { v: 27, en: 'We will go three days’ journey into the wilderness, and sacrifice to Yahweh our God, as he shall command us.”', pt: 'Havemos de ir caminho de três dias ao deserto, para que ofereçamos sacrifícios ao Senhor nosso Deus, como ele nos ordenar.' },
      { v: 28, en: 'Pharaoh said, “I will let you go, that you may sacrifice to Yahweh your God in the wilderness, only you shall not go very far away. Pray for me.”', pt: 'Então disse Faraó: Eu vos deixarei ir, para que ofereçais sacrifícios ao Senhor vosso Deus no deserto; somente não ireis muito longe; e orai por mim.' },
      { v: 29, en: 'Moses said, “Behold, I go out from you, and I will pray to Yahweh that the swarms of flies may depart from Pharaoh, from his servants, and from his people, tomorrow; only don’t let Pharaoh deal deceitfully any more in not letting the people go to sacrifice to Yahweh.”', pt: 'Respondeu Moisés: Eis que saio da tua presença e orarei ao Senhor, que estes enxames de moscas se apartem amanhã de Faraó, dos seus servos, e do seu povo; somente não torne mais Faraó a proceder dolosamente, não deixando ir o povo para oferecer sacrifícios ao Senhor.' },
      { v: 30, en: 'Moses went out from Pharaoh, and prayed to Yahweh.', pt: 'Então saiu Moisés da presença de Faraó, e orou ao Senhor.' },
      { v: 31, en: 'Yahweh did according to the word of Moses, and he removed the swarms of flies from Pharaoh, from his servants, and from his people. There remained not one.', pt: 'E fez o Senhor conforme a palavra de Moisés, e apartou os enxames de moscas de Faraó, dos seus servos, e do seu povo; não ficou uma sequer.' },
      { v: 32, en: 'Pharaoh hardened his heart this time also, and he didn’t let the people go.', pt: 'Mas endureceu Faraó ainda esta vez o seu coração, e não deixou ir o povo.' },
    ],
    9: [
      { v: 1, en: 'Then Yahweh said to Moses, “Go in to Pharaoh, and tell him, ‘This is what Yahweh, the God of the Hebrews, says: “Let my people go, that they may serve me.', pt: 'Depois o Senhor disse a Moisés: Vai a Faraó e dize-lhe: Assim diz o Senhor, o Deus dos hebreus: Deixa ir o meu povo, para que me sirva.' },
      { v: 2, en: 'For if you refuse to let them go, and hold them still,', pt: 'Porque, se recusares deixá-los ir, e ainda os retiveres,' },
      { v: 3, en: 'behold, Yahweh’s hand is on your livestock which are in the field, on the horses, on the donkeys, on the camels, on the herds, and on the flocks with a very grievous pestilence.', pt: 'eis que a mão do Senhor será sobre teu gado, que está no campo: sobre os cavalos, sobre os jumentos, sobre os camelos, sobre os bois e sobre as ovelhas; haverá uma pestilência muito grave.' },
      { v: 4, en: 'Yahweh will make a distinction between the livestock of Israel and the livestock of Egypt; and nothing shall die of all that belongs to the children of Israel.”’”', pt: 'Mas o Senhor fará distinção entre o gado de Israel e o gado do Egito; e não morrerá nada de tudo o que pertence aos filhos de Israel.' },
      { v: 5, en: 'Yahweh appointed a set time, saying, “Tomorrow Yahweh shall do this thing in the land.”', pt: 'E o Senhor assinalou certo tempo, dizendo: Amanhã fará o Senhor isto na terra.' },
      { v: 6, en: 'Yahweh did that thing on the next day; and all the livestock of Egypt died, but of the livestock of the children of Israel, not one died.', pt: 'Fez, pois, o Senhor isso no dia seguinte; e todo gado dos egípcios morreu; porém do gado dos filhos de Israel não morreu nenhum.' },
      { v: 7, en: 'Pharaoh sent, and, behold, there was not so much as one of the livestock of the Israelites dead. But the heart of Pharaoh was stubborn, and he didn’t let the people go.', pt: 'E Faraó mandou ver, e eis que do gado dos israelitas não morrera sequer um. Mas o coração de Faraó se obstinou, e não deixou ir o povo.' },
      { v: 8, en: 'Yahweh said to Moses and to Aaron, “Take to you handfuls of ashes of the furnace, and let Moses sprinkle it toward the sky in the sight of Pharaoh.', pt: 'Então disse o Senhor a Moisés e a Arão: Tomai mancheias de cinza do forno, e Moisés a espalhe para o céu diante dos olhos de Faraó;' },
      { v: 9, en: 'It shall become small dust over all the land of Egypt, and shall be a boil breaking out with boils on man and on animal, throughout all the land of Egypt.”', pt: 'e ela se tornará em pó fino sobre toda a terra do Egito, e haverá tumores que arrebentarão em úlceras nos homens e no gado, por toda a terra do Egito.' },
      { v: 10, en: 'They took ashes of the furnace, and stood before Pharaoh; and Moses sprinkled it up toward the sky; and it became a boil breaking out with boils on man and on animal.', pt: 'E eles tomaram cinza do forno, e apresentaram-se diante de Faraó; e Moisés a espalhou para o céu, e ela se tomou em tumores que arrebentavam em úlceras nos homens e no gado.' },
      { v: 11, en: 'The magicians couldn’t stand before Moses because of the boils; for the boils were on the magicians, and on all the Egyptians.', pt: 'Os magos não podiam manter-se diante de Moisés, por causa dos tumores; porque havia tumores nos magos, e em todos os egípcios.' },
      { v: 12, en: 'Yahweh hardened the heart of Pharaoh, and he didn’t listen to them, as Yahweh had spoken to Moses.', pt: 'Mas o Senhor endureceu o coração de Faraó, e este não os ouviu, como o Senhor tinha dito a Moisés.' },
      { v: 13, en: 'Yahweh said to Moses, “Rise up early in the morning, and stand before Pharaoh, and tell him, ‘This is what Yahweh, the God of the Hebrews, says: “Let my people go, that they may serve me.', pt: 'Então disse o Senhor a Moisés: Levanta-te pela manhã cedo, põe-te diante de Faraó, e dize-lhe: Assim diz o Senhor, o Deus dos hebreus: Deixa ir o meu povo, para que me sirva;' },
      { v: 14, en: 'For this time I will send all my plagues against your heart, against your officials, and against your people; that you may know that there is no one like me in all the earth.', pt: 'porque desta vez enviarei todas as a minhas pragas sobre o teu coração, e sobre os teus servos, e sobre o teu povo, para que saibas que não há outro como eu em toda a terra.' },
      { v: 15, en: 'For now I would have stretched out my hand, and struck you and your people with pestilence, and you would have been cut off from the earth;', pt: 'Agora, por pouco, teria eu estendido a mão e ferido a ti e ao teu povo com pestilência, e tu terias sido destruído da terra;' },
      { v: 16, en: 'but indeed for this cause I have made you stand: to show you my power, and that my name may be declared throughout all the earth;', pt: 'mas, na verdade, para isso te hei mantido com vida, para te mostrar o meu poder, e para que o meu nome seja anunciado em toda a terra.' },
      { v: 17, en: 'as you still exalt yourself against my people, that you won’t let them go.', pt: 'Tu ainda te exaltas contra o meu povo, não o deixando ir?' },
      { v: 18, en: 'Behold, tomorrow about this time I will cause it to rain a very grievous hail, such as has not been in Egypt since the day it was founded even until now.', pt: 'Eis que amanhã, por este tempo, s farei chover saraiva tão grave qual nunca houve no Egito, desde o dia em que foi fundado até agora.' },
      { v: 19, en: 'Now therefore command that all of your livestock and all that you have in the field be brought into shelter. Every man and animal that is found in the field, and isn’t brought home, the hail shall come down on them, and they shall die.”’”', pt: 'Agora, pois, manda recolher o teu gado e tudo o que tens no campo; porque sobre todo homem e animal que se acharem no campo, e não se recolherem à casa, cairá a saraiva, e morrerão.' },
      { v: 20, en: 'Those who feared Yahweh’s word among the servants of Pharaoh made their servants and their livestock flee into the houses.', pt: 'Quem dos servos de Faraó temia a o palavra do Senhor, fez Fugir os seus servos e o seu gado para as casas;' },
      { v: 21, en: 'Whoever didn’t respect Yahweh’s word left his servants and his livestock in the field.', pt: 'mas aquele que não se importava com a palavra do Senhor, deixou os seus servos e o seu gado no campo.' },
      { v: 22, en: 'Yahweh said to Moses, “Stretch out your hand toward the sky, that there may be hail in all the land of Egypt, on man, and on animal, and on every herb of the field, throughout the land of Egypt.”', pt: 'Então disse o Senhor a Moisés: Estende a tua mão para o céu, para que caia saraiva em toda a terra do Egito, sobre os homens e sobre os animais, e sobre toda a erva do campo na terra do Egito.' },
      { v: 23, en: 'Moses stretched out his rod toward the heavens, and Yahweh sent thunder, hail, and lightning flashed down to the earth. Yahweh rained hail on the land of Egypt.', pt: 'E Moisés estendeu a sua vara para o céu, e o Senhor enviou trovões e saraiva, e fogo desceu à terra; e o Senhor fez chover saraiva sobre a terra do Egito.' },
      { v: 24, en: 'So there was very severe hail, and lightning mixed with the hail, such as had not been in all the land of Egypt since it became a nation.', pt: 'Havia, pois, saraiva misturada com fogo, saraiva tão grave qual nunca houvera em toda a terra do Egito, desde que veio a ser uma nação.' },
      { v: 25, en: 'The hail struck throughout all the land of Egypt all that was in the field, both man and animal; and the hail struck every herb of the field, and broke every tree of the field.', pt: 'E a saraiva feriu, em toda a terra do Egito, tudo quanto havia no campo, tanto homens como animais; feriu também toda erva do campo, e quebrou todas as árvores do campo.' },
      { v: 26, en: 'Only in the land of Goshen, where the children of Israel were, there was no hail.', pt: 'Somente na terra de Gósem onde se achavam os filhos de Israel, não houve saraiva.' },
      { v: 27, en: 'Pharaoh sent, and called for Moses and Aaron, and said to them, “I have sinned this time. Yahweh is righteous, and I and my people are wicked.', pt: 'Então Faraó mandou chamar Moisés e e Arão, e disse-lhes: Esta vez pequei; o Senhor é justo, mas eu e o meu povo somos a ímpios.' },
      { v: 28, en: 'Pray to Yahweh; for there has been enough of mighty thunderings and hail. I will let you go, and you shall stay no longer.”', pt: 'Orai ao Senhor; pois já bastam estes trovões da parte de Deus e esta saraiva; eu vos deixarei ir, e não permanecereis mais, aqui.' },
      { v: 29, en: 'Moses said to him, “As soon as I have gone out of the city, I will spread abroad my hands to Yahweh. The thunders shall cease, and there will not be any more hail; that you may know that the earth is Yahweh’s.', pt: 'Respondeu-lhe Moisés: Logo que eu tiver saído da cidade estenderei minhas mãos ao Senhor; os trovões cessarão, e não haverá, mais saraiva, para que saibas que a terra é do Senhor.' },
      { v: 30, en: 'But as for you and your servants, I know that you don’t yet fear Yahweh God.”', pt: 'Todavia, quanto a ti e aos teus servos, eu sei que ainda não temereis diante do Senhor Deus.' },
      { v: 31, en: 'The flax and the barley were struck, for the barley was in the ear, and the flax was in bloom.', pt: 'Ora, o linho e a cevada foram danificados, porque a cevada já estava na espiga, e o linho em flor;' },
      { v: 32, en: 'But the wheat and the spelt were not struck, for they had not grown up.', pt: 'mas não foram danificados o trigo e a espelta, porque não estavam crescidos.' },
      { v: 33, en: 'Moses went out of the city from Pharaoh, and spread abroad his hands to Yahweh; and the thunders and hail ceased, and the rain was not poured on the earth.', pt: 'Saiu, pois, Moisés da cidade, da presença de Faraó, e estendeu as mãos ao Senhor; e cessaram os trovões e a saraiva, e a chuva não caiu mais sobre a terra.' },
      { v: 34, en: 'When Pharaoh saw that the rain and the hail and the thunders had ceased, he sinned yet more, and hardened his heart, he and his servants.', pt: 'Vendo Faraó que a chuva, a saraiva e os trovões tinham cessado, continuou a pecar, e endureceu o seu coração, ele e os seus servos.' },
      { v: 35, en: 'The heart of Pharaoh was hardened, and he didn’t let the children of Israel go, just as Yahweh had spoken through Moses.', pt: 'Assim, o coração de Faraó se endureceu, e não deixou ir os filhos de Israel, como o Senhor tinha dito por Moisés.' },
    ],
    10: [
      { v: 1, en: 'Yahweh said to Moses, “Go in to Pharaoh, for I have hardened his heart, and the heart of his servants, that I may show these my signs among them,', pt: 'Depois disse o Senhor a Moisés: vai a Faraó; porque tenho endurecido o seu coração, e o coração de seus servos, para manifestar estes meus sinais no meio deles,' },
      { v: 2, en: 'and that you may tell in the hearing of your son, and of your son’s son, what things I have done to Egypt, and my signs which I have done among them; that you may know that I am Yahweh.”', pt: 'e para que contes aos teus filhos, e aos filhos de teus filhos, as coisas que fiz no Egito, e os meus sinais que operei entre eles; para que vós saibais que eu sou o Senhor.' },
      { v: 3, en: 'Moses and Aaron went in to Pharaoh, and said to him, “This is what Yahweh, the God of the Hebrews, says: ‘How long will you refuse to humble yourself before me? Let my people go, that they may serve me.', pt: 'Foram, pois, Moisés e Arão a Faraó, e disseram-lhe: Assim diz o Senhor, o Deus dos hebreus: Até quando recusarás humilhar-te diante de mim? Deixa ir o meu povo, para que me sirva;' },
      { v: 4, en: 'Or else, if you refuse to let my people go, behold, tomorrow I will bring locusts into your country,', pt: 'mas se tu recusares deixar ir o meu povo, eis que amanhã trarei gafanhotos aos teus termos;' },
      { v: 5, en: 'and they shall cover the surface of the earth, so that one won’t be able to see the earth. They shall eat the residue of that which has escaped, which remains to you from the hail, and shall eat every tree which grows for you out of the field.', pt: 'e eles cobrirão a face da terra, de sorte que não se poderá ver a terra e comerão o resto do que escapou, o que vos ficou da saraiva; também comerão toda árvore que vos cresce no campo;' },
      { v: 6, en: 'Your houses shall be filled, and the houses of all your servants, and the houses of all the Egyptians; as neither your fathers nor your fathers’ fathers have seen, since the day that they were on the earth to this day.’” He turned, and went out from Pharaoh.', pt: 'e encherão as tuas casas, as casas de todos os teus servos e as casas de todos os egípcios, como nunca viram teus pais nem os pais de teus pais, desde o dia em que apareceram na terra até o dia de hoje. E virou-se, e saiu da presença de Faraó.' },
      { v: 7, en: 'Pharaoh’s servants said to him, “How long will this man be a snare to us? Let the men go, that they may serve Yahweh, their God. Don’t you yet know that Egypt is destroyed?”', pt: 'Então os servos de Faraó lhe disseram: Até quando este homem nos há de ser por laço? deixa ir os homens, para que sirvam ao Senhor seu Deus; porventura não sabes ainda que o Egito está destruído?' },
      { v: 8, en: 'Moses and Aaron were brought again to Pharaoh, and he said to them, “Go, serve Yahweh your God; but who are those who will go?”', pt: 'Pelo que Moisés e Arão foram levados outra vez a Faraó, e ele lhes disse: Ide, servi ao Senhor vosso Deus. Mas quais são os que hão de ir?' },
      { v: 9, en: 'Moses said, “We will go with our young and with our old; with our sons and with our daughters, with our flocks and with our herds will we go; for we must hold a feast to Yahweh.”', pt: 'Respondeu-lhe Moisés: Havemos de ir com os nossos jovens e com os nossos velhos; com os nossos filhos e com as nossas filhas, com os nossos rebanhos e com o nosso gado havemos de ir; porque temos de celebrar uma festa ao Senhor.' },
      { v: 10, en: 'He said to them, “Yahweh be with you if I will let you go with your little ones! See, evil is clearly before your faces.', pt: 'Replicou-lhes Faraó: Seja o Senhor convosco, se eu vos deixar ir a vós e a vossos pequeninos! Olhai, porque há mal diante de vós.' },
      { v: 11, en: 'Not so! Go now you who are men, and serve Yahweh; for that is what you desire!” They were driven out from Pharaoh’s presence.', pt: 'Não será assim; agora, ide vós, os homens, e servi ao Senhor, pois isso é o que pedistes: E foram expulsos da presença de Faraó.' },
      { v: 12, en: 'Yahweh said to Moses, “Stretch out your hand over the land of Egypt for the locusts, that they may come up on the land of Egypt, and eat every herb of the land, even all that the hail has left.”', pt: 'Então disse o Senhor a Moisés: Quanto aos gafanhotos, estende a tua mão sobre a terra do Egito, para que venham eles sobre a terra do Egito e comam toda erva da terra, tudo o que deixou a saraiva.' },
      { v: 13, en: 'Moses stretched out his rod over the land of Egypt, and Yahweh brought an east wind on the land all that day, and all night; and when it was morning, the east wind brought the locusts.', pt: 'Então estendeu Moisés sua vara sobre a terra do Egito, e o Senhor trouxe sobre a terra um vento oriental todo aquele dia e toda aquela noite; e, quando amanheceu, o vento oriental trouxe os gafanhotos.' },
      { v: 14, en: 'The locusts went up over all the land of Egypt, and rested in all the borders of Egypt. They were very grievous. Before them there were no such locusts as they, nor will there ever be again.', pt: 'Subiram, pois, os gafanhotos sobre toda a terra do Egito e pousaram sobre todos os seus termos; tão numerosos foram, que antes destes nunca houve tantos, nem depois deles haverá.' },
      { v: 15, en: 'For they covered the surface of the whole earth, so that the land was darkened, and they ate every herb of the land, and all the fruit of the trees which the hail had left. There remained nothing green, either tree or herb of the field, through all the land of Egypt.', pt: 'Pois cobriram a face de toda a terra, de modo que a terra se escureceu; e comeram toda a erva da terra e todo o fruto das árvores, que deixara a saraiva; nada verde ficou, nem de árvore nem de erva do campo, por toda a terra do Egito.' },
      { v: 16, en: 'Then Pharaoh called for Moses and Aaron in haste, and he said, “I have sinned against Yahweh your God, and against you.', pt: 'Então Faraó mandou apressadamente chamar Moisés e Arão, e lhes disse: Pequei contra o Senhor vosso Deus, e contra vós.' },
      { v: 17, en: 'Now therefore please forgive my sin again, and pray to Yahweh your God, that he may also take away from me this death.”', pt: 'Agora: pois, perdoai-me peço-vos somente esta vez o meu pecado, e orai ao Senhor vosso Deus que tire de mim mais esta morte.' },
      { v: 18, en: 'He went out from Pharaoh, and prayed to Yahweh.', pt: 'Saiu, pois, Moisés da presença de Faraó, e orou ao Senhor.' },
      { v: 19, en: 'Yahweh turned an exceeding strong west wind, which took up the locusts, and drove them into the Red Sea. There remained not one locust in all the borders of Egypt.', pt: 'Então o Senhor trouxe um vento ocidental fortíssimo, o qual levantou os gafanhotos e os lançou no Mar Vermelho; não ficou um só gafanhoto em todos os termos do Egito.' },
      { v: 20, en: 'But Yahweh hardened Pharaoh’s heart, and he didn’t let the children of Israel go.', pt: 'O Senhor, porém, endureceu o coração de Faraó, e este não deixou ir os filhos de Israel.' },
      { v: 21, en: 'Yahweh said to Moses, “Stretch out your hand toward the sky, that there may be darkness over the land of Egypt, even darkness which may be felt.”', pt: 'Então disse o Senhor a Moisés: Estende a mão para o céu, para que haja trevas sobre a terra do Egito, trevas que se possam apalpar.' },
      { v: 22, en: 'Moses stretched out his hand toward the sky, and there was a thick darkness in all the land of Egypt for three days.', pt: 'Estendeu, pois, Moisés a mão para o céu, e houve trevas espessas em toda a terra do Egito por três dias.' },
      { v: 23, en: 'They didn’t see one another, and nobody rose from his place for three days; but all the children of Israel had light in their dwellings.', pt: 'Não se viram uns aos outros, e ninguém se levantou do seu lugar por três dias; mas para todos os filhos de Israel havia luz nas suas habitações.' },
      { v: 24, en: 'Pharaoh called to Moses, and said, “Go, serve Yahweh. Only let your flocks and your herds stay behind. Let your little ones also go with you.”', pt: 'Então mandou Faraó chamar Moisés, e disse: Ide, servi ao Senhor; somente fiquem os vossos rebanhos e o vosso gado; mas vão juntamente convosco os vossos pequeninos.' },
      { v: 25, en: 'Moses said, “You must also give into our hand sacrifices and burnt offerings, that we may sacrifice to Yahweh our God.', pt: 'Moisés, porém, disse: Tu também nos tens de dar nas mãos sacrifícios e holocaustos, para que possamos oferecer sacrifícios ao Senhor nosso Deus.' },
      { v: 26, en: 'Our livestock also shall go with us. Not a hoof shall be left behind, for of it we must take to serve Yahweh our God; and we don’t know with what we must serve Yahweh, until we come there.”', pt: 'E também o nosso gado há de ir conosco; nem uma unha ficará; porque dele havemos de tomar para servir ao Senhor nosso Deus; porque não sabemos com que havemos de servir ao Senhor, até que cheguemos lá.' },
      { v: 27, en: 'But Yahweh hardened Pharaoh’s heart, and he wouldn’t let them go.', pt: 'O Senhor, porém, endureceu o coração de Faraó, e este não os quis deixar ir:' },
      { v: 28, en: 'Pharaoh said to him, “Get away from me! Be careful to see my face no more; for in the day you see my face you shall die!”', pt: 'Disse, pois, Faraó a Moisés: Retira-te de mim, guarda-te que não mais vejas o meu rosto; porque no dia em que me vires o rosto morrerás.' },
      { v: 29, en: 'Moses said, “You have spoken well. I will see your face again no more.”', pt: 'Respondeu Moisés: Disseste bem; eu nunca mais verei o teu rosto.' },
    ],
    11: [
      { v: 1, en: 'Yahweh said to Moses, “Yet one plague more will I bring on Pharaoh, and on Egypt; afterwards he will let you go. When he lets you go, he will surely thrust you out altogether.', pt: 'Disse o Senhor a Moisés: Ainda mais uma praga trarei sobre Faraó, e sobre o Egito; depois ele vos deixará ir daqui; e, deixando vos ir a todos, com efeito vos expulsará daqui.' },
      { v: 2, en: 'Speak now in the ears of the people, and let every man ask of his neighbor, and every woman of her neighbor, jewels of silver, and jewels of gold.”', pt: 'Fala agora aos ouvidos do povo, que cada homem peça ao seu vizinho, e cada mulher à sua vizinha, jóias de prata e jóias de ouro.' },
      { v: 3, en: 'Yahweh gave the people favor in the sight of the Egyptians. Moreover the man Moses was very great in the land of Egypt, in the sight of Pharaoh’s servants, and in the sight of the people.', pt: 'E o Senhor deu ao povo graça aos olhos dos egípcios. Além disso o varão Moisés era mui grande na terra do Egito, aos olhos dos servos de Faraó e aos olhos do povo.' },
      { v: 4, en: 'Moses said, “This is what Yahweh says: ‘About midnight I will go out into the middle of Egypt,', pt: 'Depois disse Moisés a Faraó: Assim diz o Senhor: ë meia-noite eu sairei pelo meio do Egito;' },
      { v: 5, en: 'and all the firstborn in the land of Egypt shall die, from the firstborn of Pharaoh who sits on his throne, even to the firstborn of the female servant who is behind the mill; and all the firstborn of livestock.', pt: 'e todos os primogênitos na terra do Egito morrerão, desde o primogênito de Faraó, que se assenta sobre o seu trono, até o primogênito da serva que está detrás da mó, e todos os primogênitos dos animais.' },
      { v: 6, en: 'There shall be a great cry throughout all the land of Egypt, such as there has not been, nor shall be any more.', pt: 'Pelo que haverá grande clamor em toda a terra do Egito, como nunca houve nem haverá jamais.' },
      { v: 7, en: 'But against any of the children of Israel a dog won’t even bark or move its tongue, against man or animal; that you may know that Yahweh makes a distinction between the Egyptians and Israel.', pt: 'Mas contra os filhos de Israel nem mesmo um cão moverá a sua língua, nem contra homem nem contra animal; para que saibais que o Senhor faz distinção entre os egípcios e os filhos de Israel.' },
      { v: 8, en: 'All these servants of yours will come down to me, and bow down themselves to me, saying, “Get out, with all the people who follow you”; and after that I will go out.’” He went out from Pharaoh in hot anger.', pt: 'Então todos estes teus servos descerão a mim, e se inclinarão diante de mim, dizendo: Sai tu, e todo o povo que te segue as pisadas. Depois disso eu sairei. E Moisés saiu da presença de Faraó ardendo em ira.' },
      { v: 9, en: 'Yahweh said to Moses, “Pharaoh won’t listen to you, that my wonders may be multiplied in the land of Egypt.”', pt: 'Pois o Senhor dissera a Moisés: Faraó não vos ouvirá, para que as minhas maravilhas se multipliquem na terra do Egito.' },
      { v: 10, en: 'Moses and Aaron did all these wonders before Pharaoh, and Yahweh hardened Pharaoh’s heart, and he didn’t let the children of Israel go out of his land.', pt: 'E Moisés e Arão fizeram todas estas maravilhas diante de Faraó; mas o Senhor endureceu o coração de Faraó, que não deixou ir da sua terra os filhos de Israel.' },
    ],
    12: [
      { v: 1, en: 'Yahweh spoke to Moses and Aaron in the land of Egypt, saying,', pt: 'Ora, o Senhor falou a Moisés e a Arão na terra do Egito, dizendo:' },
      { v: 2, en: '“This month shall be to you the beginning of months. It shall be the first month of the year to you.', pt: 'Este mês será para vós o princípio dos meses; este vos será o primeiro dos meses do ano.' },
      { v: 3, en: 'Speak to all the congregation of Israel, saying, ‘On the tenth day of this month, they shall take to them every man a lamb, according to their fathers’ houses, a lamb for a household;', pt: 'Falai a toda a congregação de Israel, dizendo: Ao décimo dia deste mês tomará cada um para si um cordeiro, segundo as casas dos pais, um cordeiro para cada família.' },
      { v: 4, en: 'and if the household is too little for a lamb, then he and his neighbor next to his house shall take one according to the number of the souls; according to what everyone can eat you shall make your count for the lamb.', pt: 'Mas se a família for pequena demais para um cordeiro, tomá-lo-á juntamente com o vizinho mais próximo de sua casa, conforme o número de almas; conforme ao comer de cada um, fareis a conta para o cordeiro.' },
      { v: 5, en: 'Your lamb shall be without defect, a male a year old. You shall take it from the sheep, or from the goats:', pt: 'O cordeiro, ou cabrito, será sem defeito, macho de um ano, o qual tomareis das ovelhas ou das cabras,' },
      { v: 6, en: 'and you shall keep it until the fourteenth day of the same month; and the whole assembly of the congregation of Israel shall kill it at evening.', pt: 'e o guardareis até o décimo quarto dia deste mês; e toda a assembléia da congregação de Israel o matará à tardinha:' },
      { v: 7, en: 'They shall take some of the blood, and put it on the two door posts and on the lintel, on the houses in which they shall eat it.', pt: 'Tomarão do sangue, e pô-lo-ão em ambos os umbrais e na verga da porta, nas casas em que o comerem.' },
      { v: 8, en: 'They shall eat the meat in that night, roasted with fire, and unleavened bread. They shall eat it with bitter herbs.', pt: 'E naquela noite comerão a carne assada ao fogo, com pães ázimos; com ervas amargosas a comerao.' },
      { v: 9, en: 'Don’t eat it raw, nor boiled at all with water, but roasted with fire; with its head, its legs and its inner parts.', pt: 'Não comereis dele cru, nem cozido em água, mas sim assado ao fogo; a sua cabeça com as suas pernas e com a sua fressura.' },
      { v: 10, en: 'You shall let nothing of it remain until the morning; but that which remains of it until the morning you shall burn with fire.', pt: 'Nada dele deixareis até pela manhã; mas o que dele ficar até pela manhã, queimá-lo-eis no fogo.' },
      { v: 11, en: 'This is how you shall eat it: with your belt on your waist, your shoes on your feet, and your staff in your hand; and you shall eat it in haste: it is Yahweh’s Passover.', pt: 'Assim pois o comereis: Os vossos lombos cingidos, os vossos sapatos nos pés, e o vosso cajado na mão; e o comereis apressadamente; esta é a páscoa do Senhor.' },
      { v: 12, en: 'For I will go through the land of Egypt in that night, and will strike all the firstborn in the land of Egypt, both man and animal. Against all the gods of Egypt I will execute judgments: I am Yahweh.', pt: 'Porque naquela noite passarei pela terra do Egito, e ferirei todos os primogênitos na terra do Egito, tanto dos homens como dos animais; e sobre todos os deuses do Egito executarei juízos; eu sou o Senhor.' },
      { v: 13, en: 'The blood shall be to you for a token on the houses where you are: and when I see the blood, I will pass over you, and there shall no plague be on you to destroy you, when I strike the land of Egypt.', pt: 'Mas o sangue vos será por sinal nas casas em que estiverdes; vendo eu o sangue, passarei por cima de vós, e não haverá entre vós praga para vos destruir, quando eu ferir a terra do Egito. :' },
      { v: 14, en: 'This day shall be to you for a memorial, and you shall keep it a feast to Yahweh: throughout your generations you shall keep it a feast by an ordinance forever.', pt: 'E este dia vos será por memorial, e celebrá-lo-eis por festa ao Senhor; através das vossas gerações o celebrareis por estatuto perpétuo.' },
      { v: 15, en: '“‘Seven days you shall eat unleavened bread; even the first day you shall put away yeast out of your houses, for whoever eats leavened bread from the first day until the seventh day, that soul shall be cut off from Israel.', pt: 'Por sete dias comereis pães ázimos; logo ao primeiro dia tirareis o fermento das vossas casas, porque qualquer que comer pão levedado, entre o primeiro e o sétimo dia, esse será cortado de Israel.' },
      { v: 16, en: 'In the first day there shall be to you a holy convocation, and in the seventh day a holy convocation; no kind of work shall be done in them, except that which every man must eat, that only may be done by you.', pt: 'E ao primeiro dia haverá uma santa convocação; também ao sétimo dia tereis uma santa convocação; neles não se fará trabalho algum, senão o que diz respeito ao que cada um houver de comer; somente isso poderá ser feito por vós.' },
      { v: 17, en: 'You shall observe the feast of unleavened bread; for in this same day I have brought your armies out of the land of Egypt: therefore you shall observe this day throughout your generations by an ordinance forever.', pt: 'Guardareis, pois, a festa dos pães ázimos, porque nesse mesmo dia tirei vossos exércitos da terra do Egito; pelo que guardareis este dia através das vossas gerações por estatuto perpétuo.' },
      { v: 18, en: 'In the first month, on the fourteenth day of the month at evening, you shall eat unleavened bread, until the twenty first day of the month at evening.', pt: 'No primeiro mês, aos catorze dias do mês, à tarde, comereis pães ázimos até vinte e um do mês à tarde.' },
      { v: 19, en: 'There shall be no yeast found in your houses for seven days, for whoever eats that which is leavened, that soul shall be cut off from the congregation of Israel, whether he is a foreigner, or one who is born in the land.', pt: 'Por sete dias não se ache fermento algum nas vossas casas; porque qualquer que comer pão levedado, esse será cortado da congregação de Israel, tanto o peregrino como o natural da terra.' },
      { v: 20, en: 'You shall eat nothing leavened. In all your habitations you shall eat unleavened bread.’”', pt: 'Nenhuma coisa levedada comereis; em todas as vossas habitações comereis pães ázimos.' },
      { v: 21, en: 'Then Moses called for all the elders of Israel, and said to them, “Draw out, and take lambs according to your families, and kill the Passover.', pt: 'Chamou, pois, Moisés todos os anciãos de Israel, e disse-lhes: Ide e tomai-vos cordeiros segundo as vossas famílias, e imolai a páscoa.' },
      { v: 22, en: 'You shall take a bunch of hyssop, and dip it in the blood that is in the basin, and strike the lintel and the two door posts with the blood that is in the basin; and none of you shall go out of the door of his house until the morning.', pt: 'Então tomareis um molho de hissopo, embebê-lo-eis no sangue que estiver na bacia e marcareis com ele a verga da porta e os dois umbrais; mas nenhum de vós sairá da porta da sua casa até pela manhã.' },
      { v: 23, en: 'For Yahweh will pass through to strike the Egyptians; and when he sees the blood on the lintel, and on the two door posts, Yahweh will pass over the door, and will not allow the destroyer to come in to your houses to strike you.', pt: 'Porque o Senhor passará para ferir aos egípcios; e, ao ver o sangue na verga da porta e em ambos os umbrais, o Senhor passará aquela porta, e não deixará o destruidor entrar em vossas casas para vos ferir.' },
      { v: 24, en: 'You shall observe this thing for an ordinance to you and to your sons forever.', pt: 'Portanto guardareis isto por estatuto para vós e para vossos filhos, para sempre.' },
      { v: 25, en: 'It shall happen when you have come to the land which Yahweh will give you, according as he has promised, that you shall keep this service.', pt: 'Quando, pois, tiverdes entrado na terra que o Senhor vos dará, como tem prometido, guardareis este culto.' },
      { v: 26, en: 'It will happen, when your children ask you, ‘What do you mean by this service?’', pt: 'E quando vossos filhos vos perguntarem: Que quereis dizer com este culto?' },
      { v: 27, en: 'that you shall say, ‘It is the sacrifice of Yahweh’s Passover, who passed over the houses of the children of Israel in Egypt, when he struck the Egyptians, and spared our houses.’” The people bowed their heads and worshiped.', pt: 'Respondereis: Este é o sacrifício da páscoa do Senhor, que passou as casas dos filhos de Israel no Egito, quando feriu os egípcios, e livrou as nossas casas. Então o povo inclinou-se e adorou.' },
      { v: 28, en: 'The children of Israel went and did so; as Yahweh had commanded Moses and Aaron, so they did.', pt: 'E foram os filhos de Israel, e fizeram isso; como o Senhor ordenara a Moisés e a Arão, assim fizeram.' },
      { v: 29, en: 'At midnight, Yahweh struck all the firstborn in the land of Egypt, from the firstborn of Pharaoh who sat on his throne to the firstborn of the captive who was in the dungeon; and all the firstborn of livestock.', pt: 'E aconteceu que à meia-noite o Senhor feriu todos os primogênitos na terra do Egito, desde o primogênito de Faraó, que se assentava em seu trono, até o primogênito do cativo que estava no cárcere, e todos os primogênitos dos animais.' },
      { v: 30, en: 'Pharaoh rose up in the night, he, and all his servants, and all the Egyptians; and there was a great cry in Egypt, for there was not a house where there was not one dead.', pt: 'E Faraó levantou-se de noite, ele e todos os seus servos, e todos os egípcios; e fez-se grande clamor no Egito, porque não havia casa em que não houvesse um morto.' },
      { v: 31, en: 'He called for Moses and Aaron by night, and said, “Rise up, get out from among my people, both you and the children of Israel; and go, serve Yahweh, as you have said!', pt: 'Então Faraó chamou Moisés e Arão de noite, e disse: Levantai-vos, saí do meio do meu povo, tanto vós como os filhos de Israel; e ide servir ao Senhor, como tendes dito.' },
      { v: 32, en: 'Take both your flocks and your herds, as you have said, and be gone; and bless me also!”', pt: 'Levai também convosco os vossos rebanhos e o vosso gado, como tendes dito; e ide, e abençoai-me também a mim.' },
      { v: 33, en: 'The Egyptians were urgent with the people, to send them out of the land in haste, for they said, “We are all dead men.”', pt: 'E os egípcios apertavam ao povo, e apressando-se por lançá-los da terra; porque diziam: Estamos todos mortos.' },
      { v: 34, en: 'The people took their dough before it was leavened, their kneading troughs being bound up in their clothes on their shoulders.', pt: 'Ao que o povo tomou a massa, antes que ela levedasse, e as amassadeiras atadas e em seus vestidos, sobre os ombros.' },
      { v: 35, en: 'The children of Israel did according to the word of Moses; and they asked of the Egyptians jewels of silver, and jewels of gold, and clothing.', pt: 'Fizeram, pois, os filhos de Israel conforme a palavra de Moisés, e pediram aos egípcios jóias de prata, e jóias de ouro, e vestidos.' },
      { v: 36, en: 'Yahweh gave the people favor in the sight of the Egyptians, so that they let them have what they asked. They plundered the Egyptians.', pt: 'E o Senhor deu ao povo graça aos olhos dos egípcios, de modo que estes lhe davam o que pedia; e despojaram aos egipcios.' },
      { v: 37, en: 'The children of Israel traveled from Rameses to Succoth, about six hundred thousand on foot who were men, besides children.', pt: 'Assim viajaram os filhos de Israel de a Ramessés a Sucote, cerca de seiscentos mil homens de pé, sem contar as crianças.' },
      { v: 38, en: 'A mixed multitude went up also with them, with flocks, herds, and even very much livestock.', pt: 'Também subiu com eles uma grande mistura de gente; e, em rebanhos e manadas, uma grande quantidade de gado.' },
      { v: 39, en: 'They baked unleavened cakes of the dough which they brought out of Egypt; for it wasn’t leavened, because they were thrust out of Egypt, and couldn’t wait, and they had not prepared any food for themselves.', pt: 'E cozeram bolos ázimos da massa que levaram do Egito, porque ela não se tinha levedado, porquanto foram lançados do Egito; e não puderam deter-se, nem haviam preparado comida.' },
      { v: 40, en: 'Now the time that the children of Israel lived in Egypt was four hundred thirty years.', pt: 'Ora, o tempo que os filhos de Israel moraram no Egito foi de quatrocentos e trinta anos.' },
      { v: 41, en: 'At the end of four hundred thirty years, to the day, all of Yahweh’s armies went out from the land of Egypt.', pt: 'E aconteceu que, ao fim de quatrocentos e trinta anos, naquele mesmo dia, todos os exércitos do Senhor saíram da terra do Egito.' },
      { v: 42, en: 'It is a night to be much observed to Yahweh for bringing them out from the land of Egypt. This is that night of Yahweh, to be much observed of all the children of Israel throughout their generations.', pt: 'Esta é uma noite que se deve guardar ao Senhor, porque os tirou da terra do Egito; esta é a noite do Senhor, que deve ser guardada por todos os filhos de Israel através das suas gerações.' },
      { v: 43, en: 'Yahweh said to Moses and Aaron, “This is the ordinance of the Passover. No foreigner shall eat of it,', pt: 'Disse mais o Senhor a Moisés e a Arão: Esta é a ordenança da páscoa; nenhum, estrangeiro comerá dela;' },
      { v: 44, en: 'but every man’s servant who is bought for money, when you have circumcised him, then shall he eat of it.', pt: 'mas todo escravo comprado por dinheiro, depois que o houveres circuncidado, comerá dela.' },
      { v: 45, en: 'A foreigner and a hired servant shall not eat of it.', pt: 'O forasteiro e o assalariado não comerão dela.' },
      { v: 46, en: 'It must be eaten in one house. You shall not carry any of the meat outside of the house. Do not break any of its bones.', pt: 'Numa só casa se comerá o cordeiro; não levareis daquela carne fora da casa nem lhe quebrareis osso algum.' },
      { v: 47, en: 'All the congregation of Israel shall keep it.', pt: 'Toda a congregação de Israel a observará.' },
      { v: 48, en: 'When a stranger shall live as a foreigner with you, and will keep the Passover to Yahweh, let all his males be circumcised, and then let him come near and keep it; and he shall be as one who is born in the land: but no uncircumcised person shall eat of it.', pt: 'Quando, porém, algum estrangeiro peregrinar entre vós e quiser celebrar a páscoa ao Senhor, circuncidem-se todos os seus varões; então se chegará e a celebrará, e será como o natural da terra; mas nenhum incircunciso comerá dela.' },
      { v: 49, en: 'One law shall be to him who is born at home, and to the stranger who lives as a foreigner among you.”', pt: 'Haverá uma mesma lei para o natural e para o estrangeiro que peregrinar entre vós.' },
      { v: 50, en: 'All the children of Israel did so. As Yahweh commanded Moses and Aaron, so they did.', pt: 'Assim, pois, fizeram todos os filhos de Israel; como o Senhor ordenara a Moisés e a Arão, assim fizeram.' },
      { v: 51, en: 'That same day, Yahweh brought the children of Israel out of the land of Egypt by their armies.', pt: 'E naquele mesmo dia o Senhor tirou os filhos de Israel da terra do Egito, segundo os seus exércitos.' },
    ],
    13: [
      { v: 1, en: 'Yahweh spoke to Moses, saying,', pt: 'Então falou o Senhor a Moisés, dizendo:' },
      { v: 2, en: '“Sanctify to me all the firstborn, whatever opens the womb among the children of Israel, both of man and of animal. It is mine.”', pt: 'Santifica-me todo primogênito, todo o que abrir a madre de sua mãe entre os filhos de Israel, assim de homens como de animais; porque meu é.' },
      { v: 3, en: 'Moses said to the people, “Remember this day, in which you came out of Egypt, out of the house of bondage; for by strength of hand Yahweh brought you out from this place. No leavened bread shall be eaten.', pt: 'E Moisés disse ao povo: Lembrai-vos deste dia, em que saístes do Egito, da casa da servidão; pois com mão forte o Senhor vos tirou daqui; portanto não se comerá pão levedado.' },
      { v: 4, en: 'Today you go out in the month Abib.', pt: 'Hoje, no mês de abibe, vós saís.' },
      { v: 5, en: 'It shall be, when Yahweh shall bring you into the land of the Canaanite, and the Hittite, and the Amorite, and the Hivite, and the Jebusite, which he swore to your fathers to give you, a land flowing with milk and honey, that you shall keep this service in this month.', pt: 'Quando o Senhor te houver introduzido na terra dos cananeus, dos heteus, dos amorreus, dos heveus e dos jebuseus, que ele jurou a teus pais que te daria, terra que mana leite e mel, guardarás este culto nestê mes.' },
      { v: 6, en: 'Seven days you shall eat unleavened bread, and in the seventh day shall be a feast to Yahweh.', pt: 'Sete dias comerás pães ázimos, e ao sétimo dia haverá uma festa ao Senhor.' },
      { v: 7, en: 'Unleavened bread shall be eaten throughout the seven days; and no leavened bread shall be seen with you. No yeast shall be seen with you, within all your borders.', pt: 'Sete dias se comerão pães ázimos, e o levedado não se verá contigo, nem ainda fermento será visto em todos os teus termos.' },
      { v: 8, en: 'You shall tell your son in that day, saying, ‘It is because of that which Yahweh did for me when I came out of Egypt.’', pt: 'Naquele dia contarás a teu filho, dizendo: Isto é por causa do que o Senhor me fez, quando eu saí do Egito;' },
      { v: 9, en: 'It shall be for a sign to you on your hand, and for a memorial between your eyes, that Yahweh’s law may be in your mouth; for with a strong hand Yahweh has brought you out of Egypt.', pt: 'e te será por sinal sobre tua mão e por memorial entre teus olhos, para que a lei do Senhor esteja em tua boca; porquanto com mão forte o Senhor te tirou do Egito.' },
      { v: 10, en: 'You shall therefore keep this ordinance in its season from year to year.', pt: 'Portanto guardarás este estatuto a seu tempo, de ano em ano.' },
      { v: 11, en: '“It shall be, when Yahweh shall bring you into the land of the Canaanite, as he swore to you and to your fathers, and shall give it you,', pt: 'Também quando o Senhor te houver introduzido na terra dos cananeus, como jurou a ti e a teus pais, quando ta houver dado,' },
      { v: 12, en: 'that you shall set apart to Yahweh all that opens the womb, and every firstborn that comes from an animal which you have. The males shall be Yahweh’s.', pt: 'separarás para o Senhor tudo o que abrir a madre, até mesmo todo primogênito dos teus animais; os machos serão do Senhor.' },
      { v: 13, en: 'Every firstborn of a donkey you shall redeem with a lamb; and if you will not redeem it, then you shall break its neck; and you shall redeem all the firstborn of man among your sons.', pt: 'Mas todo primogênito de jumenta resgatarás com um cordeiro; e, se o não quiseres resgatar, quebrar-lhe-ás a cerviz:; e todo primogênito do homem entre teus filhos resgatarás.' },
      { v: 14, en: 'It shall be, when your son asks you in time to come, saying, ‘What is this?’ that you shall tell him, ‘By strength of hand Yahweh brought us out from Egypt, from the house of bondage.', pt: 'E quando teu filho te perguntar no futuro, dizendo: Que é isto? responder-lhe-ás: O Senhor, com mão forte, nos tirou do Egito, da casa da servidão.' },
      { v: 15, en: 'When Pharaoh stubbornly refused to let us go, Yahweh killed all the firstborn in the land of Egypt, both the firstborn of man, and the firstborn of livestock. Therefore I sacrifice to Yahweh all that opens the womb, being males; but all the firstborn of my sons I redeem.’', pt: 'Porque sucedeu que, endurecendo-se Faraó, para não nos deixar ir, o Senhor matou todos os primogênitos na terra do Egito, tanto os primogênitos dos homens como os primogênitos dos animais; por isso eu sacrifico ao Senhor todos os primogênitos, sendo machos; mas a todo primogênito de meus filhos eu resgato.' },
      { v: 16, en: 'It shall be for a sign on your hand, and for symbols between your eyes: for by strength of hand Yahweh brought us out of Egypt.”', pt: 'E isto será por sinal sobre tua mão, e por frontais entre os teus olhos, porque o Senhor, com mão forte, nos tirou do Egito.' },
      { v: 17, en: 'When Pharaoh had let the people go, God didn’t lead them by the way of the land of the Philistines, although that was near; for God said, “Lest perhaps the people change their minds when they see war, and they return to Egypt”;', pt: 'Ora, quando Faraó deixou ir o povo, Deus não o conduziu pelo caminho da terra dos filisteus, se bem que fosse mais perto; porque Deus disse: Para que porventura o povo não se arrependa, vendo a guerra, e volte para o Egito;' },
      { v: 18, en: 'but God led the people around by the way of the wilderness by the Red Sea; and the children of Israel went up armed out of the land of Egypt.', pt: 'mas Deus fez o povo rodear pelo caminho do deserto perto do Mar Vermelho; e os filhos de Israel subiram armados da terra do Egito.' },
      { v: 19, en: 'Moses took the bones of Joseph with him, for he had made the children of Israel swear, saying, “God will surely visit you, and you shall carry up my bones away from here with you.”', pt: 'Moisés levou consigo os ossos de José, porquanto havia este solenemente ajuramentado os filhos de Israel, dizendo: Certamente Deus vos visitará; e vós haveis de levar daqui convosco os meus ossos.' },
      { v: 20, en: 'They took their journey from Succoth, and encamped in Etham, in the edge of the wilderness.', pt: 'Assim partiram de Sucote, e acamparam-se em Etã, à entrada do deserto.' },
      { v: 21, en: 'Yahweh went before them by day in a pillar of cloud, to lead them on their way, and by night in a pillar of fire, to give them light, that they might go by day and by night:', pt: 'E o Senhor ia adiante deles, de dia numa coluta e os dois para os guiar pelo caminho, e de noite numa coluna de fogo para os alumiar, a fim de que caminhassem de dia e de noite.' },
      { v: 22, en: 'the pillar of cloud by day, and the pillar of fire by night, didn’t depart from before the people.', pt: 'Não desaparecia de diante do povo a coluna de nuvem de dia, nem a coluna de fogo de noite.' },
    ],
    14: [
      { v: 1, en: 'Yahweh spoke to Moses, saying,', pt: 'Disse o Senhor a Moisés:' },
      { v: 2, en: '“Speak to the children of Israel, that they turn back and encamp before Pihahiroth, between Migdol and the sea, before Baal Zephon. You shall encamp opposite it by the sea.', pt: 'Fala aos filhos de Israel que se voltem e se acampem diante de Pi-Hairote, entre Migdol e o mar, diante de Baal-Zefom; em frente dele assentareis o acampamento junto ao mar.' },
      { v: 3, en: 'Pharaoh will say of the children of Israel, ‘They are entangled in the land. The wilderness has shut them in.’', pt: 'Então Faraó dirá dos filhos de Israel: Eles estão embaraçados na terra, o deserto os encerrou.' },
      { v: 4, en: 'I will harden Pharaoh’s heart, and he will follow after them; and I will get honor over Pharaoh, and over all his armies; and the Egyptians shall know that I am Yahweh.” They did so.', pt: 'Eu endurecerei o coração de Faraó, e ele os perseguirá; glorificar-me-ei em Faraó, e em todo o seu exército; e saberão os egípcios que eu sou o Senhor. E eles fizeram assim.' },
      { v: 5, en: 'The king of Egypt was told that the people had fled; and the heart of Pharaoh and of his servants was changed towards the people, and they said, “What is this we have done, that we have let Israel go from serving us?”', pt: 'Quando, pois, foi anunciado ao rei do Egito que o povo havia fugido, mudou-se o coração de Faraó, e dos seus servos, contra o povo, e disseram: Que é isso que fizemos, permitindo que Israel saísse e deixasse de nos servir?' },
      { v: 6, en: 'He prepared his chariot, and took his army with him;', pt: 'E Faraó aprontou o seu carro, e tomou consigo o seu povo;' },
      { v: 7, en: 'and he took six hundred chosen chariots, and all the chariots of Egypt, and captains over all of them.', pt: 'tomou também seiscentos carros escolhidos e todos os carros do Egito, e capitães sobre todos eles.' },
      { v: 8, en: 'Yahweh hardened the heart of Pharaoh king of Egypt, and he pursued the children of Israel; for the children of Israel went out with a high hand.', pt: 'Porque o Senhor endureceu o coração de Faraó, rei do Egito, e este perseguiu os filhos de Israel; pois os filhos de Israel saíam afoitamente.' },
      { v: 9, en: 'The Egyptians pursued them. All the horses and chariots of Pharaoh, his horsemen, and his army overtook them encamping by the sea, beside Pihahiroth, before Baal Zephon.', pt: 'Os egípcios, com todos os cavalos e carros de Faraó, e os seus cavaleiros e o seu exército, os perseguiram e os alcançaram acampados junto ao mar, perto de Pi-Hairote, diante de Baal-Zefom.' },
      { v: 10, en: 'When Pharaoh came near, the children of Israel lifted up their eyes, and behold, the Egyptians were marching after them; and they were very afraid. The children of Israel cried out to Yahweh.', pt: 'Quando Faraó se aproximava, os filhos de Israel levantaram os olhos, e eis que os egípcios marchavam atrás deles; pelo que tiveram muito medo os filhos de Israel e clamaram ao Senhor:' },
      { v: 11, en: 'They said to Moses, “Because there were no graves in Egypt, have you taken us away to die in the wilderness? Why have you treated us this way, to bring us out of Egypt?', pt: 'e disseram a Moisés: Foi porque não havia sepulcros no Egito que de lá nos tiraste para morrermos neste deserto? Por que nos fizeste isto, tirando-nos do Egito?' },
      { v: 12, en: 'Isn’t this the word that we spoke to you in Egypt, saying, ‘Leave us alone, that we may serve the Egyptians?’ For it would have been better for us to serve the Egyptians than to die in the wilderness.”', pt: 'Não é isto o que te dissemos no Egito: Deixa-nos, que sirvamos aos egípcios? Pois melhor nos fora servir aos egípcios, do que morrermos no deserto.' },
      { v: 13, en: 'Moses said to the people, “Don’t be afraid. Stand still, and see the salvation of Yahweh, which he will work for you today: for the Egyptians whom you have seen today, you shall never see them again.', pt: 'Moisés, porém, disse ao povo: Não temais; estai quietos, e vede o livramento do Senhor, que ele hoje vos fará; porque aos egípcios que hoje vistes, nunca mais tornareis a ver;' },
      { v: 14, en: 'Yahweh will fight for you, and you shall be still.”', pt: 'o Senhor pelejará por vós; e vós vos calareis.' },
      { v: 15, en: 'Yahweh said to Moses, “Why do you cry to me? Speak to the children of Israel, that they go forward.', pt: 'Então disse o Senhor a Moisés: Por que clamas a mim? dize aos filhos de Israel que marchem.' },
      { v: 16, en: 'Lift up your rod, and stretch out your hand over the sea, and divide it: and the children of Israel shall go into the middle of the sea on dry ground.', pt: 'E tu, levanta a tua vara, e estende a mão sobre o mar e fende-o, para que os filhos de Israel passem pelo meio do mar em seco.' },
      { v: 17, en: 'Behold, I myself will harden the hearts of the Egyptians, and they shall go in after them: and I will get myself honor over Pharaoh, and over all his armies, over his chariots, and over his horsemen.', pt: 'Eis que eu endurecerei o coração dos egípcios, e estes entrarão atrás deles; e glorificar-me-ei em Faraó e em todo o seu exército, nos seus carros e nos seus cavaleiros.' },
      { v: 18, en: 'The Egyptians shall know that I am Yahweh, when I have gotten myself honor over Pharaoh, over his chariots, and over his horsemen.”', pt: 'E os egípcios saberão que eu sou o Senhor, quando me tiver glorificado em Faraó, nos seus carros e nos seus cavaleiros.' },
      { v: 19, en: 'The angel of God, who went before the camp of Israel, moved and went behind them; and the pillar of cloud moved from before them, and stood behind them.', pt: 'Então o anjo de Deus, que ia adiante do exército de Israel, se retirou e se pos atrás deles; também a coluna de nuvem se retirou de diante deles e se pôs atrás,' },
      { v: 20, en: 'It came between the camp of Egypt and the camp of Israel; and there was the cloud and the darkness, yet gave it light by night: and one didn’t come near the other all night.', pt: 'colocando-se entre o campo dos egípcios e o campo dos israelitas; assim havia nuvem e trevas; contudo aquela clareava a noite para Israel; de maneira que em toda a noite não se aproximou um do outro.' },
      { v: 21, en: 'Moses stretched out his hand over the sea, and Yahweh caused the sea to go back by a strong east wind all night, and made the sea dry land, and the waters were divided.', pt: 'Então Moisés estendeu a mão sobre o mar; e o Senhor fez retirar o mar por um forte vento oriental toda aquela noite, e fez do mar terra seca, e as águas foram divididas.' },
      { v: 22, en: 'The children of Israel went into the middle of the sea on the dry ground, and the waters were a wall to them on their right hand, and on their left.', pt: 'E os filhos de Israel entraram pelo meio do mar em seco; e as águas foram-lhes qual muro à sua direita e à sua esquerda.' },
      { v: 23, en: 'The Egyptians pursued, and went in after them into the middle of the sea: all of Pharaoh’s horses, his chariots, and his horsemen.', pt: 'E os egípcios os perseguiram, e entraram atrás deles até o meio do mar, com todos os cavalos de Faraó, os seus carros e os seus cavaleiros.' },
      { v: 24, en: 'In the morning watch, Yahweh looked out on the Egyptian army through the pillar of fire and of cloud, and confused the Egyptian army.', pt: 'Na vigília da manhã, o Senhor, na coluna do fogo e da nuvem, olhou para o campo dos egípcios, e alvoroçou o campo dos egípcios;' },
      { v: 25, en: 'He took off their chariot wheels, and they drove them heavily; so that the Egyptians said, “Let’s flee from the face of Israel, for Yahweh fights for them against the Egyptians!”', pt: 'embaraçou-lhes as rodas dos carros, e fê-los andar dificultosamente; de modo que os egípcios disseram: Fujamos de diante de Israel, porque o Senhor peleja por eles contra os egípcios.' },
      { v: 26, en: 'Yahweh said to Moses, “Stretch out your hand over the sea, that the waters may come again on the Egyptians, on their chariots, and on their horsemen.”', pt: 'Nisso o Senhor disse a Moisés: Estende a mão sobre o mar, para que as águas se tornem sobre os egípcios, sobre os seus carros e sobre os seus cavaleiros.' },
      { v: 27, en: 'Moses stretched out his hand over the sea, and the sea returned to its strength when the morning appeared; and the Egyptians fled against it. Yahweh overthrew the Egyptians in the middle of the sea.', pt: 'Então Moisés estendeu a mão sobre o mar, e o mar retomou a sua força ao amanhecer, e os egípcios fugiram de encontro a ele; assim o Senhor derribou os egípcios no meio do mar.' },
      { v: 28, en: 'The waters returned, and covered the chariots and the horsemen, even all Pharaoh’s army that went in after them into the sea. There remained not so much as one of them.', pt: 'As águas, tornando, cobriram os carros e os cavaleiros, todo o exército de Faraó, que atrás deles havia entrado no mar; não ficou nem sequer um deles.' },
      { v: 29, en: 'But the children of Israel walked on dry land in the middle of the sea, and the waters were a wall to them on their right hand, and on their left.', pt: 'Mas os filhos de Israel caminharam a pé enxuto pelo meio do mar; as águas foram-lhes qual muro à sua direita e à sua esquerda.' },
      { v: 30, en: 'Thus Yahweh saved Israel that day out of the hand of the Egyptians; and Israel saw the Egyptians dead on the seashore.', pt: 'Assim o Senhor, naquele dia, salvou Israel da mão dos egípcios; e Israel viu os egípcios mortos na praia do mar.' },
      { v: 31, en: 'Israel saw the great work which Yahweh did to the Egyptians, and the people feared Yahweh; and they believed in Yahweh, and in his servant Moses.', pt: 'E viu Israel a grande obra que o Senhor operara contra os egípcios; pelo que o povo temeu ao Senhor, e creu no Senhor e em Moisés, seu servo.' },
    ],
    15: [
      { v: 1, en: 'Then Moses and the children of Israel sang this song to Yahweh, and said, “I will sing to Yahweh, for he has triumphed gloriously. The horse and his rider he has thrown into the sea.', pt: 'Então cantaram Moisés e os filhos de Israel este cântico ao Senhor, dizendo: Cantarei ao Senhor, porque gloriosamente triunfou; lançou no mar o cavalo e o seu cavaleiro.' },
      { v: 2, en: 'Yah is my strength and song. He has become my salvation. This is my God, and I will praise him; my father’s God, and I will exalt him.', pt: 'O Senhor é a minha força, e o meu cântico; ele se tem tornado a minha salvação; é ele o meu Deus, portanto o louvarei; é o Deus de meu pai, por isso o exaltarei.' },
      { v: 3, en: 'Yahweh is a man of war. Yahweh is his name.', pt: 'O Senhor é homem de guerra; Jeová é o seu nome.' },
      { v: 4, en: 'He has cast Pharaoh’s chariots and his army into the sea. His chosen captains are sunk in the Red Sea.', pt: 'Lançou no mar os carros de Faraó e o seu exército; os seus escolhidos capitães foram submersos no Mar Vermelho.' },
      { v: 5, en: 'The deeps cover them. They went down into the depths like a stone.', pt: 'Os abismos os cobriram; desceram às profundezas como pedra.' },
      { v: 6, en: 'Your right hand, Yahweh, is glorious in power. Your right hand, Yahweh, dashes the enemy in pieces.', pt: 'A tua destra, ó Senhor, é gloriosa em poder; a tua destra, ó Senhor, destroça o inimigo.' },
      { v: 7, en: 'In the greatness of your excellency, you overthrow those who rise up against you. You send out your wrath. It consumes them as stubble.', pt: 'Na grandeza da tua excelência derrubas os que se levantam contra ti; envias o teu furor, que os devora como restolho.' },
      { v: 8, en: 'With the blast of your nostrils, the waters were piled up. The floods stood upright as a heap. The deeps were congealed in the heart of the sea.', pt: 'Ao sopro dos teus narizes amontoaram-se as águas, as correntes pararam como montão; os abismos coalharam-se no coração do mar.' },
      { v: 9, en: 'The enemy said, ‘I will pursue. I will overtake. I will divide the plunder. My desire shall be satisfied on them. I will draw my sword, my hand shall destroy them.’', pt: 'O inimigo dizia: Perseguirei, alcançarei, repartirei os despojos; deles se satisfará o meu desejo; arrancarei a minha espada, a minha mão os destruirá.' },
      { v: 10, en: 'You blew with your wind. The sea covered them. They sank like lead in the mighty waters.', pt: 'Sopraste com o teu vento, e o mar os cobriu; afundaram-se como chumbo em grandes aguas.' },
      { v: 11, en: 'Who is like you, Yahweh, among the gods? Who is like you, glorious in holiness, fearful in praises, doing wonders?', pt: 'Quem entre os deuses é como tu, ó Senhor? a quem é como tu poderoso em santidade, admirável em louvores, operando maravilhas?' },
      { v: 12, en: 'You stretched out your right hand. The earth swallowed them.', pt: 'Estendeste a mão direita, e a terra os tragou.' },
      { v: 13, en: '“You, in your loving kindness, have led the people that you have redeemed. You have guided them in your strength to your holy habitation.', pt: 'Na tua beneficência guiaste o povo que remiste; na tua força o conduziste à tua santa habitação.' },
      { v: 14, en: 'The peoples have heard. They tremble. Pangs have taken hold on the inhabitants of Philistia.', pt: 'Os povos ouviram e estremeceram; dores apoderaram-se dos a habitantes da Filístia.' },
      { v: 15, en: 'Then the chiefs of Edom were dismayed. Trembling takes hold of the mighty men of Moab. All the inhabitants of Canaan have melted away.', pt: 'Então os príncipes de Edom se pasmaram; dos poderosos de Moabe apoderou-se um tremor; derreteram-se todos os habitantes de Canaã.' },
      { v: 16, en: 'Terror and dread falls on them. By the greatness of your arm they are as still as a stone— until your people pass over, Yahweh, until the people you have purchased pass over.', pt: 'Sobre eles caiu medo, e pavor; pela grandeza do teu braço emudeceram como uma pedra, até que o teu povo passasse, ó Senhor, até que passasse este povo que adquiriste.' },
      { v: 17, en: 'You shall bring them in, and plant them in the mountain of your inheritance, the place, Yahweh, which you have made for yourself to dwell in; the sanctuary, Lord, which your hands have established.', pt: 'Tu os introduzirás, e os plantarás no monte da tua herança, no lugar que tu, ó Senhor, aparelhaste para a tua habitação, no santuário, ó Senhor, que as tuas mãos estabeleceram.' },
      { v: 18, en: 'Yahweh shall reign forever and ever.”', pt: 'O Senhor reinará eterna e perpetuamente.' },
      { v: 19, en: 'For the horses of Pharaoh went in with his chariots and with his horsemen into the sea, and Yahweh brought back the waters of the sea on them; but the children of Israel walked on dry land in the middle of the sea.', pt: 'Porque os cavalos de Faraó, com os seus carros e com os seus cavaleiros, entraram no mar, e o Senhor fez tornar as águas do mar sobre eles, mas os filhos de Israel passaram em seco pelo meio do mar.' },
      { v: 20, en: 'Miriam the prophetess, the sister of Aaron, took a tambourine in her hand; and all the women went out after her with tambourines and with dances.', pt: 'Então Miriã, a profetisa, irmã de Arão, tomou na mão um tamboril, e todas as mulheres saíram atrás dela com tamboris, e com danças.' },
      { v: 21, en: 'Miriam answered them, “Sing to Yahweh, for he has triumphed gloriously. The horse and his rider he has thrown into the sea.”', pt: 'E Miriã lhes respondia: Cantai ao Senhor, porque gloriosamente triunfou; lançou no mar o cavalo com o seu cavaleiro.' },
      { v: 22, en: 'Moses led Israel onward from the Red Sea, and they went out into the wilderness of Shur; and they went three days in the wilderness, and found no water.', pt: 'Depois Moisés fez partir a Israel do Mar Vermelho, e saíram para o deserto de Sur; caminharam três dias no deserto, e não acharam água.' },
      { v: 23, en: 'When they came to Marah, they couldn’t drink from the waters of Marah, for they were bitter. Therefore its name was called Marah.', pt: 'E chegaram a Mara, mas não podiam beber das suas águas, porque eram amargas; por isso chamou-se o lugar Mara.' },
      { v: 24, en: 'The people murmured against Moses, saying, “What shall we drink?”', pt: 'E o povo murmurou contra Moisés, dizendo: Que havemos de beber?' },
      { v: 25, en: 'Then he cried to Yahweh. Yahweh showed him a tree, and he threw it into the waters, and the waters were made sweet. There he made a statute and an ordinance for them, and there he tested them;', pt: 'Então clamou Moisés ao Senhor, e o Senhor mostrou-lhe uma árvore, e Moisés lançou-a nas águas, as quais se tornaram doces. Ali Deus lhes deu um estatuto e uma ordenança, e ali os provou,' },
      { v: 26, en: 'and he said, “If you will diligently listen to Yahweh your God’s voice, and will do that which is right in his eyes, and will pay attention to his commandments, and keep all his statutes, I will put none of the diseases on you, which I have put on the Egyptians; for I am Yahweh who heals you.”', pt: 'dizendo: Se ouvires atentamente a voz do Senhor teu Deus, e fizeres o que é reto diante de seus olhos, e inclinares os ouvidos aos seus mandamentos, e guardares todos os seus estatutos, sobre ti não enviarei nenhuma das enfermidades que enviei sobre os egípcios; porque eu sou o Senhor que te sara.' },
      { v: 27, en: 'They came to Elim, where there were twelve springs of water, and seventy palm trees: and they encamped there by the waters.', pt: 'Então vieram a Elim, onde havia doze fontes de água e setenta palmeiras; e ali, junto das águas, acamparam.' },
    ],
    16: [
      { v: 1, en: 'They took their journey from Elim, and all the congregation of the children of Israel came to the wilderness of Sin, which is between Elim and Sinai, on the fifteenth day of the second month after their departing out of the land of Egypt.', pt: 'Depois partiram de Elim; e veio toda a congregação dos filhos de Israel ao deserto de Sim, que está entre Elim e Sinai, aos quinze dias do segundo mês depois que saíram da terra do Egito.' },
      { v: 2, en: 'The whole congregation of the children of Israel murmured against Moses and against Aaron in the wilderness;', pt: 'E toda a congregação dos filhos de Israel murmurou contra Moisés e contra Arão no deserto.' },
      { v: 3, en: 'and the children of Israel said to them, “We wish that we had died by Yahweh’s hand in the land of Egypt, when we sat by the meat pots, when we ate our fill of bread, for you have brought us out into this wilderness, to kill this whole assembly with hunger.”', pt: 'Pois os filhos de Israel lhes disseram: Quem nos dera que tivéssemos morrido pela mão do Senhor na terra do Egito, quando estávamos sentados junto às panelas de carne, quando comíamos pão até fartar! porque nos tendes tirado para este deserto, para matardes de fome a toda esta multidão.' },
      { v: 4, en: 'Then Yahweh said to Moses, “Behold, I will rain bread from the sky for you, and the people shall go out and gather a day’s portion every day, that I may test them, whether they will walk in my law, or not.', pt: 'Então disse o Senhor a Moisés: Eis que vos farei chover pão do céu; e sairá o povo e colherá diariamente a porção para cada dia, para que eu o prove se anda em minha lei ou não.' },
      { v: 5, en: 'It shall come to pass on the sixth day, that they shall prepare that which they bring in, and it shall be twice as much as they gather daily.”', pt: 'Mas ao sexto dia prepararão o que colherem; e será o dobro do que colhem cada dia.' },
      { v: 6, en: 'Moses and Aaron said to all the children of Israel, “At evening, then you shall know that Yahweh has brought you out from the land of Egypt;', pt: 'Disseram, pois, Moisés e Arão a todos os filhos de Israel: tarde sabereis que o Senhor é quem vos tirou da terra do Egito,' },
      { v: 7, en: 'and in the morning, then you shall see Yahweh’s glory; because he hears your murmurings against Yahweh. Who are we, that you murmur against us?”', pt: 'e amanhã vereis a glória do Senhor, porquanto ele ouviu as vossas murmurações contra o Senhor; e quem somos nós, para que murmureis contra nós?' },
      { v: 8, en: 'Moses said, “Now Yahweh shall give you meat to eat in the evening, and in the morning bread to satisfy you; because Yahweh hears your murmurings which you murmur against him. And who are we? Your murmurings are not against us, but against Yahweh.”', pt: 'Disse mais Moisés: Isso será quando o Senhor à tarde vos der carne para comer, e pela manhã pão a fartar, porquanto o Senhor ouve as vossas murmurações, com que murmurais contra ele; e quem somos nós? As vossas murmurações não são contra nós, mas sim contra o Senhor.' },
      { v: 9, en: 'Moses said to Aaron, “Tell all the congregation of the children of Israel, ‘Come near before Yahweh, for he has heard your murmurings.’”', pt: 'Depois disse Moisés a Arão: Dize a toda a congregação dos filhos de Israel: Chegai-vos à presença do Senhor, porque ele ouviu as vossas murmurações.' },
      { v: 10, en: 'As Aaron spoke to the whole congregation of the children of Israel, they looked toward the wilderness, and behold, Yahweh’s glory appeared in the cloud.', pt: 'E quando Arão falou a toda a congregação dos filhos de Israel, estes olharam para o deserto, e eis que a glória do Senhor, apareceu na nuvem.' },
      { v: 11, en: 'Yahweh spoke to Moses, saying,', pt: 'Então o Senhor falou a Moisés, dizendo:' },
      { v: 12, en: '“I have heard the murmurings of the children of Israel. Speak to them, saying, ‘At evening you shall eat meat, and in the morning you shall be filled with bread: and you shall know that I am Yahweh your God.’”', pt: 'Tenho ouvido as murmurações dos filhos de Israel; dize-lhes: ë tardinha comereis carne, e pela manhã vos fartareis de pão; e sabereis que eu sou o Senhor vosso Deus.' },
      { v: 13, en: 'In the evening, quail came up and covered the camp; and in the morning the dew lay around the camp.', pt: 'E aconteceu que à tarde subiram codornizes, e cobriram o arraial; e pela manhã havia uma camada de orvalho ao redor do arraial.' },
      { v: 14, en: 'When the dew that lay had gone, behold, on the surface of the wilderness was a small round thing, small as the frost on the ground.', pt: 'Quando desapareceu a camada de orvalho, eis que sobre a superfície do deserto estava uma coisa miúda, semelhante a escamas, coisa miúda como a geada sobre a terra.' },
      { v: 15, en: 'When the children of Israel saw it, they said to one another, “What is it?” For they didn’t know what it was. Moses said to them, “It is the bread which Yahweh has given you to eat.”', pt: 'E, vendo-a os filhos de Israel, disseram uns aos outros: Que é isto? porque não sabiam o que era. Então lhes disse Moisés: Este é o pão que o Senhor vos deu para comer.' },
      { v: 16, en: 'This is the thing which Yahweh has commanded: “Gather of it everyone according to his eating; an omer a head, according to the number of your persons, you shall take it, every man for those who are in his tent.”', pt: 'Isto é o que o Senhor ordenou: Colhei dele cada um conforme o que pode comer; um gômer para cada cabeça, segundo o número de pessoas; cada um tomará para os que se acharem na sua tenda.' },
      { v: 17, en: 'The children of Israel did so, and gathered some more, some less.', pt: 'Assim o fizeram os filhos de Israel; e colheram uns mais e outros menos.' },
      { v: 18, en: 'When they measured it with an omer, he who gathered much had nothing over, and he who gathered little had no lack. They gathered every man according to his eating.', pt: 'Quando, porém, o mediam com o gômer, nada sobejava ao que colhera muito, nem faltava ao que colhera pouco; colhia cada um tanto quanto podia comer.' },
      { v: 19, en: 'Moses said to them, “Let no one leave of it until the morning.”', pt: 'Também disse-lhes Moisés: Ninguém deixe dele para amanhã.' },
      { v: 20, en: 'Notwithstanding they didn’t listen to Moses, but some of them left of it until the morning, and it bred worms, and became foul: and Moses was angry with them.', pt: 'Eles, porém, não deram ouvidos a Moisés, antes alguns dentre eles deixaram dele para o dia seguinte; e criou bichos, e cheirava mal; por isso indignou-se Moisés contra eles.' },
      { v: 21, en: 'They gathered it morning by morning, everyone according to his eating. When the sun grew hot, it melted.', pt: 'Colhiam-no, pois, pela manhã, cada um conforme o que podia comer; porque, vindo o calor do sol, se derretia.' },
      { v: 22, en: 'On the sixth day, they gathered twice as much bread, two omers for each one, and all the rulers of the congregation came and told Moses.', pt: 'Mas ao sexto dia colheram pão em dobro, dois gômeres para cada um; pelo que todos os principais da congregação vieram, e contaram-no a Moisés.' },
      { v: 23, en: 'He said to them, “This is that which Yahweh has spoken, ‘Tomorrow is a solemn rest, a holy Sabbath to Yahweh. Bake that which you want to bake, and boil that which you want to boil; and all that remains over lay up for yourselves to be kept until the morning.’”', pt: 'E ele lhes disse: Isto é o que o Senhor tem dito: Amanhã é repouso, sábado santo ao Senhor; o que quiserdes assar ao forno, assai-o, e o que quiserdes cozer em água, cozei-o em água; e tudo o que sobejar, ponde-o de lado para vós, guardando-o para amanhã.' },
      { v: 24, en: 'They laid it up until the morning, as Moses asked, and it didn’t become foul, and there were no worms in it.', pt: 'Guardaram-no, pois, até o dia seguinte, como Moisés tinha ordenado; e não cheirou mal, nem houve nele bicho algum.' },
      { v: 25, en: 'Moses said, “Eat that today, for today is a Sabbath to Yahweh. Today you shall not find it in the field.', pt: 'Então disse Moisés: Comei-o hoje, porquanto hoje é o sábado do Senhor; hoje não o achareis no campo.' },
      { v: 26, en: 'Six days you shall gather it, but on the seventh day is the Sabbath. In it there shall be none.”', pt: 'Seis dias o colhereis, mas o sétimo dia é o sábado; nele não haverá.' },
      { v: 27, en: 'On the seventh day, some of the people went out to gather, and they found none.', pt: 'Mas aconteceu ao sétimo dia que saíram alguns do povo para o colher, e não o acharam.' },
      { v: 28, en: 'Yahweh said to Moses, “How long do you refuse to keep my commandments and my laws?', pt: 'Então disse o Senhor a Moisés: Até quando recusareis guardar os meus mandamentos e as minhas leis?' },
      { v: 29, en: 'Behold, because Yahweh has given you the Sabbath, therefore he gives you on the sixth day the bread of two days. Everyone stay in his place. Let no one go out of his place on the seventh day.”', pt: 'Vede, visto que o Senhor vos deu o sábado, por isso ele no sexto dia vos dá pão para dois dias; fique cada um no seu lugar, não saia ninguém do seu lugar no sétimo dia.' },
      { v: 30, en: 'So the people rested on the seventh day.', pt: 'Assim repousou o povo no sétimo dia.' },
      { v: 31, en: 'The house of Israel called its name Manna, and it was like coriander seed, white; and its taste was like wafers with honey.', pt: 'A casa de Israel deu-lhe o nome de maná. Era como semente de coentro; era branco, e tinha o sabor de bolos de mel.' },
      { v: 32, en: 'Moses said, “This is the thing which Yahweh has commanded, ‘Let an omer-full of it be kept throughout your generations, that they may see the bread with which I fed you in the wilderness, when I brought you out of the land of Egypt.’”', pt: 'E disse Moisés: Isto é o que o Senhor ordenou: Dele enchereis um gômer, o qual se guardará para as vossas gerações, para que elas vejam o pão que vos dei a comer no deserto, quando eu vos tirei da terra do Egito.' },
      { v: 33, en: 'Moses said to Aaron, “Take a pot, and put an omer-full of manna in it, and lay it up before Yahweh, to be kept throughout your generations.”', pt: 'Disse também Moisés a Arão: Toma um vaso, mete nele um gômer cheio de maná e põe-no diante do Senhor, a fim de que seja guardado para as vossas gerações.' },
      { v: 34, en: 'As Yahweh commanded Moses, so Aaron laid it up before the Testimony, to be kept.', pt: 'Como o Senhor tinha ordenado a Moisés, assim Arão o pôs diante do testemunho, para ser guardado.' },
      { v: 35, en: 'The children of Israel ate the manna forty years, until they came to an inhabited land. They ate the manna until they came to the borders of the land of Canaan.', pt: 'Ora, os filhos de Israel comeram o maná quarenta anos, até que chegaram a uma terra habitada; comeram o maná até que chegaram aos termos da terra de Canaã.' },
      { v: 36, en: 'Now an omer is one tenth of an ephah.', pt: 'Um gômer é a décima parte de uma efa.' },
    ],
    17: [
      { v: 1, en: 'All the congregation of the children of Israel traveled from the wilderness of Sin, by their journeys, according to Yahweh’s commandment, and encamped in Rephidim; but there was no water for the people to drink.', pt: 'Partiu toda a congregação dos filhos de Israel do deserto de Sim, pelas suas jornadas, segundo o mandamento do Senhor, e acamparam em Refidim; e não havia ali água para o povo beber.' },
      { v: 2, en: 'Therefore the people quarreled with Moses, and said, “Give us water to drink.” Moses said to them, “Why do you quarrel with me? Why do you test Yahweh?”', pt: 'Então o povo contendeu com Moisés, dizendo: Dá-nos água para beber. Respondeu-lhes Moisés: Por que contendeis comigo? por que tentais ao Senhor?' },
      { v: 3, en: 'The people were thirsty for water there; and the people murmured against Moses, and said, “Why have you brought us up out of Egypt, to kill us, our children, and our livestock with thirst?”', pt: 'Mas o povo, tendo sede ali, murmurou contra Moisés, dizendo: Por que nos fizeste subir do Egito, para nos matares de sede, a nós e aos nossos filhos, e ao nosso gado?' },
      { v: 4, en: 'Moses cried to Yahweh, saying, “What shall I do with these people? They are almost ready to stone me.”', pt: 'Pelo que Moisés, clamando ao Senhor, disse: Que hei de fazer a este povo? daqui a pouco me apedrejará.' },
      { v: 5, en: 'Yahweh said to Moses, “Walk on before the people, and take the elders of Israel with you, and take the rod in your hand with which you struck the Nile, and go.', pt: 'Então disse o Senhor a Moisés: Passa adiante do povo, e leva contigo alguns dos anciãos de Israel; toma na mão a tua vara, com que feriste o rio, e vai-te.' },
      { v: 6, en: 'Behold, I will stand before you there on the rock in Horeb. You shall strike the rock, and water will come out of it, that the people may drink.” Moses did so in the sight of the elders of Israel.', pt: 'Eis que eu estarei ali diante de ti sobre a rocha, em Horebe; ferirás a rocha, e dela sairá agua para que o povo possa beber. Assim, pois fez Moisés à vista dos anciãos de Israel.' },
      { v: 7, en: 'He called the name of the place Massah, and Meribah, because the children of Israel quarreled, and because they tested Yahweh, saying, “Is Yahweh among us, or not?”', pt: 'E deu ao lugar o nome de Massá e Meribá, por causa da contenda dos filhos de Israel, e porque tentaram ao Senhor, dizendo: Está o Senhor no meio de nós, ou não?' },
      { v: 8, en: 'Then Amalek came and fought with Israel in Rephidim.', pt: 'Então veio Amaleque, e pelejou contra e Israel em Refidim.' },
      { v: 9, en: 'Moses said to Joshua, “Choose men for us, and go out, fight with Amalek. Tomorrow I will stand on the top of the hill with God’s rod in my hand.”', pt: 'Pelo que disse Moisés a Josué: Escolhe-nos homens, e sai, peleja contra Amaleque; e amanhã eu estarei sobre o cume do outeiro, tendo na mão a vara de Deus.' },
      { v: 10, en: 'So Joshua did as Moses had told him, and fought with Amalek; and Moses, Aaron, and Hur went up to the top of the hill.', pt: 'Fez, pois, Josué como Moisés lhe dissera, e pelejou contra Amaleque; e Moisés, Arão, e Hur subiram ao cume do outeiro.' },
      { v: 11, en: 'When Moses held up his hand, Israel prevailed. When he let down his hand, Amalek prevailed.', pt: 'E acontecia que quando Moisés levantava a mão, prevalecia Israel; mas quando ele abaixava a mão, prevalecia Amaleque.' },
      { v: 12, en: 'But Moses’ hands were heavy; and they took a stone, and put it under him, and he sat on it. Aaron and Hur held up his hands, the one on the one side, and the other on the other side. His hands were steady until sunset.', pt: 'As mãos de Moisés, porém, ficaram cansadas; por isso tomaram uma pedra, e a puseram debaixo dele, e ele sentou-se nela; Arão e Hur sustentavam-lhe as mãos, um de um lado e o outro do outro; assim ficaram as suas mãos firmes até o pôr do sol.' },
      { v: 13, en: 'Joshua defeated Amalek and his people with the edge of the sword.', pt: 'Assim Josué prostrou a Amaleque e a seu povo, ao fio da espada.' },
      { v: 14, en: 'Yahweh said to Moses, “Write this for a memorial in a book, and rehearse it in the ears of Joshua: that I will utterly blot out the memory of Amalek from under the sky.”', pt: 'Então disse o Senhor a Moisés: Escreve isto para memorial num livro, e relata-o aos ouvidos de Josué; que eu hei de riscar totalmente a memória de Amaleque de debaixo do céu.' },
      { v: 15, en: 'Moses built an altar, and called its name Yahweh our Banner.', pt: 'Pelo que Moisés edificou um altar, ao qual chamou Jeová-Níssi.' },
      { v: 16, en: 'He said, “Yah has sworn: ‘Yahweh will have war with Amalek from generation to generation.’”', pt: 'E disse: Porquanto jurou o Senhor que ele fará guerra contra Amaleque de geração em geração.' },
    ],
    18: [
      { v: 1, en: 'Now Jethro, the priest of Midian, Moses’ father-in-law, heard of all that God had done for Moses, and for Israel his people, how that Yahweh had brought Israel out of Egypt.', pt: 'Ora Jetro, sacerdote de Midiã, sogro de Moisés, ouviu todas as coisas que Deus tinha feito a Moisés e a Israel, seu povo, como o Senhor tinha tirado a Israel do Egito.' },
      { v: 2, en: 'Jethro, Moses’ father-in-law, received Zipporah, Moses’ wife, after he had sent her away,', pt: 'E Jetro, sogro de Moisés, tomou a Zípora, a mulher de Moisés, depois que este lha enviara,' },
      { v: 3, en: 'and her two sons. The name of one son was Gershom, for Moses said, “I have lived as a foreigner in a foreign land”.', pt: 'e aos seus dois filhos, dos quais um se chamava Gérson; porque disse Moisés: Fui peregrino em terra estrangeira;' },
      { v: 4, en: 'The name of the other was Eliezer, for he said, “My father’s God was my help and delivered me from Pharaoh’s sword.”', pt: 'e o outro se chamava Eliézer; porque disse: O Deus de meu pai foi minha ajuda, e me livrou da espada de Faraó.' },
      { v: 5, en: 'Jethro, Moses’ father-in-law, came with his sons and his wife to Moses into the wilderness where he was encamped, at the Mountain of God.', pt: 'Veio, pois, Jetro, o sogro de Moisés, com os filhos e a mulher deste, a Moisés, no deserto onde se tinha acampado, junto ao monte de Deus;' },
      { v: 6, en: 'He said to Moses, “I, your father-in-law Jethro, have come to you with your wife, and her two sons with her.”', pt: 'e disse a Moisés: Eu, teu sogro Jetro, venho a ti, com tua mulher e seus dois filhos com ela.' },
      { v: 7, en: 'Moses went out to meet his father-in-law, and bowed and kissed him. They asked each other of their welfare, and they came into the tent.', pt: 'Então saiu Moisés ao encontro de seu sogro, inclinou-se diante dele e o beijou; perguntaram um ao outro como estavam, e entraram na tenda.' },
      { v: 8, en: 'Moses told his father-in-law all that Yahweh had done to Pharaoh and to the Egyptians for Israel’s sake, all the hardships that had come on them on the way, and how Yahweh delivered them.', pt: 'Depois Moisés contou a seu sogro tudo o que o Senhor tinha feito a Faraó e aos egípcios por amor de Israel, todo o trabalho que lhes sobreviera no caminho, e como o Senhor os livrara.' },
      { v: 9, en: 'Jethro rejoiced for all the goodness which Yahweh had done to Israel, in that he had delivered them out of the hand of the Egyptians.', pt: 'E alegrou-se Jetro por todo o bem que o Senhor tinha feito a Israel, livrando-o da mão dos egipcios,' },
      { v: 10, en: 'Jethro said, “Blessed be Yahweh, who has delivered you out of the hand of the Egyptians, and out of the hand of Pharaoh; who has delivered the people from under the hand of the Egyptians.', pt: 'e disse: Bendito seja o Senhor, que vos livrou da mão dos egípcios e da mão de Faraó; que livrou o povo de debaixo da mão dos egípcios.' },
      { v: 11, en: 'Now I know that Yahweh is greater than all gods because of the thing in which they dealt arrogantly against them.”', pt: 'Agora sei que o Senhor é maior que todos os deuses; até naquilo em que se houveram arrogantemente contra o povo.' },
      { v: 12, en: 'Jethro, Moses’ father-in-law, took a burnt offering and sacrifices for God. Aaron came with all the elders of Israel, to eat bread with Moses’ father-in-law before God.', pt: 'Então Jetro, o sogro de Moisés, tomou holocausto e sacrifícios para Deus; e veio Arão, e todos os anciãos de Israel, para comerem pão com o sogro de Moisés diante de Deus.' },
      { v: 13, en: 'On the next day, Moses sat to judge the people, and the people stood around Moses from the morning to the evening.', pt: 'No dia seguinte assentou-se Moisés para julgar o povo; e o povo estava em pé junto de Moisés desde a manhã até a tarde.' },
      { v: 14, en: 'When Moses’ father-in-law saw all that he did to the people, he said, “What is this thing that you do for the people? Why do you sit alone, and all the people stand around you from morning to evening?”', pt: 'Vendo, pois, o sogro de Moisés tudo o que ele fazia ao povo, perguntou: Que é isto que tu fazes ao povo? por que te assentas só, permanecendo todo o povo junto de ti desde a manhã até a tarde?' },
      { v: 15, en: 'Moses said to his father-in-law, “Because the people come to me to inquire of God.', pt: 'Respondeu Moisés a seu sogro: É por que o povo vem a mim para consultar a Deus.' },
      { v: 16, en: 'When they have a matter, they come to me, and I judge between a man and his neighbor, and I make them know the statutes of God, and his laws.”', pt: 'Quando eles têm alguma questão, vêm a mim; e eu julgo entre um e outro e lhes declaro os estatutos de Deus e as suas leis.' },
      { v: 17, en: 'Moses’ father-in-law said to him, “The thing that you do is not good.', pt: 'O sogro de Moisés, porém, lhe replicou: Não é bom o que fazes.' },
      { v: 18, en: 'You will surely wear away, both you, and this people that is with you; for the thing is too heavy for you. You are not able to perform it yourself alone.', pt: 'certamente desfalecerás, assim tu, como este povo que está contigo; porque isto te é pesado demais; tu só não o podes fazer.' },
      { v: 19, en: 'Listen now to my voice. I will give you counsel, and God be with you. You represent the people before God, and bring the causes to God.', pt: 'Ouve agora a minha voz; eu te aconselharei, e seja Deus contigo: sê tu pelo povo diante de Deus, e leva tu as causas a Deus;' },
      { v: 20, en: 'You shall teach them the statutes and the laws, and shall show them the way in which they must walk, and the work that they must do.', pt: 'ensinar-lhes-ás os estatutos e as leis, e lhes mostrarás o caminho em que devem andar, e a obra que devem fazer.' },
      { v: 21, en: 'Moreover you shall provide out of all the people able men which fear God: men of truth, hating unjust gain; and place such over them, to be rulers of thousands, rulers of hundreds, rulers of fifties, and rulers of tens.', pt: 'Além disto procurarás dentre todo o povo homens de capacidade, tementes a Deus, homens verazes, que aborreçam a avareza, e os porás sobre eles por chefes de mil, chefes de cem, chefes de cinqüenta e chefes de dez;' },
      { v: 22, en: 'Let them judge the people at all times. It shall be that every great matter they shall bring to you, but every small matter they shall judge themselves. So shall it be easier for you, and they shall share the load with you.', pt: 'e julguem eles o povo em todo o tempo. Que a ti tragam toda causa grave, mas toda causa pequena eles mesmos a julguem; assim a ti mesmo te aliviarás da carga, e eles a levarão contigo.' },
      { v: 23, en: 'If you will do this thing, and God commands you so, then you will be able to endure, and all these people also will go to their place in peace.”', pt: 'Se isto fizeres, e Deus to mandar, poderás então subsistir; assim também todo este povo irá em paz para o seu lugar.' },
      { v: 24, en: 'So Moses listened to the voice of his father-in-law, and did all that he had said.', pt: 'E Moisés deu ouvidos à voz de seu sogro, e fez tudo quanto este lhe dissera;' },
      { v: 25, en: 'Moses chose able men out of all Israel, and made them heads over the people, rulers of thousands, rulers of hundreds, rulers of fifties, and rulers of tens.', pt: 'e escolheu Moisés homens capazes dentre todo o Israel, e os pôs por cabeças sobre o povo: chefes de mil, chefes de cem, chefes de cinqüenta e chefes de dez.' },
      { v: 26, en: 'They judged the people at all times. They brought the hard causes to Moses, but every small matter they judged themselves.', pt: 'Estes, pois, julgaram o povo em todo o tempo; as causas graves eles as trouxeram a Moisés; mas toda causa pequena, julgaram-na eles mesmos.' },
      { v: 27, en: 'Moses let his father-in-law depart, and he went his way into his own land.', pt: 'Então despediu Moisés a seu sogro, o qual se foi para a sua terra.' },
    ],
    19: [
      { v: 1, en: 'In the third month after the children of Israel had gone out of the land of Egypt, on that same day they came into the wilderness of Sinai.', pt: 'No terceiro mês depois que os filhos de Israel haviam saído da terra do Egito, no mesmo dia chegaram ao deserto de Sinai.' },
      { v: 2, en: 'When they had departed from Rephidim, and had come to the wilderness of Sinai, they encamped in the wilderness; and there Israel encamped before the mountain.', pt: 'Tendo partido de Refidim, entraram no deserto de Sinai, onde se acamparam; Israel, pois, ali acampou-se em frente do monte.' },
      { v: 3, en: 'Moses went up to God, and Yahweh called to him out of the mountain, saying, “This is what you shall tell the house of Jacob, and tell the children of Israel:', pt: 'Então subiu Moisés a Deus, e do monte o Senhor o chamou, dizendo: Assim falarás à casa de Jacó, e anunciarás aos filhos de Israel:' },
      { v: 4, en: '‘You have seen what I did to the Egyptians, and how I bore you on eagles’ wings, and brought you to myself.', pt: 'Vós tendes visto o que fiz: aos egípcios, como vos levei sobre asas de águias, e vos trouxe a mim.' },
      { v: 5, en: 'Now therefore, if you will indeed obey my voice, and keep my covenant, then you shall be my own possession from among all peoples; for all the earth is mine;', pt: 'Agora, pois, se atentamente ouvirdes a minha voz e guardardes o meu pacto, então sereis a minha possessão peculiar dentre todos os povos, porque minha é toda a terra;' },
      { v: 6, en: 'and you shall be to me a kingdom of priests, and a holy nation.’ These are the words which you shall speak to the children of Israel.”', pt: 'e vós sereis para mim reino sacerdotal e nação santa. São estas as palavras que falarás aos filhos de Israel.' },
      { v: 7, en: 'Moses came and called for the elders of the people, and set before them all these words which Yahweh commanded him.', pt: 'Veio, pois, Moisés e, tendo convocado os anciãos do povo, expôs diante deles todas estas palavras, que o Senhor lhe tinha ordenado.' },
      { v: 8, en: 'All the people answered together, and said, “All that Yahweh has spoken we will do.” Moses reported the words of the people to Yahweh.', pt: 'Ao que todo o povo respondeu a uma voz: Tudo o que o Senhor tem falado, faremos. E relatou Moisés ao Senhor as palavras do povo.' },
      { v: 9, en: 'Yahweh said to Moses, “Behold, I come to you in a thick cloud, that the people may hear when I speak with you, and may also believe you forever.” Moses told the words of the people to Yahweh.', pt: 'Então disse o Senhor a Moisés: Eis que eu virei a ti em uma nuvem espessa, para que o povo ouça, quando eu falar contigo, e também para que sempre te creia. Porque Moisés tinha anunciado as palavras do seu povo ao Senhor.' },
      { v: 10, en: 'Yahweh said to Moses, “Go to the people, and sanctify them today and tomorrow, and let them wash their garments,', pt: 'Disse mais o Senhor a Moisés: Vai ao povo, e santifica-os hoje e amanhã; lavem eles os seus vestidos,' },
      { v: 11, en: 'and be ready against the third day; for on the third day Yahweh will come down in the sight of all the people on Mount Sinai.', pt: 'e estejam prontos para o terceiro dia; porquanto no terceiro dia descerá o Senhor diante dos olhos de todo o povo sobre o monte Sinai.' },
      { v: 12, en: 'You shall set bounds to the people all around, saying, ‘Be careful that you don’t go up onto the mountain, or touch its border. Whoever touches the mountain shall be surely put to death.', pt: 'Também marcarás limites ao povo em redor, dizendo: Guardai-vos, não subais ao monte, nem toqueis o seu termo; todo aquele que tocar o monte será morto.' },
      { v: 13, en: 'No hand shall touch him, but he shall surely be stoned or shot through; whether it is animal or man, he shall not live.’ When the trumpet sounds long, they shall come up to the mountain.”', pt: 'Mão alguma tocará naquele que o fizer, mas ele será apedrejado ou asseteado; quer seja animal, quer seja homem, não viverá. Quando soar a buzina longamente, subirão eles até o pé do monte.' },
      { v: 14, en: 'Moses went down from the mountain to the people, and sanctified the people; and they washed their clothes.', pt: 'Então Moisés desceu do monte ao povo, e santificou o povo; e lavaram os seus vestidos.' },
      { v: 15, en: 'He said to the people, “Be ready by the third day. Don’t have sexual relations with a woman.”', pt: 'E disse ele ao povo: Estai prontos para o terceiro dia; e não vos chegueis a mulher.' },
      { v: 16, en: 'On the third day, when it was morning, there were thunders and lightnings, and a thick cloud on the mountain, and the sound of an exceedingly loud trumpet; and all the people who were in the camp trembled.', pt: 'Ao terceiro dia, ao amanhecer, houve trovões, relâmpagos, e uma nuvem espessa sobre o monte; e ouviu-se um sonido de buzina mui forte, de maneira que todo o povo que estava no arraial estremeceu.' },
      { v: 17, en: 'Moses led the people out of the camp to meet God; and they stood at the lower part of the mountain.', pt: 'E Moisés levou o povo fora do arraial ao encontro de Deus; e puseram-se ao pé do monte.' },
      { v: 18, en: 'All of Mount Sinai smoked, because Yahweh descended on it in fire; and its smoke ascended like the smoke of a furnace, and the whole mountain quaked greatly.', pt: 'Nisso todo o monte Sinai fumegava, porque o Senhor descera sobre ele em fogo; e a fumaça subiu como a fumaça de uma fornalha, e todo o monte tremia fortemente.' },
      { v: 19, en: 'When the sound of the trumpet grew louder and louder, Moses spoke, and God answered him by a voice.', pt: 'E, crescendo o sonido da buzina cada vez mais, Moisés falava, e Deus lhe respondia por uma voz.' },
      { v: 20, en: 'Yahweh came down on Mount Sinai, to the top of the mountain. Yahweh called Moses to the top of the mountain, and Moses went up.', pt: 'E, tendo o Senhor descido sobre o monte Sinai, sobre o cume do monte, chamou a Moisés ao cume do monte; e Moisés subiu.' },
      { v: 21, en: 'Yahweh said to Moses, “Go down, warn the people, lest they break through to Yahweh to gaze, and many of them perish.', pt: 'Então disse o Senhor a Moisés: Desce, adverte ao povo, para não suceder que traspasse os limites até o Senhor, a fim de ver, e muitos deles pereçam.' },
      { v: 22, en: 'Let the priests also, who come near to Yahweh, sanctify themselves, lest Yahweh break out on them.”', pt: 'Ora, santifiquem-se também os sacerdotes, que se chegam ao Senhor, para que o Senhor não se lance sobre eles.' },
      { v: 23, en: 'Moses said to Yahweh, “The people can’t come up to Mount Sinai, for you warned us, saying, ‘Set bounds around the mountain, and sanctify it.’”', pt: 'Respondeu Moisés ao Senhor: O povo não poderá subir ao monte Sinai, porque tu nos tens advertido, dizendo: Marca limites ao redor do monte, e santifica-o.' },
      { v: 24, en: 'Yahweh said to him, “Go down! You shall bring Aaron up with you, but don’t let the priests and the people break through to come up to Yahweh, lest he break out against them.”', pt: 'Ao que lhe disse o Senhor: Vai, desce; depois subirás tu, e Arão contigo; os sacerdotes, porém, e o povo não traspassem os limites para subir ao Senhor, para que ele não se lance sobre eles.' },
      { v: 25, en: 'So Moses went down to the people, and told them.', pt: 'Então Moisés desceu ao povo, e disse-lhes isso.' },
    ],
    20: [
      { v: 1, en: 'God spoke all these words, saying,', pt: 'Então falou Deus todas estas palavras, dizendo:' },
      { v: 2, en: '“I am Yahweh your God, who brought you out of the land of Egypt, out of the house of bondage.', pt: 'Eu sou o Senhor teu Deus, que te tirei da terra do Egito, da casa da servidão.' },
      { v: 3, en: '“You shall have no other gods before me.', pt: 'Não terás outros deuses diante de mim.' },
      { v: 4, en: '“You shall not make for yourselves an idol, nor any image of anything that is in the heavens above, or that is in the earth beneath, or that is in the water under the earth:', pt: 'Não farás para ti imagem esculpida, nem figura alguma do que há em cima no céu, nem em baixo na terra, nem nas águas debaixo da terra.' },
      { v: 5, en: 'you shall not bow yourself down to them, nor serve them, for I, Yahweh your God, am a jealous God, visiting the iniquity of the fathers on the children, on the third and on the fourth generation of those who hate me,', pt: 'Não te encurvarás diante delas, nem as servirás; porque eu, o Senhor teu Deus, sou Deus zeloso, que visito a iniqüidade dos pais nos filhos até a terceira e quarta geração daqueles que me odeiam.' },
      { v: 6, en: 'and showing loving kindness to thousands of those who love me and keep my commandments.', pt: 'e uso de misericórdia com milhares dos que me amam e guardam os meus mandamentos.' },
      { v: 7, en: '“You shall not take the name of Yahweh your God in vain, for Yahweh will not hold him guiltless who takes his name in vain.', pt: 'Não tomarás o nome do Senhor teu Deus em vão; porque o Senhor não terá por inocente aquele que tomar o seu nome em vão.' },
      { v: 8, en: '“Remember the Sabbath day, to keep it holy.', pt: 'Lembra-te do dia do sábado, para o santificar.' },
      { v: 9, en: 'You shall labor six days, and do all your work,', pt: 'Seis dias trabalharás, e farás todo o teu trabalho;' },
      { v: 10, en: 'but the seventh day is a Sabbath to Yahweh your God. You shall not do any work in it, you, nor your son, nor your daughter, your male servant, nor your female servant, nor your livestock, nor your stranger who is within your gates;', pt: 'mas o sétimo dia é o sábado do Senhor teu Deus. Nesse dia não farás trabalho algum, nem tu, nem teu filho, nem tua filha, nem o teu servo, nem a tua serva, nem o teu animal, nem o estrangeiro que está dentro das tuas portas.' },
      { v: 11, en: 'for in six days Yahweh made heaven and earth, the sea, and all that is in them, and rested the seventh day; therefore Yahweh blessed the Sabbath day, and made it holy.', pt: 'Porque em seis dias fez o Senhor o céu e a terra, o mar e tudo o que neles há, e ao sétimo dia descansou; por isso o Senhor abençoou o dia do sábado, e o santificou.' },
      { v: 12, en: '“Honor your father and your mother, that your days may be long in the land which Yahweh your God gives you.', pt: 'Honra a teu pai e a tua mãe, para que se prolonguem os teus dias na terra que o Senhor teu Deus te dá.' },
      { v: 13, en: '“You shall not murder.', pt: 'Não matarás.' },
      { v: 14, en: '“You shall not commit adultery.', pt: 'Não adulterarás.' },
      { v: 15, en: '“You shall not steal.', pt: 'Não furtarás.' },
      { v: 16, en: '“You shall not give false testimony against your neighbor.', pt: 'Não dirás falso testemunho contra o teu proximo.' },
      { v: 17, en: '“You shall not covet your neighbor’s house. You shall not covet your neighbor’s wife, nor his male servant, nor his female servant, nor his ox, nor his donkey, nor anything that is your neighbor’s.”', pt: 'Não cobiçarás a casa do teu próximo, não cobiçarás a mulher do teu próximo, nem o seu servo, nem a sua serva, nem o seu boi, nem o seu jumento, nem coisa alguma do teu próximo.' },
      { v: 18, en: 'All the people perceived the thunderings, the lightnings, the sound of the trumpet, and the mountain smoking. When the people saw it, they trembled, and stayed at a distance.', pt: 'Ora, todo o povo presenciava os trovões, e os relâmpagos, e o sonido da buzina, e o monte a fumegar; e o povo, vendo isso, estremeceu e pôs-se de longe.' },
      { v: 19, en: 'They said to Moses, “Speak with us yourself, and we will listen; but don’t let God speak with us, lest we die.”', pt: 'E disseram a Moisés: Fala-nos tu mesmo, e ouviremos; mas não fale Deus conosco, para que não morramos.' },
      { v: 20, en: 'Moses said to the people, “Don’t be afraid, for God has come to test you, and that his fear may be before you, that you won’t sin.”', pt: 'Respondeu Moisés ao povo: Não temais, porque Deus veio para vos provar, e para que o seu temor esteja diante de vós, a fim de que não pequeis.' },
      { v: 21, en: 'The people stayed at a distance, and Moses came near to the thick darkness where God was.', pt: 'Assim o povo estava em pé de longe; Moisés, porém, se chegou às trevas espessas onde Deus estava.' },
      { v: 22, en: 'Yahweh said to Moses, “This is what you shall tell the children of Israel: ‘You yourselves have seen that I have talked with you from heaven.', pt: 'Então disse o Senhor a Moisés: Assim dirás aos filhos de Israel: Vós tendes visto que do céu eu vos falei.' },
      { v: 23, en: 'You shall most certainly not make gods of silver or gods of gold for yourselves to be alongside me.', pt: 'Não fareis outros deuses comigo; deuses de prata, ou deuses de ouro, não os fareis para vós.' },
      { v: 24, en: 'You shall make an altar of earth for me, and shall sacrifice on it your burnt offerings and your peace offerings, your sheep and your cattle. In every place where I record my name I will come to you and I will bless you.', pt: 'um altar de terra me farás, e sobre ele sacrificarás os teus holocaustos, e as tuas ofertas pacíficas, as tuas ovelhas e os teus bois. Em todo lugar em que eu fizer recordar o meu nome, virei a ti e te abençoarei.' },
      { v: 25, en: 'If you make me an altar of stone, you shall not build it of cut stones; for if you lift up your tool on it, you have polluted it.', pt: 'E se me fizeres um altar de pedras, não o construirás de pedras lavradas; pois se sobre ele levantares o teu buril, profaná-lo-ás.' },
      { v: 26, en: 'You shall not go up by steps to my altar, that your nakedness may not be exposed to it.’', pt: 'Também não subirás ao meu altar por degraus, para que não seja ali exposta a tua nudez.' },
    ],
    21: [
      { v: 1, en: '“Now these are the ordinances which you shall set before them.', pt: 'Estes são os estatutos que lhes proporás:' },
      { v: 2, en: '“If you buy a Hebrew servant, he shall serve six years and in the seventh he shall go out free without paying anything.', pt: 'Se comprares um servo hebreu, seis anos servirá; mas ao sétimo sairá forro, de graça.' },
      { v: 3, en: 'If he comes in by himself, he shall go out by himself. If he is married, then his wife shall go out with him.', pt: 'Se entrar sozinho, sozinho sairá; se tiver mulher, então com ele sairá sua mulher.' },
      { v: 4, en: 'If his master gives him a wife and she bears him sons or daughters, the wife and her children shall be her master’s, and he shall go out by himself.', pt: 'Se seu senhor lhe houver dado uma mulher e ela lhe houver dado filhos ou filhas, a mulher e os filhos dela serão de seu senhor e ele sairá sozinho.' },
      { v: 5, en: 'But if the servant shall plainly say, ‘I love my master, my wife, and my children. I will not go out free;’', pt: 'Mas se esse servo expressamente disser: Eu amo a meu senhor, a minha mulher e a meus filhos, não quero sair forro;' },
      { v: 6, en: 'then his master shall bring him to God, and shall bring him to the door or to the doorpost, and his master shall bore his ear through with an awl, and he shall serve him for ever.', pt: 'então seu senhor o levará perante os juízes, e o fará chegar à porta, ou ao umbral da porta, e o seu senhor lhe furará a orelha com uma sovela; e ele o servirá para sempre.' },
      { v: 7, en: '“If a man sells his daughter to be a female servant, she shall not go out as the male servants do.', pt: 'Se um homem vender sua filha para ser serva, ela não saira como saem os servos.' },
      { v: 8, en: 'If she doesn’t please her master, who has married her to himself, then he shall let her be redeemed. He shall have no right to sell her to a foreign people, since he has dealt deceitfully with her.', pt: 'Se ela não agradar ao seu senhor, de modo que não se despose com ela, então ele permitirá que seja resgatada; vendê-la a um povo estrangeiro, não o poderá fazer, visto ter usado de dolo para com ela.' },
      { v: 9, en: 'If he marries her to his son, he shall deal with her as a daughter.', pt: 'Mas se a desposar com seu filho, fará com ela conforme o direito de filhas.' },
      { v: 10, en: 'If he takes another wife to himself, he shall not diminish her food, her clothing, and her marital rights.', pt: 'Se lhe tomar outra, não diminuirá e o mantimento daquela, nem o seu vestido, nem o seu direito conjugal.' },
      { v: 11, en: 'If he doesn’t do these three things for her, she may go free without paying any money.', pt: 'E se não lhe cumprir estas três obrigações, ela sairá de graça, sem dar dinheiro.' },
      { v: 12, en: '“One who strikes a man so that he dies shall surely be put to death,', pt: 'Quem ferir a um homem, de modo que este morra, certamente será morto.' },
      { v: 13, en: 'but not if it is unintentional, but God allows it to happen: then I will appoint you a place where he shall flee.', pt: 'Se, porém, lhe não armar ciladas, mas Deus lho entregar nas mãos, então te designarei um lugar, para onde ele fugirá.' },
      { v: 14, en: 'If a man schemes and comes presumptuously on his neighbor to kill him, you shall take him from my altar, that he may die.', pt: 'No entanto, se alguém se levantar deliberadamente contra seu próximo para o matar à traição, tirá-lo-ás do meu altar, para que morra.' },
      { v: 15, en: '“Anyone who attacks his father or his mother shall be surely put to death.', pt: 'Quem ferir a seu pai, ou a sua mãe, certamente será morto.' },
      { v: 16, en: '“Anyone who kidnaps someone and sells him, or if he is found in his hand, he shall surely be put to death.', pt: 'Quem furtar algum homem, e o vender, ou mesmo se este for achado na sua mão, certamente será morto.' },
      { v: 17, en: '“Anyone who curses his father or his mother shall surely be put to death.', pt: 'Quem amaldiçoar a seu pai ou a sua mãe, certamente será morto.' },
      { v: 18, en: '“If men quarrel and one strikes the other with a stone, or with his fist, and he doesn’t die, but is confined to bed;', pt: 'Se dois homens brigarem e um ferir ao outro com pedra ou com o punho, e este não morrer, mas cair na cama,' },
      { v: 19, en: 'if he rises again and walks around with his staff, then he who struck him shall be cleared: only he shall pay for the loss of his time, and shall provide for his healing until he is thoroughly healed.', pt: 'se ele tornar a levantar-se e andar fora sobre o seu bordão, então aquele que o feriu será absolvido; somente lhe pagará o tempo perdido e fará que ele seja completamente curado.' },
      { v: 20, en: '“If a man strikes his servant or his maid with a rod, and he dies under his hand, he shall surely be punished.', pt: 'Se alguém ferir a seu servo ou a sua serva com pau, e este morrer debaixo da sua mão, certamente será castigado;' },
      { v: 21, en: 'Notwithstanding, if he gets up after a day or two, he shall not be punished, for he is his property.', pt: 'mas se sobreviver um ou dois dias, não será castigado; porque é dinheiro seu.' },
      { v: 22, en: '“If men fight and hurt a pregnant woman so that she gives birth prematurely, and yet no harm follows, he shall be surely fined as much as the woman’s husband demands and the judges allow.', pt: 'Se alguns homens brigarem, e um ferir uma mulher grávida, e for causa de que aborte, não resultando, porém, outro dano, este certamente será multado, conforme o que lhe impuser o marido da mulher, e pagará segundo o arbítrio dos juízes;' },
      { v: 23, en: 'But if any harm follows, then you must take life for life,', pt: 'mas se resultar dano, então darás vida por vida,' },
      { v: 24, en: 'eye for eye, tooth for tooth, hand for hand, foot for foot,', pt: 'olho por olho, dente por dente, mão por mão, pé por pé,' },
      { v: 25, en: 'burning for burning, wound for wound, and bruise for bruise.', pt: 'queimadura por queimadura, ferida por ferida, golpe por golpe.' },
      { v: 26, en: '“If a man strikes his servant’s eye, or his maid’s eye, and destroys it, he shall let him go free for his eye’s sake.', pt: 'Se alguém ferir o olho do seu servo ou o olho da sua serva e o cegar, deixá-lo-á ir forro por causa do olho.' },
      { v: 27, en: 'If he strikes out his male servant’s tooth, or his female servant’s tooth, he shall let him go free for his tooth’s sake.', pt: 'Da mesma sorte se tirar o dente do seu servo ou o dente da sua serva, deixá-lo-á ir forro por causa do dente.' },
      { v: 28, en: '“If a bull gores a man or a woman to death, the bull shall surely be stoned, and its meat shall not be eaten; but the owner of the bull shall not be held responsible.', pt: 'Se um boi escornear um homem ou uma mulher e este morrer, certamente será apedrejado o boi e a sua carne não se comerá; mas o dono do boi será absolvido.' },
      { v: 29, en: 'But if the bull had a habit of goring in the past, and it has been testified to its owner, and he has not kept it in, but it has killed a man or a woman, the bull shall be stoned, and its owner shall also be put to death.', pt: 'Mas se o boi dantes era escorneador, e o seu dono, tendo sido disso advertido, não o guardou, o boi, matando homem ou mulher, será apedrejado, e também o seu dono será morto.' },
      { v: 30, en: 'If a ransom is laid on him, then he shall give for the redemption of his life whatever is laid on him.', pt: 'Se lhe for imposto resgate, então dará como redenção da sua vida tudo quanto lhe for imposto;' },
      { v: 31, en: 'Whether it has gored a son or has gored a daughter, according to this judgment it shall be done to him.', pt: 'quer tenha o boi escorneado a um filho, quer a uma filha, segundo este julgamento lhe será feito.' },
      { v: 32, en: 'If the bull gores a male servant or a female servant, thirty shekels of silver shall be given to their master, and the ox shall be stoned.', pt: 'Se o boi escornear um servo, ou uma serva, dar-se-á trinta siclos de prata ao seu senhor, e o boi será apedrejado.' },
      { v: 33, en: '“If a man opens a pit, or if a man digs a pit and doesn’t cover it, and a bull or a donkey falls into it,', pt: 'Se alguém descobrir uma cova, ou se alguém cavar uma cova e não a cobrir, e nela cair um boi ou um jumento,' },
      { v: 34, en: 'the owner of the pit shall make it good. He shall give money to its owner, and the dead animal shall be his.', pt: 'o dono da cova dará indenização; pagá-la-á em dinheiro ao dono do animal morto, mas este será seu.' },
      { v: 35, en: '“If one man’s bull injures another’s, so that it dies, then they shall sell the live bull, and divide its price; and they shall also divide the dead animal.', pt: 'Se o boi de alguém ferir de morte o boi do seu próximo, então eles venderão o boi vivo e repartirão entre si o dinheiro da venda, e o morto também dividirão entre si.' },
      { v: 36, en: 'Or if it is known that the bull was in the habit of goring in the past, and its owner has not kept it in, he shall surely pay bull for bull, and the dead animal shall be his own.', pt: 'Ou se for notório que aquele boi dantes era escorneador, e seu dono não o guardou, certamente pagará boi por boi, porém o morto será seu.' },
    ],
    22: [
      { v: 1, en: '“If a man steals an ox or a sheep, and kills it, or sells it; he shall pay five oxen for an ox, and four sheep for a sheep.', pt: 'Se alguém furtar um boi (ou uma ovelha), e o matar ou vender, por um boi pagará cinco bois, e por uma ovelha quatro ovelhas.' },
      { v: 2, en: 'If the thief is found breaking in, and is struck so that he dies, there shall be no guilt of bloodshed for him.', pt: 'Se o ladrão for achado a minar uma casa, e for ferido de modo que morra, o que o feriu não será réu de sangue;' },
      { v: 3, en: 'If the sun has risen on him, guilt of bloodshed shall be for him; he shall make restitution. If he has nothing, then he shall be sold for his theft.', pt: 'mas se o sol houver saído sobre o ladrão, o que o feriu será réu de sangue. O ladrão certamente dará indenização; se nada possuir, será então vendido por seu furto.' },
      { v: 4, en: 'If the stolen property is found in his hand alive, whether it is ox, donkey, or sheep, he shall pay double.', pt: 'Se o furto for achado vivo na sua mão, seja boi, ou jumento, ou ovelha, pagará ele o dobro.' },
      { v: 5, en: '“If a man causes a field or vineyard to be eaten, and lets his animal loose, and it grazes in another man’s field, he shall make restitution from the best of his own field, and from the best of his own vineyard.', pt: 'Se alguém fizer pastar o seu animal num campo ou numa vinha, e se soltar o seu animal e este pastar no campo de outrem, do melhor do seu próprio campo e do melhor da sua própria vinha fará restituição.' },
      { v: 6, en: '“If fire breaks out, and catches in thorns so that the shocks of grain, or the standing grain, or the field are consumed; he who kindled the fire shall surely make restitution.', pt: 'Se alastrar um fogo e pegar nos espinhos, de modo que sejam destruídas as medas de trigo, ou a seara, ou o campo, aquele que acendeu o fogo certamente dará, indenização.' },
      { v: 7, en: '“If a man delivers to his neighbor money or stuff to keep, and it is stolen out of the man’s house; if the thief is found, he shall pay double.', pt: 'Se alguém entregar ao seu próximo dinheiro, ou objetos, para guardar, e isso for furtado da casa desse homem, o ladrão, se for achado, pagará o dobro.' },
      { v: 8, en: 'If the thief isn’t found, then the master of the house shall come near to God, to find out if he hasn’t put his hand to his neighbor’s goods.', pt: 'Se o ladrão não for achado, então o dono da casa irá à presença dos juizes para se verificar se não meteu a mão nos bens do seu próximo.' },
      { v: 9, en: 'For every matter of trespass, whether it is for ox, for donkey, for sheep, for clothing, or for any kind of lost thing, about which one says, ‘This is mine,’ the cause of both parties shall come before God. He whom God condemns shall pay double to his neighbor.', pt: 'Em todo caso de transgressão, seja a respeito de boi, ou de jumento, ou de ovelhas, ou de vestidos, ou de qualquer coisa perdida de que alguém disser que é sua, a causa de ambas as partes será levada perante os juízes; aquele a quem os juízes condenarem pagará o dobro ao seu próximo.' },
      { v: 10, en: '“If a man delivers to his neighbor a donkey, an ox, a sheep, or any animal to keep, and it dies or is injured, or driven away, no man seeing it;', pt: 'Se alguém entregar a seu próximo para guardar um jumento, ou boi, ou ovelha, ou outro qualquer animal, e este morrer, ou for aleijado, ou arrebatado, ninguém o vendo,' },
      { v: 11, en: 'the oath of Yahweh shall be between them both, whether he hasn’t put his hand to his neighbor’s goods; and its owner shall accept it, and he shall not make restitution.', pt: 'então haverá o juramento do Senhor entre ambos, para ver se o guardador não meteu a mão nos bens do seu próximo; e o dono aceitará o juramento, e o outro não fará restituição.' },
      { v: 12, en: 'But if it is stolen from him, he shall make restitution to its owner.', pt: 'Se, porém, o animal lhe tiver sido furtado, fará restituirão ao seu dono.' },
      { v: 13, en: 'If it is torn in pieces, let him bring it for evidence. He shall not make good that which was torn.', pt: 'Se tiver sido dilacerado, trá-lo-á em testemunho disso; não dará indenização pelo dilacerado.' },
      { v: 14, en: '“If a man borrows anything of his neighbor’s, and it is injured, or dies, its owner not being with it, he shall surely make restitution.', pt: 'Se alguém pedir emprestado a seu próximo algum animal, e este for danificado ou morrer, não estando presente o seu dono, certamente dará indenização;' },
      { v: 15, en: 'If its owner is with it, he shall not make it good. If it is a leased thing, it came for its lease.', pt: 'se o dono estiver presente, o outro não dará indenização; se tiver sido alugado, o aluguel responderá por qualquer dano.' },
      { v: 16, en: '“If a man entices a virgin who isn’t pledged to be married, and lies with her, he shall surely pay a dowry for her to be his wife.', pt: 'Se alguém seduzir uma virgem que não for desposada, e se deitar com ela, certamente pagará por ela o dote e a terá por mulher.' },
      { v: 17, en: 'If her father utterly refuses to give her to him, he shall pay money according to the dowry of virgins.', pt: 'Se o pai dela inteiramente recusar dar-lha, pagará ele em dinheiro o que for o dote das virgens.' },
      { v: 18, en: '“You shall not allow a sorceress to live.', pt: 'Não permitirás que viva uma feiticeira.' },
      { v: 19, en: '“Whoever has sex with an animal shall surely be put to death.', pt: 'Todo aquele que se deitar com animal, certamente será morto.' },
      { v: 20, en: '“He who sacrifices to any god, except to Yahweh only, shall be utterly destroyed.', pt: 'Quem sacrificar a qualquer deus, a não ser tão-somente ao Senhor, será morto.' },
      { v: 21, en: '“You shall not wrong an alien or oppress him, for you were aliens in the land of Egypt.', pt: 'Ao estrangeiro não maltratarás, nem o oprimirás; pois vós fostes estrangeiros na terra do Egito.' },
      { v: 22, en: '“You shall not take advantage of any widow or fatherless child.', pt: 'A nenhuma viúva nem órfão afligireis.' },
      { v: 23, en: 'If you take advantage of them at all, and they cry at all to me, I will surely hear their cry;', pt: 'Se de algum modo os afligirdes, e eles clamarem a mim, eu certamente ouvirei o seu clamor;' },
      { v: 24, en: 'and my wrath will grow hot, and I will kill you with the sword; and your wives shall be widows, and your children fatherless.', pt: 'e a minha ira se acenderá, e vos matarei à espada; vossas mulheres ficarão viúvas, e vossos filhos órfãos.' },
      { v: 25, en: '“If you lend money to any of my people with you who is poor, you shall not be to him as a creditor. You shall not charge him interest.', pt: 'Se emprestares dinheiro ao meu povo, ao pobre que está contigo, não te haverás com ele como credor; não lhe imporás juros.' },
      { v: 26, en: 'If you take your neighbor’s garment as collateral, you shall restore it to him before the sun goes down,', pt: 'Ainda que chegues a tomar em penhor o vestido do teu próximo, lho restituirás antes do pôr do sol;' },
      { v: 27, en: 'for that is his only covering, it is his garment for his skin. What would he sleep in? It will happen, when he cries to me, that I will hear, for I am gracious.', pt: 'porque é a única cobertura que tem; é o vestido da sua pele; em que se deitaria ele? Quando pois clamar a mim, eu o ouvirei, porque sou misericordioso.' },
      { v: 28, en: '“You shall not blaspheme God, nor curse a ruler of your people.', pt: 'Aos juízes não maldirás, nem amaldiçoarás ao governador do teu povo.' },
      { v: 29, en: '“You shall not delay to offer from your harvest and from the outflow of your presses. “You shall give the firstborn of your sons to me.', pt: 'Não tardarás em trazer ofertas da tua ceifa e dos teus lagares. O primogênito de teus filhos me darás.' },
      { v: 30, en: 'You shall do likewise with your cattle and with your sheep. Seven days it shall be with its mother, then on the eighth day you shall give it to me.', pt: 'Assim farás com os teus bois e com as tuas ovelhas; sete dias ficará a cria com a mãe; ao oitavo dia ma darás.' },
      { v: 31, en: '“You shall be holy men to me, therefore you shall not eat any meat that is torn by animals in the field. You shall cast it to the dogs.', pt: 'Ser-me-eis homens santos; portanto não comereis carne que por feras tenha sido despedaçada no campo; aos cães a lançareis.' },
    ],
    23: [
      { v: 1, en: '“You shall not spread a false report. Don’t join your hand with the wicked to be a malicious witness.', pt: 'Não levantarás falso boato, e não pactuarás com o ímpio, para seres testemunha injusta.' },
      { v: 2, en: '“You shall not follow a crowd to do evil. You shall not testify in court to side with a multitude to pervert justice.', pt: 'Nao seguirás a multidão para fazeres o mal; nem numa demanda darás testemunho, acompanhando a maioria, para perverteres a justiça;' },
      { v: 3, en: 'You shall not favor a poor man in his cause.', pt: 'nem mesmo ao pobre favorecerás na sua demanda.' },
      { v: 4, en: '“If you meet your enemy’s ox or his donkey going astray, you shall surely bring it back to him again.', pt: 'Se encontrares desgarrado o boi do teu inimigo, ou o seu jumento, sem falta lho reconduzirás.' },
      { v: 5, en: 'If you see the donkey of him who hates you fallen down under his burden, don’t leave him, you shall surely help him with it.', pt: 'Se vires deitado debaixo da sua carga o jumento daquele que te odeia, não passarás adiante; certamente o ajudarás a levantá-lo.' },
      { v: 6, en: '“You shall not deny justice to your poor people in their lawsuits.', pt: 'Não perverterás o direito do teu pobre na sua demanda.' },
      { v: 7, en: '“Keep far from a false charge, and don’t kill the innocent and righteous: for I will not justify the wicked.', pt: 'Guarda-te de acusares falsamente, e não matarás o inocente e justo; porque não justificarei o ímpio.' },
      { v: 8, en: '“You shall take no bribe, for a bribe blinds those who have sight and perverts the words of the righteous.', pt: 'Também não aceitarás peita, porque a peita cega os que têm vista, e perverte as palavras dos justos.' },
      { v: 9, en: '“You shall not oppress an alien, for you know the heart of an alien, since you were aliens in the land of Egypt.', pt: 'Outrossim, não oprimirás o estrangeiro; pois vós conheceis o coração do estrangeiro, porque fostes estrangeiros na terra do Egito.' },
      { v: 10, en: '“For six years you shall sow your land, and shall gather in its increase,', pt: 'Seis anos semearás tua terra, e recolherás os seus frutos;' },
      { v: 11, en: 'but the seventh year you shall let it rest and lie fallow, that the poor of your people may eat; and what they leave the animal of the field shall eat. In the same way, you shall deal with your vineyard and with your olive grove.', pt: 'mas no sétimo ano a deixarás descansar e ficar em pousio, para que os pobres do teu povo possam comer, e do que estes deixarem comam os animais do campo. Assim farás com a tua vinha e com o teu olival.' },
      { v: 12, en: '“Six days you shall do your work, and on the seventh day you shall rest, that your ox and your donkey may have rest, and the son of your servant, and the alien may be refreshed.', pt: 'Seis dias farás os teus trabalhos, mas ao sétimo dia descansarás; para que descanse o teu boi e o teu jumento, e para que tome alento o filho da tua escrava e o estrangeiro.' },
      { v: 13, en: '“Be careful to do all things that I have said to you; and don’t invoke the name of other gods or even let them be heard out of your mouth.', pt: 'Em tudo o que vos tenho dito, andai apercebidos. Do nome de outros deuses nem fareis menção; nunca se ouça da vossa boca o nome deles.' },
      { v: 14, en: '“You shall observe a feast to me three times a year.', pt: 'Três vezes no ano me celebrarás festa:' },
      { v: 15, en: 'You shall observe the feast of unleavened bread. Seven days you shall eat unleavened bread, as I commanded you, at the time appointed in the month Abib (for in it you came out of Egypt), and no one shall appear before me empty.', pt: 'A festa dos pães ázimos guardarás: sete dias comerás pães ázimos como te ordenei, ao tempo apontado no mês de abibe, porque nele saíste do Egito; e ninguém apareça perante mim de mãos vazias;' },
      { v: 16, en: 'And the feast of harvest, the first fruits of your labors, which you sow in the field; and the feast of ingathering, at the end of the year, when you gather in your labors out of the field.', pt: 'também guardarás a festa da sega, a das primícias do teu trabalho, que houveres semeado no campo; igualmente guardarás a festa da colheita à saída do ano, quando tiveres colhido do campo os frutos do teu trabalho.' },
      { v: 17, en: 'Three times in the year all your males shall appear before the Lord Yahweh.', pt: 'Três vezes no ano todos os teus homens aparecerão diante do Senhor Deus.' },
      { v: 18, en: '“You shall not offer the blood of my sacrifice with leavened bread. The fat of my feast shall not remain all night until the morning.', pt: 'Não oferecerás o sangue do meu sacrifício com pão levedado, nem ficará da noite para a manhã a gordura da minha festa.' },
      { v: 19, en: 'The first of the first fruits of your ground you shall bring into the house of Yahweh your God. “You shall not boil a young goat in its mother’s milk.', pt: 'As primícias dos primeiros frutos da tua terra trarás à casa do Senhor teu Deus. Não cozerás o cabrito no leite de sua mãe.' },
      { v: 20, en: '“Behold, I send an angel before you, to keep you by the way, and to bring you into the place which I have prepared.', pt: 'Eis que eu envio um anjo adiante de ti, para guardar-te pelo caminho, e conduzir-te ao lugar que te tenho preparado.' },
      { v: 21, en: 'Pay attention to him, and listen to his voice. Don’t provoke him, for he will not pardon your disobedience, for my name is in him.', pt: 'Anda apercebido diante dele, e ouve a sua voz; não sejas rebelde contra ele, porque não perdoará a tua rebeldia; pois nele está o meu nome.' },
      { v: 22, en: 'But if you indeed listen to his voice, and do all that I speak, then I will be an enemy to your enemies, and an adversary to your adversaries.', pt: 'Mas se, na verdade, ouvires a sua voz, e fizeres tudo o que eu disser, então serei inimigo dos teus inimigos, e adversário dos teus adversários.' },
      { v: 23, en: 'For my angel shall go before you, and bring you in to the Amorite, the Hittite, the Perizzite, the Canaanite, the Hivite, and the Jebusite; and I will cut them off.', pt: 'Porque o meu anjo irá adiante de ti, e te introduzirá na terra dos amorreus, dos heteus, dos perizeus, dos cananeus, dos heveus e dos jebuseus; e eu os aniquilarei.' },
      { v: 24, en: 'You shall not bow down to their gods, nor serve them, nor follow their practices, but you shall utterly overthrow them and demolish their pillars.', pt: 'Não te inclinarás diante dos seus deuses, nem os servirás, nem farás conforme as suas obras; Antes os derrubarás totalmente, e quebrarás de todo as suas colunas.' },
      { v: 25, en: 'You shall serve Yahweh your God, and he will bless your bread and your water, and I will take sickness away from among you.', pt: 'Servireis, pois, ao Senhor vosso Deus, e ele abençoará o vosso pão e a vossa água; e eu tirarei do meio de vós as enfermidades.' },
      { v: 26, en: 'No one will miscarry or be barren in your land. I will fulfill the number of your days.', pt: 'Na tua terra não haverá mulher que aborte, nem estéril; o número dos teus dias completarei.' },
      { v: 27, en: 'I will send my terror before you, and will confuse all the people to whom you come, and I will make all your enemies turn their backs to you.', pt: 'Enviarei o meu terror adiante de ti, pondo em confusão todo povo em cujas terras entrares, e farei que todos os teus inimigos te voltem as costas.' },
      { v: 28, en: 'I will send the hornet before you, which will drive out the Hivite, the Canaanite, and the Hittite, from before you.', pt: 'Também enviarei na tua frente vespas, que expulsarão de diante de ti os heveus, os cananeus e os heteus.' },
      { v: 29, en: 'I will not drive them out from before you in one year, lest the land become desolate, and the animals of the field multiply against you.', pt: 'Não os expulsarei num só ano, para que a terra não se torne em deserto, e as feras do campo não se multipliquem contra ti.' },
      { v: 30, en: 'Little by little I will drive them out from before you, until you have increased and inherit the land.', pt: 'Pouco a pouco os lançarei de diante de ti, até que te multipliques e possuas a terra por herança.' },
      { v: 31, en: 'I will set your border from the Red Sea even to the sea of the Philistines, and from the wilderness to the River; for I will deliver the inhabitants of the land into your hand, and you shall drive them out before you.', pt: 'E fixarei os teus limites desde o Mar Vermelho até o mar dos filisteus, e desde o deserto até o o rio; porque hei de entregar nas tuas mãos os moradores da terra, e tu os expulsarás de diante de ti.' },
      { v: 32, en: 'You shall make no covenant with them, nor with their gods.', pt: 'Não farás pacto algum com eles, nem com os seus deuses.' },
      { v: 33, en: 'They shall not dwell in your land, lest they make you sin against me, for if you serve their gods, it will surely be a snare to you.”', pt: 'Não habitarão na tua terra, para que não te façam pecar contra mim; pois se servires os seus deuses, certamente isso te será um laço.' },
    ],
    24: [
      { v: 1, en: 'He said to Moses, “Come up to Yahweh, you, and Aaron, Nadab, and Abihu, and seventy of the elders of Israel; and worship from a distance.', pt: 'Depois disse Deus a Moisés: Subi ao Senhor, tu e Arão, Nadabe e Abiú, e setenta dos anciãos de Israel, e adorai de longe.' },
      { v: 2, en: 'Moses alone shall come near to Yahweh, but they shall not come near. The people shall not go up with him.”', pt: 'Só Moisés se chegará ao Senhor; os, outros não se chegarão; nem o povo subirá com ele.' },
      { v: 3, en: 'Moses came and told the people all Yahweh’s words, and all the ordinances; and all the people answered with one voice, and said, “All the words which Yahweh has spoken will we do.”', pt: 'Veio, pois, Moisés e relatou ao povo todas as palavras do Senhor e todos os estatutos; então todo o povo respondeu a uma voz: Tudo o que o Senhor tem falado faremos.' },
      { v: 4, en: 'Moses wrote all Yahweh’s words, and rose up early in the morning, and built an altar under the mountain, and twelve pillars for the twelve tribes of Israel.', pt: 'Então Moisés escreveu todas as palavras do Senhor e, tendo-se levantado de manhã cedo, edificou um altar ao pé do monte, e doze colunas, segundo as doze tribos de Israel,' },
      { v: 5, en: 'He sent young men of the children of Israel, who offered burnt offerings and sacrificed peace offerings of cattle to Yahweh.', pt: 'e enviou certos mancebos dos filhos de Israel, os quais ofereceram holocaustos, e sacrificaram ao Senhor sacrifícios pacíficos, de bois.' },
      { v: 6, en: 'Moses took half of the blood and put it in basins, and half of the blood he sprinkled on the altar.', pt: 'E Moisés tomou a metade do sangue, e a pôs em bacias; e a outra metade do sangue espargiu sobre o altar.' },
      { v: 7, en: 'He took the book of the covenant and read it in the hearing of the people, and they said, “All that Yahweh has spoken will we do, and be obedient.”', pt: 'Também tomou o livro do pacto e o leu perante o povo; e o povo disse: Tudo o que o Senhor tem falado faremos, e obedeceremos.' },
      { v: 8, en: 'Moses took the blood, and sprinkled it on the people, and said, “Look, this is the blood of the covenant, which Yahweh has made with you concerning all these words.”', pt: 'Então tomou Moisés aquele sangue, e espargiu-o sobre o povo e disse: Eis aqui o sangue do pacto que o Senhor tem feito convosco no tocante a todas estas coisas.' },
      { v: 9, en: 'Then Moses, Aaron, Nadab, Abihu, and seventy of the elders of Israel went up.', pt: 'Então subiram Moisés e Arão, Nadabe e Abiú, e setenta dos anciãos de Israel,' },
      { v: 10, en: 'They saw the God of Israel. Under his feet was like a paved work of sapphire stone, like the skies for clearness.', pt: 'e viram o Deus de Israel, e debaixo de seus pés havia como que uma calçada de pedra de safira, que parecia com o próprio céu na sua pureza.' },
      { v: 11, en: 'He didn’t lay his hand on the nobles of the children of Israel. They saw God, and ate and drank.', pt: 'Deus, porém, não estendeu a sua mão contra os nobres dos filhos de Israel; eles viram a Deus, e comeram e beberam.' },
      { v: 12, en: 'Yahweh said to Moses, “Come up to me on the mountain, and stay here, and I will give you the stone tablets with the law and the commands that I have written, that you may teach them.”', pt: 'Depois disse o Senhor a Moisés: Sobe a mim ao monte, e espera ali; e dar-te-ei tábuas de pedra, e a lei, e os mandamentos que tenho escrito, para lhos ensinares.' },
      { v: 13, en: 'Moses rose up with Joshua, his servant, and Moses went up onto God’s Mountain.', pt: 'E levantando-se Moisés com Josué, seu servidor, subiu ao monte de Deus,' },
      { v: 14, en: 'He said to the elders, “Wait here for us, until we come again to you. Behold, Aaron and Hur are with you. Whoever is involved in a dispute can go to them.”', pt: 'tendo dito aos anciãos: Esperai-nos aqui, até que tornemos a vós; eis que Arão e Hur ficam convosco; quem tiver alguma questão, se chegará a eles.' },
      { v: 15, en: 'Moses went up on the mountain, and the cloud covered the mountain.', pt: 'E tendo Moisés subido ao monte, a nuvem cobriu o monte.' },
      { v: 16, en: 'Yahweh’s glory settled on Mount Sinai, and the cloud covered it six days. The seventh day he called to Moses out of the middle of the cloud.', pt: 'Também a glória do Senhor repousou sobre o monte Sinai, e a nuvem o cobriu por seis dias; e ao sétimo dia, do meio da nuvem, Deus chamou a Moisés.' },
      { v: 17, en: 'The appearance of Yahweh’s glory was like devouring fire on the top of the mountain in the eyes of the children of Israel.', pt: 'Ora, a aparência da glória do Senhor era como um fogo consumidor no cume do monte, aos olhos dos filhos de Israel.' },
      { v: 18, en: 'Moses entered into the middle of the cloud, and went up on the mountain; and Moses was on the mountain forty days and forty nights.', pt: 'Moisés, porém, entrou no meio da nuvem, depois que subiu ao monte; e Moisés esteve no monte quarenta dias e quarenta noites.' },
    ],
    25: [
      { v: 1, en: 'Yahweh spoke to Moses, saying,', pt: 'Então disse o Senhor a Moisés:' },
      { v: 2, en: '“Speak to the children of Israel, that they take an offering for me. From everyone whose heart makes him willing you shall take my offering.', pt: 'Fala aos filhos de Israel que me tragam uma oferta alçada; de todo homem cujo coração se mover voluntariamente, dele tomareis a minha oferta alçada.' },
      { v: 3, en: 'This is the offering which you shall take from them: gold, silver, brass,', pt: 'E esta é a oferta alçada que tomareis deles: ouro, prata, bronze,' },
      { v: 4, en: 'blue, purple, scarlet, fine linen, goats’ hair,', pt: 'estofo azul, púrpura, carmesim, linho fino, pêlos de cabras,' },
      { v: 5, en: 'rams’ skins dyed red, sea cow hides, acacia wood,', pt: 'peles de carneiros tintas de vermelho, peles de golfinhos, madeira de acácia,' },
      { v: 6, en: 'oil for the light, spices for the anointing oil and for the sweet incense,', pt: 'azeite para a luz, especiarias para o óleo da unção e para o incenso aromàtico,' },
      { v: 7, en: 'onyx stones, and stones to be set for the ephod and for the breastplate.', pt: 'pedras de ônix, e pedras de engaste para o éfode e para o peitoral.' },
      { v: 8, en: 'Let them make me a sanctuary, that I may dwell among them.', pt: 'E me farão um santuário, para que eu habite no meio deles.' },
      { v: 9, en: 'According to all that I show you, the pattern of the tabernacle, and the pattern of all of its furniture, even so you shall make it.', pt: 'Conforme a tudo o que eu te mostrar para modelo do tabernáculo, e para modelo de todos os seus móveis, assim mesmo o fareis.' },
      { v: 10, en: '“They shall make an ark of acacia wood. Its length shall be two and a half cubits, its width a cubit and a half, and a cubit and a half its height.', pt: 'Também farão uma arca de madeira ,de acácia; o seu comprimento será de dois côvados e meio, e a sua largura de um côvado e meio, e de um côvado e meio a sua altura.' },
      { v: 11, en: 'You shall overlay it with pure gold. You shall overlay it inside and outside, and you shall make a gold molding around it.', pt: 'E cobri-la-ás de ouro puro, por dentro e por fora a cobrirás; e farás sobre ela uma moldura de ouro ao redor;' },
      { v: 12, en: 'You shall cast four rings of gold for it, and put them in its four feet. Two rings shall be on the one side of it, and two rings on the other side of it.', pt: 'e fundirás para ela quatro argolas de ouro, que porás nos quatro cantos dela; duas argolas de um lado e duas do outro.' },
      { v: 13, en: 'You shall make poles of acacia wood, and overlay them with gold.', pt: 'Também farás varais de madeira de acácia, que cobrirás de ouro.' },
      { v: 14, en: 'You shall put the poles into the rings on the sides of the ark to carry the ark.', pt: 'Meterás os varais nas argolas, aos lados da arca, para se levar por eles a arca.' },
      { v: 15, en: 'The poles shall be in the rings of the ark. They shall not be taken from it.', pt: 'Os varais permanecerão nas argolas da arca; não serão tirados dela.' },
      { v: 16, en: 'You shall put the testimony which I shall give you into the ark.', pt: 'E porás na arca o testemunho, que eu te darei.' },
      { v: 17, en: 'You shall make a mercy seat of pure gold. Two and a half cubits shall be its length, and a cubit and a half its width.', pt: 'Igualmente farás um propiciatório, de ouro puro; o seu comprimento será de dois covados e meio, e a sua largura de um côvado e meio.' },
      { v: 18, en: 'You shall make two cherubim of hammered gold. You shall make them at the two ends of the mercy seat.', pt: 'Farás também dois querubins de ouro; de ouro batido os farás, nas duas extremidades do propiciatório.' },
      { v: 19, en: 'Make one cherub at the one end, and one cherub at the other end. You shall make the cherubim on its two ends of one piece with the mercy seat.', pt: 'Farás um querubim numa extremidade e o outro querubim na outra extremidade; de uma só peça com o propiciatório fareis os querubins nas duas extremidades dele.' },
      { v: 20, en: 'The cherubim shall spread out their wings upward, covering the mercy seat with their wings, with their faces toward one another. The faces of the cherubim shall be toward the mercy seat.', pt: 'Os querubins estenderão as suas asas por cima do propiciatório, cobrindo-o com as asas, tendo as faces voltadas um para o outro; as faces dos querubins estarão voltadas para o propiciatório.' },
      { v: 21, en: 'You shall put the mercy seat on top of the ark, and in the ark you shall put the testimony that I will give you.', pt: 'E porás o propiciatório em cima da arca; e dentro da arca porás o testemunho que eu te darei.' },
      { v: 22, en: 'There I will meet with you, and I will tell you from above the mercy seat, from between the two cherubim which are on the ark of the testimony, all that I command you for the children of Israel.', pt: 'E ali virei a ti, e de cima do propiciatório, do meio dos dois querubins que estão sobre a arca do testemunho, falarei contigo a respeito de tudo o que eu te ordenar no tocante aos filhos de Israel.' },
      { v: 23, en: '“You shall make a table of acacia wood. Two cubits shall be its length, and a cubit its width, and one and a half cubits its height.', pt: 'Também farás uma mesa de madeira de acácia; o seu comprimento será de dois côvados, a sua largura de um côvado e a sua altura de um côvado e meio;' },
      { v: 24, en: 'You shall overlay it with pure gold, and make a gold molding around it.', pt: 'cobri-la-ás de ouro puro, e lhe farás uma moldura de ouro ao redor.' },
      { v: 25, en: 'You shall make a rim of a hand width around it. You shall make a golden molding on its rim around it.', pt: 'Também lhe farás ao redor uma guarnição de quatro dedos de largura, e ao redor na guarnição farás uma moldura de ouro.' },
      { v: 26, en: 'You shall make four rings of gold for it, and put the rings in the four corners that are on its four feet.', pt: 'Também lhe farás quatro argolas de ouro, e porás as argolas nos quatro cantos, que estarão sobre os quatro pés.' },
      { v: 27, en: 'the rings shall be close to the rim, for places for the poles to carry the table.', pt: 'Junto da guarnição estarão as argolas, como lugares para os varais, para se levar a mesa.' },
      { v: 28, en: 'You shall make the poles of acacia wood, and overlay them with gold, that the table may be carried with them.', pt: 'Farás, pois, estes varais de madeira de acácia, e os cobrirás de ouro; e levar-se-á por eles a mesa.' },
      { v: 29, en: 'You shall make its dishes, its spoons, its ladles, and its bowls to pour out offerings with. You shall make them of pure gold.', pt: 'Também farás os seus pratos, as suas colheres, os seus cântaros e as suas tigelas com que serão oferecidas as libações; de ouro puro os farás.' },
      { v: 30, en: 'You shall set bread of the presence on the table before me always.', pt: 'E sobre a mesa porás os pães da o proposição perante mim para sempre.' },
      { v: 31, en: '“You shall make a lamp stand of pure gold. Of hammered work shall the lamp stand be made, even its base, its shaft, its cups, its buds, and its flowers, shall be of one piece with it.', pt: 'Também farás um candelabro de ouro puro; de ouro batido se fará o candelabro, tanto o seu pedestal como a sua haste; os seus copos, os seus cálices e as suas corolas formarão com ele uma só peça.' },
      { v: 32, en: 'There shall be six branches going out of its sides: three branches of the lamp stand out of its one side, and three branches of the lamp stand out of its other side;', pt: 'E de seus lados sairão seis braços: três de um lado, e três do outro.' },
      { v: 33, en: 'three cups made like almond blossoms in one branch, a bud and a flower; and three cups made like almond blossoms in the other branch, a bud and a flower, so for the six branches going out of the lamp stand;', pt: 'Em um braço haverá três copos a modo de flores de amêndoa, com cálice e corola; também no outro braço três copos a modo de flores de amêndoa, com cálice e corola; assim se farão os seis braços que saem do candelabro.' },
      { v: 34, en: 'and in the lamp stand four cups made like almond blossoms, its buds and its flowers;', pt: 'Mas na haste central haverá quatro copos a modo de flores de amêndoa, com os seus cálices e as suas corolas,' },
      { v: 35, en: 'and a bud under two branches of one piece with it, and a bud under two branches of one piece with it, and a bud under two branches of one piece with it, for the six branches going out of the lamp stand.', pt: 'e um cálice debaixo de dois braços, formando com a haste uma só peça; outro cálice debaixo de dois outros braços, de uma só peça com a haste; e ainda outro cálice debaixo de dois outros braços, de uma só peça com a haste; assim será para os seis braços que saem do candelabro.' },
      { v: 36, en: 'Their buds and their branches shall be of one piece with it, all of it one beaten work of pure gold.', pt: 'Os seus cálices e os seus braços formarão uma só peça com a haste; o todo será de obra batida de ouro puro.' },
      { v: 37, en: 'You shall make its lamps seven, and they shall light its lamps to give light to the space in front of it.', pt: 'Também lhe farás sete lâmpadas, as quais se acenderão para alumiar defronte dele.' },
      { v: 38, en: 'Its snuffers and its snuff dishes shall be of pure gold.', pt: 'Os seus espevitadores e os seus cinzeiros serão de ouro puro.' },
      { v: 39, en: 'It shall be made of a talent of pure gold, with all these accessories.', pt: 'De um talento de ouro puro se fará o candelabro, com todos estes utensílios.' },
      { v: 40, en: 'See that you make them after their pattern, which has been shown to you on the mountain.', pt: 'Atenta, pois, que os faças conforme o seu modelo, que te foi mostrado no monte.' },
    ],
    26: [
      { v: 1, en: '“Moreover you shall make the tabernacle with ten curtains; of fine twined linen, and blue, and purple, and scarlet, with cherubim. The work of the skillful workman you shall make them.', pt: 'O tabernáculo farás de dez cortinas de linho fino torcido, e de estofo azul, púrpura, e carmesim; com querubins as farás, obra de artífice.' },
      { v: 2, en: 'The length of each curtain shall be twenty-eight cubits, and the width of each curtain four cubits: all the curtains shall have one measure.', pt: 'O comprimento de cada cortina será de vinte e oito côvados, e a largura de quatro côvados; todas as cortinas serão da mesma medida.' },
      { v: 3, en: 'Five curtains shall be coupled together to one another; and the other five curtains shall be coupled to one another.', pt: 'Cinco cortinas serão enlaçadas, cada uma à outra; e as outras cinco serão enlaçadas da mesma maneira.' },
      { v: 4, en: 'You shall make loops of blue on the edge of the one curtain from the edge in the coupling; and likewise you shall make in the edge of the curtain that is outermost in the second coupling.', pt: 'Farás laçadas de estofo azul na orla da última cortina do primeiro grupo; assim também farás na orla da primeira cortina do segundo grupo;' },
      { v: 5, en: 'You shall make fifty loops in the one curtain, and you shall make fifty loops in the edge of the curtain that is in the second coupling. The loops shall be opposite one another.', pt: 'a saber, cinqüenta laçadas na orla de uma cortina, e cinqüenta laçadas na orla da outra; as laçadas serão contrapostas uma à outra.' },
      { v: 6, en: 'You shall make fifty clasps of gold, and couple the curtains to one another with the clasps: and the tabernacle shall be a unit.', pt: 'Farás cinqüenta colchetes de ouro, e prenderás com eles as cortinas, uma à outra; assim o tabernáculo virá a ser um todo.' },
      { v: 7, en: '“You shall make curtains of goats’ hair for a covering over the tabernacle. You shall make them eleven curtains.', pt: 'Farás também cortinas de pêlos de cabras para servirem de tenda sobre o tabernáculo; onze destas cortinas farás.' },
      { v: 8, en: 'The length of each curtain shall be thirty cubits, and the width of each curtain four cubits: the eleven curtains shall have one measure.', pt: 'O comprimento de cada cortina será de trinta côvados, e a largura de cada cortina de quatro côvados; as onze cortinas serão da mesma medida.' },
      { v: 9, en: 'You shall couple five curtains by themselves, and six curtains by themselves, and shall double over the sixth curtain in the forefront of the tent.', pt: 'E ajuntarás cinco cortinas em um grupo, e as outras seis cortinas em outro grupo; e dobrarás a sexta cortina na frente da tenda.' },
      { v: 10, en: 'You shall make fifty loops on the edge of the one curtain that is outermost in the coupling, and fifty loops on the edge of the curtain which is outermost in the second coupling.', pt: 'E farás cinqüenta laçadas na orla da última cortina do primeiro grupo, e outras cinqüenta laçadas na orla da primeira cortina do segundo grupo.' },
      { v: 11, en: 'You shall make fifty clasps of brass, and put the clasps into the loops, and couple the tent together, that it may be one.', pt: 'Farás também cinqüenta colchetes de bronze, e meterás os colchetes nas laçadas, e assim ajuntarás a tenda, para que venha a ser um todo.' },
      { v: 12, en: 'The overhanging part that remains of the curtains of the tent, the half curtain that remains, shall hang over the back of the tabernacle.', pt: 'E o resto que sobejar das cortinas da tenda, a saber, a meia cortina que sobejar, penderá aos fundos do tabernáculo.' },
      { v: 13, en: 'The cubit on the one side, and the cubit on the other side, of that which remains in the length of the curtains of the tent, shall hang over the sides of the tabernacle on this side and on that side, to cover it.', pt: 'E o côvado que sobejar de um lado e de outro no comprimento das cortinas da tenda, penderá de um e de outro lado do tabernáculo, para cobri-lo.' },
      { v: 14, en: 'You shall make a covering for the tent of rams’ skins dyed red, and a covering of sea cow hides above.', pt: 'Farás também para a tenda uma coberta de peles de carneiros, tintas de vermelho, e por cima desta uma coberta de peles de golfinhos.' },
      { v: 15, en: '“You shall make the boards for the tabernacle of acacia wood, standing up.', pt: 'Farás também as tábuas para o tabernáculo de madeira de acácia, as quais serão colocadas verticalmente.' },
      { v: 16, en: 'Ten cubits shall be the length of a board, and one and a half cubits the width of each board.', pt: 'O comprimento de cada tábua será de dez côvados, e a sua largura de um côvado e meio.' },
      { v: 17, en: 'There shall be two tenons in each board, joined to one another: thus you shall make for all the boards of the tabernacle.', pt: 'Duas couceiras terá cada tábua, unidas uma à outra por travessas; assim farás com todas as tábuas do tabernáculo.' },
      { v: 18, en: 'You shall make the boards for the tabernacle, twenty boards for the south side southward.', pt: 'Ao fazeres as tábuas para o tabernáculo, farás vinte delas para o lado meridional.' },
      { v: 19, en: 'You shall make forty sockets of silver under the twenty boards; two sockets under one board for its two tenons, and two sockets under another board for its two tenons.', pt: 'Farás também quarenta bases de prata debaixo das vinte tábuas; duas bases debaixo de uma tábua, para as suas duas couceiras, e duas bases debaixo de outra, para as duas couceiras dela.' },
      { v: 20, en: 'For the second side of the tabernacle, on the north side, twenty boards,', pt: 'Também para o outro lado do tabernáculo, o que dá para o norte, farás vinte tábuas,' },
      { v: 21, en: 'and their forty sockets of silver; two sockets under one board, and two sockets under another board.', pt: 'com as suas quarenta bases de prata; duas bases debaixo de uma tábua e duas debaixo de outra.' },
      { v: 22, en: 'For the far part of the tabernacle westward you shall make six boards.', pt: 'E para o lado posterior do tabernáculo, o que dá para o ocidente, farás seis tábuas.' },
      { v: 23, en: 'You shall make two boards for the corners of the tabernacle in the far part.', pt: 'Farás também duas tábuas para os cantos do tabernáculo no lado posterior.' },
      { v: 24, en: 'They shall be double beneath, and in the same way they shall be whole to its top to one ring: thus shall it be for them both; they shall be for the two corners.', pt: 'Por baixo serão duplas, do mesmo modo se estendendo inteiras até a primeira argola em cima; assim se fará com as duas tábuas; elas serão para os dois cantos.' },
      { v: 25, en: 'There shall be eight boards, and their sockets of silver, sixteen sockets; two sockets under one board, and two sockets under another board.', pt: 'Haverá oito tábuas com as suas dezesseis bases de prata: duas bases debaixo de uma tábua e duas debaixo de outra.' },
      { v: 26, en: '“You shall make bars of acacia wood: five for the boards of the one side of the tabernacle,', pt: 'Farás também travessões de madeira de acácia; cinco para as tábuas de um lado do tabernáculo,' },
      { v: 27, en: 'and five bars for the boards of the other side of the tabernacle, and five bars for the boards of the side of the tabernacle, for the far part westward.', pt: 'e cinco para as tábuas do outro lado do tabernáculo, bem como c6 azeite para a luz, especiarias para o óleo da unção e para o para o ocidente.' },
      { v: 28, en: 'The middle bar in the middle of the boards shall pass through from end to end.', pt: 'O travessão central passará ao meio das tábuas, de uma extremidade à outra.' },
      { v: 29, en: 'You shall overlay the boards with gold, and make their rings of gold for places for the bars: and you shall overlay the bars with gold.', pt: 'E cobrirás de ouro as tábuas, e de ouro farás as suas argolas, como lugares para os travessões; também os travessões cobrirás de ouro.' },
      { v: 30, en: 'You shall set up the tabernacle according to the way that it was shown to you on the mountain.', pt: 'Então levantarás o tabernáculo conforme o modelo que te foi mostrado no monte.' },
      { v: 31, en: '“You shall make a veil of blue, and purple, and scarlet, and fine twined linen, with cherubim. The work of the skillful workman shall it be made.', pt: 'Farás também um véu de azul, púrpura, carmesim, e linho fino torcido; com querubins, obra de artífice, se fará;' },
      { v: 32, en: 'You shall hang it on four pillars of acacia overlaid with gold; their hooks shall be of gold, on four sockets of silver.', pt: 'e o suspenderás sobre quatro colunas de madeira de acácia, cobertas de ouro; seus colchetes serão de ouro, sobre quatro bases de prata.' },
      { v: 33, en: 'You shall hang up the veil under the clasps, and shall bring the ark of the testimony in there within the veil: and the veil shall separate the holy place from the most holy for you.', pt: 'Pendurarás o véu debaixo dos colchetes, e levarás para dentro do véu a arca do testemunho; este véu vos fará separação entre o lugar santo e o santo dos santos.' },
      { v: 34, en: 'You shall put the mercy seat on the ark of the testimony in the most holy place.', pt: 'Porás o propiciatório sobre a arca do testemunho no santo dos santos;' },
      { v: 35, en: 'You shall set the table outside the veil, and the lamp stand over against the table on the side of the tabernacle toward the south: and you shall put the table on the north side.', pt: 'colocarás a mesa fora do véu, e o candelabro defronte da mesa, para o lado sul do tabernáculo; e porás a mesa para o lado norte.' },
      { v: 36, en: '“You shall make a screen for the door of the Tent, of blue, and purple, and scarlet, and fine twined linen, the work of the embroiderer.', pt: 'Farás também para a porta da tenda um reposteiro de azul, púrpura, carmesim: e linho fino torcido, obra de bordador.' },
      { v: 37, en: 'You shall make for the screen five pillars of acacia, and overlay them with gold: their hooks shall be of gold: and you shall cast five sockets of brass for them.', pt: 'E para o reposteiro farás cinco colunas de madeira de acácia, cobrindo-as de ouro (os seus colchetes também serão de ouro), e para elas fundirás cinco bases de bronze.' },
    ],
    27: [
      { v: 1, en: '“You shall make the altar of acacia wood, five cubits long, and five cubits wide; the altar shall be square: and its height shall be three cubits.', pt: 'Farás também o altar de madeira de acácia; de cinco côvados será o comprimento, de cinco côvados a largura (será quadrado o altar), e de três côvados a altura.' },
      { v: 2, en: 'You shall make its horns on its four corners; its horns shall be of one piece with it; and you shall overlay it with brass.', pt: 'E farás as suas pontas nos seus quatro cantos; as suas pontas formarão uma só peça com o altar; e o cobrirás de bronze.' },
      { v: 3, en: 'You shall make its pots to take away its ashes, its shovels, its basins, its meat hooks, and its fire pans: all its vessels you shall make of brass.', pt: 'Far-lhe-ás também os cinzeiros, para recolher a sua cinza, e as pás, e as bacias, e os garfos e os braseiros; todos os seus utensílios farás de bronze.' },
      { v: 4, en: 'You shall make a grating for it of network of brass: and on the net you shall make four bronze rings in its four corners.', pt: 'Far-lhe-ás também um crivo de bronze em forma de rede, e farás para esta rede quatro argolas de bronze nos seus quatro cantos,' },
      { v: 5, en: 'You shall put it under the ledge around the altar beneath, that the net may reach halfway up the altar.', pt: 'e a porás em baixo da borda em volta do altar, de maneira que a rede chegue até o meio do altar.' },
      { v: 6, en: 'You shall make poles for the altar, poles of acacia wood, and overlay them with brass.', pt: 'Farás também varais para o altar, varais de madeira de acácia, e os cobrirás de bronze.' },
      { v: 7, en: 'Its poles shall be put into the rings, and the poles shall be on the two sides of the altar, when carrying it.', pt: 'Os varais serão metidos nas argolas, e estarão de um e de outro lado do altar, quando for levado.' },
      { v: 8, en: 'You shall make it with hollow planks. They shall make it as it has been shown you on the mountain.', pt: 'èco, de tábuas, o farás; como se te mostrou no monte, assim o farão.' },
      { v: 9, en: '“You shall make the court of the tabernacle: for the south side southward there shall be hangings for the court of fine twined linen one hundred cubits long for one side:', pt: 'Farás também o átrio do tabernáculo. No lado que dá para o sul o átrio terá cortinas de linho fino torcido, de cem côvados de comprimento.' },
      { v: 10, en: 'and its pillars shall be twenty, and their sockets twenty, of brass; the hooks of the pillars and their fillets shall be of silver.', pt: 'As suas colunas serão vinte, e vinte as suas bases, todas de bronze; os colchetes das colunas e as suas faixas serão de prata.' },
      { v: 11, en: 'Likewise for the north side in length there shall be hangings one hundred cubits long, and its pillars twenty, and their sockets twenty, of brass; the hooks of the pillars, and their fillets, of silver.', pt: 'Assim também ao longo do lado do norte haverá cortinas de cem côvados de comprimento, e serão vinte as suas colunas e vinte as bases destas, todas de bronze; os colchetes das colunas e as suas faixas serão de prata.' },
      { v: 12, en: 'For the width of the court on the west side shall be hangings of fifty cubits; their pillars ten, and their sockets ten.', pt: 'E na largura do átrio do lado do ocidente haverá cortinas de cinqüenta côvados; serão dez as suas colunas, e dez as bases destas.' },
      { v: 13, en: 'The width of the court on the east side eastward shall be fifty cubits.', pt: 'Semelhantemente a largura do átrio do lado que dá para o nascente será de cinqüenta côvados.' },
      { v: 14, en: 'The hangings for the one side of the gate shall be fifteen cubits; their pillars three, and their sockets three.', pt: 'As cortinas para um lado da porta serão de quinze côvados; três serão as suas colunas, e três as bases destas.' },
      { v: 15, en: 'For the other side shall be hangings of fifteen cubits; their pillars three, and their sockets three.', pt: 'E de quinze côvados serão as cortinas para o outro lado; as suas colunas serão três, e três as bases destas.' },
      { v: 16, en: 'For the gate of the court shall be a screen of twenty cubits, of blue, and purple, and scarlet, and fine twined linen, the work of the embroiderer; their pillars four, and their sockets four.', pt: 'Também à porta do átrio haverá um reposteiro de vinte côvados, de azul, púrpura, carmesim, e linho fino torcido, obra de bordador; as suas colunas serão quatro, e quatro as bases destas.' },
      { v: 17, en: 'All the pillars of the court around shall be filleted with silver; their hooks of silver, and their sockets of brass.', pt: 'Todas as colunas do átrio ao redor serão cingidas de faixas de prata; os seus colchetes serão de prata, porém as suas bases de bronze.' },
      { v: 18, en: 'The length of the court shall be one hundred cubits, and the width fifty throughout, and the height five cubits, of fine twined linen, and their sockets of brass.', pt: 'O comprimento do átrio será de cem côvados, e a largura, por toda a extensão, de cinqüenta, e a altura de cinco côvados; as cortinas serão de linho fino torcido; e as bases das colunas de bronze.' },
      { v: 19, en: 'All the instruments of the tabernacle in all its service, and all its pins, and all the pins of the court, shall be of brass.', pt: 'Todos os utensílios do tabernáculo em todo o seu serviço, e todas as suas estacas, e todas as estacas do átrio, serão de bronze.' },
      { v: 20, en: '“You shall command the children of Israel, that they bring to you pure olive oil beaten for the light, to cause a lamp to burn continually.', pt: 'Ordenarás aos filhos de Israel que te tragam azeite puro de oliveiras, batido, para o candeeiro, para manter uma lâmpada acesa continuamente.' },
      { v: 21, en: 'In the Tent of Meeting, outside the veil which is before the testimony, Aaron and his sons shall keep it in order from evening to morning before Yahweh: it shall be a statute forever throughout their generations on the behalf of the children of Israel.', pt: 'Na tenda da revelação, fora do véu que está diante do testemunho, Arão e seus filhos a conservarão em ordem, desde a tarde até pela manhã, perante o Senhor; este será um estatuto perpétuo para os filhos de Israel pelas suas gerações.' },
    ],
    28: [
      { v: 1, en: '“Bring Aaron your brother, and his sons with him, near to you from among the children of Israel, that he may minister to me in the priest’s office, even Aaron, Nadab and Abihu, Eleazar and Ithamar, Aaron’s sons.', pt: 'Depois farás chegar a ti teu irmão Arão, e seus filhos com ele, dentre os filhos de Israel, para me administrarem o ofício sacerdotal; a saber: Arão, Nadabe e Abiú, Eleazar e Itamar, os filhos de Arão.' },
      { v: 2, en: 'You shall make holy garments for Aaron your brother, for glory and for beauty.', pt: 'Farás vestes sagradas para Arão, teu irmão, para glória e ornamento.' },
      { v: 3, en: 'You shall speak to all who are wise-hearted, whom I have filled with the spirit of wisdom, that they make Aaron’s garments to sanctify him, that he may minister to me in the priest’s office.', pt: 'Falarás a todos os homens hábeis, a quem eu tenha enchido do espírito de sabedoria, que façam as vestes de Arão para santificá-lo, a fim de que me administre o ofício sacerdotal.' },
      { v: 4, en: 'These are the garments which they shall make: a breastplate, and an ephod, and a robe, and a coat of checker work, a turban, and a sash: and they shall make holy garments for Aaron your brother, and his sons, that he may minister to me in the priest’s office.', pt: 'Estas pois são as vestes que farão: um peitoral, um éfode, um manto, uma túnica bordada, uma mitra e um cinto; farão, pois, as vestes sagradas para Arão, teu irmão, e para seus filhos, a fim de me administrarem o ofício sacerdotal.' },
      { v: 5, en: 'They shall take the gold, and the blue, and the purple, and the scarlet, and the fine linen.', pt: 'E receberão o ouro, o azul, a púrpura, o carmesim e o linho fino,' },
      { v: 6, en: '“They shall make the ephod of gold, of blue, and purple, scarlet, and fine twined linen, the work of the skillful workman.', pt: 'e farão o éfode de ouro, azul, púrpura, carmesim e linho fino torcido, obra de desenhista.' },
      { v: 7, en: 'It shall have two shoulder straps joined to the two ends of it, that it may be joined together.', pt: 'Terá duas ombreiras, que se unam às suas duas pontas, para que seja unido.' },
      { v: 8, en: 'The skillfully woven band, which is on it, that is on him, shall be like its work and of the same piece; of gold, of blue, and purple, and scarlet, and fine twined linen.', pt: 'E o cinto de obra esmerada do éfode, que estará sobre ele, formando com ele uma só peça, será de obra semelhante de ouro, azul, púrpura, carmesim e linho fino torcido.' },
      { v: 9, en: 'You shall take two onyx stones, and engrave on them the names of the children of Israel:', pt: 'E tomarás duas pedras de berilo, e gravarás nelas os nomes dos filhos de Israel.' },
      { v: 10, en: 'six of their names on the one stone, and the names of the six that remain on the other stone, in the order of their birth.', pt: 'Seis dos seus nomes numa pedra, e os seis nomes restantes na outra pedra, segundo a ordem do seu nascimento.' },
      { v: 11, en: 'With the work of an engraver in stone, like the engravings of a signet, you shall engrave the two stones, according to the names of the children of Israel: you shall make them to be enclosed in settings of gold.', pt: 'Conforme a obra de lapidário, como a gravura de um selo, gravarás as duas pedras, com os nomes dos filhos de Israel; guarnecidas de engastes de ouro as farás.' },
      { v: 12, en: 'You shall put the two stones on the shoulder straps of the ephod, to be stones of memorial for the children of Israel: and Aaron shall bear their names before Yahweh on his two shoulders for a memorial.', pt: 'E porás as duas pedras nas ombreiras do éfode, para servirem de pedras de memorial para os filhos de Israel; assim sobre um e outro ombro levará Arão diante do Senhor os seus nomes como memorial.' },
      { v: 13, en: 'You shall make settings of gold,', pt: 'Farás também engastes de ouro,' },
      { v: 14, en: 'and two chains of pure gold; you shall make them like cords of braided work: and you shall put the braided chains on the settings.', pt: 'e duas cadeiazinhas de ouro puro; como cordas as farás, de obra trançada; e aos engastes fixarás as cadeiazinhas de obra trançada.' },
      { v: 15, en: '“You shall make a breastplate of judgment, the work of the skillful workman; like the work of the ephod you shall make it; of gold, of blue, and purple, and scarlet, and fine twined linen, you shall make it.', pt: 'Farás também o peitoral do juízo, obra de artífice; conforme a obra do éfode o farás; de ouro, de azul, de púrpura, de carmesim, e de linho fino torcido o farás.' },
      { v: 16, en: 'It shall be square and folded double; a span shall be its length of it, and a span its width.', pt: 'Quadrado e duplo, será de um palmo o seu comprimento, e de um palmo a sua largura.' },
      { v: 17, en: 'You shall set in it settings of stones, four rows of stones: a row of ruby, topaz, and beryl shall be the first row;', pt: 'E o encherás de pedras de engaste, em quatro fileiras: a primeira será de uma cornalina, um topázio e uma esmeralda;' },
      { v: 18, en: 'and the second row a turquoise, a sapphire, and an emerald;', pt: 'a segunda fileira será de uma granada, uma safira e um ônix;' },
      { v: 19, en: 'and the third row a jacinth, an agate, and an amethyst;', pt: 'a terceira fileira será de um jacinto, uma ágata e uma ametista;' },
      { v: 20, en: 'and the fourth row a chrysolite, an onyx, and a jasper: they shall be enclosed in gold in their settings.', pt: 'e a quarta fileira será de uma crisólita, um berilo e um jaspe; elas serão guarnecidas de ouro nos seus engastes.' },
      { v: 21, en: 'The stones shall be according to the names of the children of Israel, twelve, according to their names; like the engravings of a signet, everyone according to his name, they shall be for the twelve tribes.', pt: 'Serão, pois, as pedras segundo os nomes dos filhos de Israel, doze segundo os seus nomes; serão como a gravura de um selo, cada uma com o seu nome, para as doze tribos.' },
      { v: 22, en: 'You shall make on the breastplate chains like cords, of braided work of pure gold.', pt: 'Também farás sobre o peitoral cadeiazinhas como cordas, obra de trança, de ouro puro.' },
      { v: 23, en: 'You shall make on the breastplate two rings of gold, and shall put the two rings on the two ends of the breastplate.', pt: 'Igualmente sobre o peitoral farás duas argolas de ouro, e porás as duas argolas nas duas extremidades do peitoral.' },
      { v: 24, en: 'You shall put the two braided chains of gold in the two rings at the ends of the breastplate.', pt: 'Então meterás as duas cadeiazinhas de ouro, de obra trançada, nas duas argolas nas extremidades do peitoral;' },
      { v: 25, en: 'The other two ends of the two braided chains you shall put on the two settings, and put them on the shoulder straps of the ephod in its forepart.', pt: 'e as outras duas pontas das duas cadeiazinhas de obra trançada meterás nos dois engastes, e as porás nas ombreiras do éfode, na parte dianteira dele.' },
      { v: 26, en: 'You shall make two rings of gold, and you shall put them on the two ends of the breastplate, on its edge, which is toward the side of the ephod inward.', pt: 'Farás outras duas argolas de ouro, e as porás nas duas extremidades do peitoral, na sua borda que estiver junto ao lado interior do éfode.' },
      { v: 27, en: 'You shall make two rings of gold, and shall put them on the two shoulder straps of the ephod underneath, in its forepart, close by its coupling, above the skillfully woven band of the ephod.', pt: 'Farás mais duas argolas de ouro, e as porás nas duas ombreiras do éfode, para baixo, na parte dianteira, junto à costura, e acima do cinto de obra esmerada do éfode.' },
      { v: 28, en: 'They shall bind the breastplate by its rings to the rings of the ephod with a lace of blue, that it may be on the skillfully woven band of the ephod, and that the breastplate may not swing out from the ephod.', pt: 'E ligarão o peitoral, pelas suas argolas, às argolas do éfode por meio de um cordão azul, de modo que fique sobre o cinto de obra esmerada do éfode e não se separe o peitoral do éfode.' },
      { v: 29, en: 'Aaron shall bear the names of the children of Israel in the breastplate of judgment on his heart, when he goes in to the holy place, for a memorial before Yahweh continually.', pt: 'Assim Arão levará os nomes dos filhos de Israel no peitoral do juízo sobre o seu coração, quando entrar no lugar santo, para memorial diante do Senhor continuamente.' },
      { v: 30, en: 'You shall put in the breastplate of judgment the Urim and the Thummim; and they shall be on Aaron’s heart, when he goes in before Yahweh: and Aaron shall bear the judgment of the children of Israel on his heart before Yahweh continually.', pt: 'Também porás no peitoral do juízo o Urim e o Tumim, para que estejam sobre o coração de Arão, quando entrar diante do Senhor; assim Arão levará o juízo dos filhos de Israel sobre o seu coração diante do Senhor continuamente.' },
      { v: 31, en: '“You shall make the robe of the ephod all of blue.', pt: 'Também farás o manto do éfode todo de azul.' },
      { v: 32, en: 'It shall have a hole for the head in the middle of it. It shall have a binding of woven work around its hole, as it were the hole of a coat of mail, that it not be torn.', pt: 'No meio dele haverá uma abertura para a cabeça; esta abertura terá um debrum de obra tecida ao redor, como a abertura de cota de malha, para que não se rompa.' },
      { v: 33, en: 'On its hem you shall make pomegranates of blue, and of purple, and of scarlet, around its hem; and bells of gold between and around them:', pt: 'E nas suas abas, em todo o seu redor, farás romãs de azul, púrpura e carmesim, e campainhas de ouro, entremeadas com elas ao redor.' },
      { v: 34, en: 'a golden bell and a pomegranate, a golden bell and a pomegranate, around the hem of the robe.', pt: 'uma campainha de ouro, e uma romã, outra campainha de ouro, e outra romã, haverá nas abas do manto ao redor.' },
      { v: 35, en: 'It shall be on Aaron to minister: and its sound shall be heard when he goes in to the holy place before Yahweh, and when he comes out, that he not die.', pt: 'E estará sobre Arão quando ministrar, para que se ouça o sonido ao entrar ele no lugar santo diante do Senhor e ao sair, para que ele não morra.' },
      { v: 36, en: '“You shall make a plate of pure gold, and engrave on it, like the engravings of a signet, ‘HOLY TO YAHWEH.’', pt: 'Também farás uma lâmina de ouro puro, e nela gravarás como a gravura de um selo: SANTO AO SENHOR.' },
      { v: 37, en: 'You shall put it on a lace of blue, and it shall be on the sash; on the front of the sash it shall be.', pt: 'Pô-la-ás em um cordão azul, de maneira que esteja na mitra; bem na frente da mitra estará.' },
      { v: 38, en: 'It shall be on Aaron’s forehead, and Aaron shall bear the iniquity of the holy things, which the children of Israel shall make holy in all their holy gifts; and it shall be always on his forehead, that they may be accepted before Yahweh.', pt: 'E estará sobre a testa de Arão, e Arão levará a iniqüidade das coisas santas, que os filhos de Israel consagrarem em todas as suas santas ofertas; e estará continuamente na sua testa, para que eles sejam aceitos diante do Senhor.' },
      { v: 39, en: 'You shall weave the coat in checker work of fine linen, and you shall make a turban of fine linen, and you shall make a sash, the work of the embroiderer.', pt: 'Também tecerás a túnica enxadrezada de linho fino; bem como de linho fino farás a mitra; e farás o cinto, obra de bordador.' },
      { v: 40, en: '“You shall make coats for Aaron’s sons, and you shall make sashes for them and you shall make headbands for them, for glory and for beauty.', pt: 'Também para os filhos de Arão farás túnicas; e far-lhes-ás cintos; também lhes farás tiaras, para glória e ornamento.' },
      { v: 41, en: 'You shall put them on Aaron your brother, and on his sons with him, and shall anoint them, and consecrate them, and sanctify them, that they may minister to me in the priest’s office.', pt: 'E vestirás com eles a Arão, teu irmão, e também a seus filhos, e os ungirás e consagrarás, e os santificarás, para que me administrem o sacerdócio.' },
      { v: 42, en: 'You shall make them linen breeches to cover the flesh of their nakedness; from the waist even to the thighs they shall reach:', pt: 'Faze-lhes também calções de linho, para cobrirem a carne nua; estender-se-ão desde os lombos até as coxas.' },
      { v: 43, en: 'They shall be on Aaron, and on his sons, when they go in to the Tent of Meeting, or when they come near to the altar to minister in the holy place; that they don’t bear iniquity, and die: it shall be a statute forever to him and to his offspring after him.', pt: 'E estarão sobre Arão e sobre seus filhos, quando entrarem na tenda da revelação, ou quando chegarem ao altar para ministrar no lugar santo, para que não levem iniqüidade e morram; isto será estatuto perpétuo para ele e para a sua descendência depois dele.' },
    ],
    29: [
      { v: 1, en: '“This is the thing that you shall do to them to make them holy, to minister to me in the priest’s office: take one young bull and two rams without defect,', pt: 'Isto é o que lhes farás para os santificar, para que me administrem o sacerdócio: Toma um novilho e dois carneiros sem defeito,' },
      { v: 2, en: 'unleavened bread, unleavened cakes mixed with oil, and unleavened wafers anointed with oil: you shall make them of fine wheat flour.', pt: 'e pão ázimo, e bolos ázimos, amassados com azeite, e coscorões ázimos, untados com azeite; de flor de farinha de trigo os farás;' },
      { v: 3, en: 'You shall put them into one basket, and bring them in the basket, with the bull and the two rams.', pt: 'e os porás num cesto, e os trarás no cesto, com o novilho e os dois carneiros.' },
      { v: 4, en: 'You shall bring Aaron and his sons to the door of the Tent of Meeting, and shall wash them with water.', pt: 'Então farás chegar Arão e seus filhos à porta da tenda da revelação e os lavarás, com água.' },
      { v: 5, en: 'You shall take the garments, and put on Aaron the coat, the robe of the ephod, the ephod, and the breastplate, and clothe him with the skillfully woven band of the ephod;', pt: 'Depois tomarás as vestes, e vestirás a Arão da túnica e do manto do éfode, e do éfode mesmo, e do peitoral, e lhe cingirás o éfode com o seu cinto de obra esmerada;' },
      { v: 6, en: 'and you shall set the turban on his head, and put the holy crown on the turban.', pt: 'e pôr-lhe-ás a mitra na cabeça; e sobre a mitra porás a coroa de santidade;' },
      { v: 7, en: 'Then you shall take the anointing oil, and pour it on his head, and anoint him.', pt: 'então tomarás o óleo da unção e, derramando-lho sobre a cabeça, o ungirás.' },
      { v: 8, en: 'You shall bring his sons, and put coats on them.', pt: 'Depois farás chegar seus filhos, e lhes farás vestir túnicas,' },
      { v: 9, en: 'You shall clothe them with belts, Aaron and his sons, and bind headbands on them: and they shall have the priesthood by a perpetual statute: and you shall consecrate Aaron and his sons.', pt: 'e os cingirás com cintos, a Arão e a seus filhos, e lhes atarás as tiaras. Por estatuto perpétuo eles terão o sacerdócio; consagrarás, pois, a Arão e a seus filhos.' },
      { v: 10, en: '“You shall bring the bull before the Tent of Meeting: and Aaron and his sons shall lay their hands on the head of the bull.', pt: 'Farás chegar o novilho diante da tenda da revelação, e Arão e seus filhos porão as mãos sobre a cabeça do novilho;' },
      { v: 11, en: 'You shall kill the bull before Yahweh, at the door of the Tent of Meeting.', pt: 'e imolarás o novilho perante o Senhor, à porta da tenda da revelação.' },
      { v: 12, en: 'You shall take of the blood of the bull, and put it on the horns of the altar with your finger; and you shall pour out all the blood at the base of the altar.', pt: 'Depois tomarás do sangue do novilho, e com o dedo o porás sobre as pontas do altar, e todo o sangue restante derramarás à base do altar.' },
      { v: 13, en: 'You shall take all the fat that covers the innards, the cover of the liver, the two kidneys, and the fat that is on them, and burn them on the altar.', pt: 'Também tomarás toda a gordura que cobre as entranhas, o redenho do fígado, os dois rins e a gordura que houver neles, e queimá-los-ás sobre o altar;' },
      { v: 14, en: 'But the meat of the bull, and its skin, and its dung, you shall burn with fire outside of the camp: it is a sin offering.', pt: 'mas a carne do novilho, o seu couro e o seu excremento queimarás fora do arraial; é sacrifício pelo pecado.' },
      { v: 15, en: '“You shall also take the one ram; and Aaron and his sons shall lay their hands on the head of the ram.', pt: 'Depois tomarás um carneiro, e Arão e seus filhos porão as mãos sobre a cabeça dele,' },
      { v: 16, en: 'You shall kill the ram, and you shall take its blood, and sprinkle it around on the altar.', pt: 'e imolarás o carneiro e, tomando o seu sangue, o espargirás sobre o altar ao redor;' },
      { v: 17, en: 'You shall cut the ram into its pieces, and wash its innards, and its legs, and put them with its pieces, and with its head.', pt: 'e partirás o carneiro em suas partes, e lavarás as suas entranhas e as suas pernas, e as porás sobre as suas partes e sobre a sua cabeça.' },
      { v: 18, en: 'You shall burn the whole ram on the altar: it is a burnt offering to Yahweh; it is a pleasant aroma, an offering made by fire to Yahweh.', pt: 'Assim queimarás todo o carneiro sobre o altar; é um holocausto para o Senhor; é cheiro suave, oferta queimada ao Senhor.' },
      { v: 19, en: '“You shall take the other ram; and Aaron and his sons shall lay their hands on the head of the ram.', pt: 'Depois tomarás o outro carneiro, e Arão e seus filhos porão as mãos sobre a cabeça dele;' },
      { v: 20, en: 'Then you shall kill the ram, and take some of its blood, and put it on the tip of the right ear of Aaron, and on the tip of the right ear of his sons, and on the thumb of their right hand, and on the big toe of their right foot, and sprinkle the blood around on the altar.', pt: 'e imolarás o carneiro, e tomarás do seu sangue, e o porás sobre a ponta da orelha direita de Arão e sobre a ponta da orelha direita de seus filhos, como também sobre o dedo polegar da sua mão direita e sobre o dedo polegar do seu pé direito; e espargirás o sangue sobre o altar ao redor.' },
      { v: 21, en: 'You shall take of the blood that is on the altar, and of the anointing oil, and sprinkle it on Aaron, and on his garments, and on his sons, and on the garments of his sons with him: and he shall be made holy, and his garments, and his sons, and his sons’ garments with him.', pt: 'Então tomarás do sangue que estará sobre o altar, e do óleo da unção, e os espargirás sobre Arão e sobre as suas vestes, e sobre seus filhos, e sobre as vestes de seus filhos com ele; assim ele será santificado e as suas vestes, também seus filhos e as vestes de seus filhos com ele.' },
      { v: 22, en: 'Also you shall take some of the ram’s fat, the fat tail, the fat that covers the innards, the cover of the liver, the two kidneys, the fat that is on them, and the right thigh (for it is a ram of consecration),', pt: 'Depois tomarás do carneiro a gordura e a cauda gorda, a gordura que cobre as entranhas e o redenho do fígado, os dois rins com a gordura que houver neles e a coxa direita (porque é carneiro de consagração),' },
      { v: 23, en: 'and one loaf of bread, one cake of oiled bread, and one wafer out of the basket of unleavened bread that is before Yahweh.', pt: 'e uma fogaça de pão, um bolo de pão azeitado e um coscorão do cesto dos pães ázimos que estará diante do Senhor,' },
      { v: 24, en: 'You shall put all of this in Aaron’s hands, and in his sons’ hands, and shall wave them for a wave offering before Yahweh.', pt: 'e tudo porás nas mãos de Arão, e nas mãos de seus filhos; e por oferta de movimento o moverás perante o Senhor.' },
      { v: 25, en: 'You shall take them from their hands, and burn them on the altar on the burnt offering, for a pleasant aroma before Yahweh: it is an offering made by fire to Yahweh.', pt: 'Depois o tomarás das suas mãos e o queimarás no altar sobre o holocausto, por cheiro suave perante o Senhor; é oferta queimada ao Senhor.' },
      { v: 26, en: '“You shall take the breast of Aaron’s ram of consecration, and wave it for a wave offering before Yahweh: and it shall be your portion.', pt: 'Também tomarás o peito do carneiro de consagração, que é de Arão, e por oferta de movimento o moverás perante o Senhor; e isto será a tua porção.' },
      { v: 27, en: 'You shall sanctify the breast of the wave offering, and the thigh of the wave offering, which is waved, and which is heaved up, of the ram of consecration, even of that which is for Aaron, and of that which is for his sons:', pt: 'E santificarás o peito da oferta de movimento e a coxa da oferta alçada, depois de movida e alçada, isto é, aquilo do carneiro de consagração que for de Arão e de seus filhos;' },
      { v: 28, en: 'and it shall be for Aaron and his sons as their portion forever from the children of Israel; for it is a wave offering: and it shall be a wave offering from the children of Israel of the sacrifices of their peace offerings, even their wave offering to Yahweh.', pt: 'e isto será para Arão e para seus fihos a porção de direito, para sempre, da parte dos filhos de Israel, porque é oferta alçada; e oferta alçada será dos filhos de Israel, dos sacrifícios das suas ofertas pacíficas, oferta alçada ao Senhor.' },
      { v: 29, en: '“The holy garments of Aaron shall be for his sons after him, to be anointed in them, and to be consecrated in them.', pt: 'As vestes sagradas de Arão ficarão para seus filhos depois dele, para nelas serem ungidos e sagrados.' },
      { v: 30, en: 'Seven days shall the son who is priest in his place put them on, when he comes into the Tent of Meeting to minister in the holy place.', pt: 'Sete dias os vestirá aquele que de seus filhos for sacerdote em seu lugar, quando entrar na tenda da revelação para ministrar no lugar santo.' },
      { v: 31, en: '“You shall take the ram of consecration, and boil its meat in a holy place.', pt: 'Também tomarás o carneiro de consagração e cozerás a sua carne em lugar santo.' },
      { v: 32, en: 'Aaron and his sons shall eat the meat of the ram, and the bread that is in the basket, at the door of the Tent of Meeting.', pt: 'E Arão e seus filhos comerão a carne do carneiro, e o pão que está no cesto, à porta da tenda da revelação;' },
      { v: 33, en: 'They shall eat those things with which atonement was made, to consecrate and sanctify them: but a stranger shall not eat of it, because they are holy.', pt: 'e comerão as coisas com que for feita expiação, para consagrá-los, e para santificá-los; mas delas o estranho nào comerá, porque são santas.' },
      { v: 34, en: 'If anything of the meat of the consecration, or of the bread, remains to the morning, then you shall burn the remainder with fire: it shall not be eaten, because it is holy.', pt: 'E se sobejar alguma coisa da carne da consagração, ou do pão, até pela manhã, o que sobejar queimarás no fogo; não se comerá, porque é santo.' },
      { v: 35, en: '“You shall do so to Aaron, and to his sons, according to all that I have commanded you. You shall consecrate them seven days.', pt: 'Assim, pois, farás a Arão e a seus filhos conforme tudo o que te hei ordenado; por sete dias os sagrarás.' },
      { v: 36, en: 'Every day you shall offer the bull of sin offering for atonement: and you shall cleanse the altar, when you make atonement for it; and you shall anoint it, to sanctify it.', pt: 'Também cada dia oferecerás para expiação o novilho de sacrifício pelo pecado; e purificarás o altar, fazendo expiação por ele; e o ungirás para santificá-lo.' },
      { v: 37, en: 'Seven days you shall make atonement for the altar, and sanctify it: and the altar shall be most holy; whatever touches the altar shall be holy.', pt: 'Sete dias farás expiação pelo altar, e o santificarás; e o altar será santíssimo; tudo o que tocar o altar será santo.' },
      { v: 38, en: '“Now this is that which you shall offer on the altar: two lambs a year old day by day continually.', pt: 'Isto, pois, é o que oferecerás sobre o altar: dois cordeiros de um ano cada dia continuamente.' },
      { v: 39, en: 'The one lamb you shall offer in the morning; and the other lamb you shall offer at evening:', pt: 'Um cordeiro oferecerás pela manhã, e o outro cordeiro oferecerás à tardinha;' },
      { v: 40, en: 'and with the one lamb a tenth part of an ephah of fine flour mixed with the fourth part of a hin of beaten oil, and the fourth part of a hin of wine for a drink offering.', pt: 'com um cordeiro a décima parte de uma efa de flor de farinha, misturada com a quarta parte de um him de azeite batido, e para libação a quarta parte de um him de vinho.' },
      { v: 41, en: 'The other lamb you shall offer at evening, and shall do to it according to the meal offering of the morning, and according to its drink offering, for a pleasant aroma, an offering made by fire to Yahweh.', pt: 'E o outro cordeiro oferecerás à tardinha, e com ele farás oferta de cereais como com a oferta da manhã, e conforme a sua oferta de libação, por cheiro suave; oferta queimada é ao Senhor.' },
      { v: 42, en: 'It shall be a continual burnt offering throughout your generations at the door of the Tent of Meeting before Yahweh, where I will meet with you, to speak there to you.', pt: 'Este será o holocausto contínuo por vossas gerações, à porta da tenda da revelação, perante o Senhor, onde vos encontrarei, para falar contigo ali.' },
      { v: 43, en: 'There I will meet with the children of Israel; and the place shall be sanctified by my glory.', pt: 'E ali virei aos filhos de Israel; e a tenda será santificada pela minha glória;' },
      { v: 44, en: 'I will sanctify the Tent of Meeting and the altar: Aaron also and his sons I will sanctify, to minister to me in the priest’s office.', pt: 'santificarei a tenda da revelação e o altar; também santificarei a Arão e seus filhos, para que me administrem o sacerdócio.' },
      { v: 45, en: 'I will dwell among the children of Israel, and will be their God.', pt: 'Habitarei no meio dos filhos de Israel, e serei o seu Deus;' },
      { v: 46, en: 'They shall know that I am Yahweh their God, who brought them out of the land of Egypt, that I might dwell among them: I am Yahweh their God.', pt: 'e eles saberão que eu sou o Senhor seu Deus, que os tirei da terra do Egito, para habitar no meio deles; eu sou o Senhor seu Deus.' },
    ],
    30: [
      { v: 1, en: '“You shall make an altar to burn incense on. You shall make it of acacia wood.', pt: 'Farás um altar para queimar o incenso; de madeira de acácia o farás.' },
      { v: 2, en: 'Its length shall be a cubit, and its width a cubit. It shall be square, and its height shall be two cubits. Its horns shall be of one piece with it.', pt: 'O seu comprimento será de um côvado, e a sua largura de um côvado; será quadrado; e de dois côvados será a sua altura; as suas pontas formarão uma só peça com ele.' },
      { v: 3, en: 'You shall overlay it with pure gold, its top, its sides around it, and its horns; and you shall make a gold molding around it.', pt: 'De ouro puro o cobrirás, tanto a face superior como as suas paredes ao redor, e as suas pontas; e lhe farás uma moldura de ouro ao redor.' },
      { v: 4, en: 'You shall make two golden rings for it under its molding; on its two ribs, on its two sides you shall make them; and they shall be for places for poles with which to bear it.', pt: 'Também lhe farás duas argolas de ouro debaixo da sua moldura; nos dois cantos de ambos os lados as farás; e elas servirão de lugares para os varais com que o altar será levado.' },
      { v: 5, en: 'You shall make the poles of acacia wood, and overlay them with gold.', pt: 'Farás também os varais de madeira de acácia e os cobrirás de ouro.' },
      { v: 6, en: 'You shall put it before the veil that is by the ark of the testimony, before the mercy seat that is over the testimony, where I will meet with you.', pt: 'E porás o altar diante do véu que está junto à arca do testemunho, diante do propiciatório, que se acha sobre o testemunho, onde eu virei a ti.' },
      { v: 7, en: 'Aaron shall burn incense of sweet spices on it every morning. When he tends the lamps, he shall burn it.', pt: 'E Arão queimará sobre ele o incenso das especiarias; cada manhã, quando puser em ordem as lâmpadas, o queimará.' },
      { v: 8, en: 'When Aaron lights the lamps at evening, he shall burn it, a perpetual incense before Yahweh throughout your generations.', pt: 'Também quando acender as lâmpadas à tardinha, o queimará; este será incenso perpétuo perante o Senhor pelas vossas gerações.' },
      { v: 9, en: 'You shall offer no strange incense on it, nor burnt offering, nor meal offering; and you shall pour no drink offering on it.', pt: 'Não oferecereis sobre ele incenso estranho, nem holocausto, nem oferta de cereais; nem tampouco derramareis sobre ele ofertas de libação.' },
      { v: 10, en: 'Aaron shall make atonement on its horns once in the year; with the blood of the sin offering of atonement once in the year he shall make atonement for it throughout your generations. It is most holy to Yahweh.”', pt: 'E uma vez no ano Arão fará expiação sobre as pontas do altar; com o sangue do sacrifício de expiação de pecado, fará expiação sobre ele uma vez no ano pelas vossas gerações; santíssimo é ao Senhor.' },
      { v: 11, en: 'Yahweh spoke to Moses, saying,', pt: 'Disse mais o Senhor a Moisés:' },
      { v: 12, en: '“When you take a census of the children of Israel, according to those who are counted among them, then each man shall give a ransom for his soul to Yahweh, when you count them; that there be no plague among them when you count them.', pt: 'Quando fizeres o alistamento dos filhos de Israel para sua enumeração, cada um deles dará ao Senhor o resgate da sua alma, quando os alistares; para que não haja entre eles praga alguma por ocasião do alistamento.' },
      { v: 13, en: 'They shall give this, everyone who passes over to those who are counted, half a shekel after the shekel of the sanctuary (the shekel is twenty gerahs ); half a shekel for an offering to Yahweh.', pt: 'Dará cada um, ao ser alistado, meio siclo, segundo o siclo do santuário (este siclo é de vinte jeiras); meio siclo é a oferta ao Senhor.' },
      { v: 14, en: 'Everyone who passes over to those who are counted, from twenty years old and upward, shall give the offering to Yahweh.', pt: 'Todo aquele que for alistado, de vinte anos para cima, dará a oferta do Senhor.' },
      { v: 15, en: 'The rich shall not give more, and the poor shall not give less, than the half shekel, when they give the offering of Yahweh, to make atonement for your souls.', pt: 'O rico não dará mais, nem o pobre dará menos do que o meio siclo, quando derem a oferta do Senhor, para fazerdes expiação por vossas almas.' },
      { v: 16, en: 'You shall take the atonement money from the children of Israel, and shall appoint it for the service of the Tent of Meeting; that it may be a memorial for the children of Israel before Yahweh, to make atonement for your souls.”', pt: 'E tomarás o dinheiro da expiação dos filhos de Israel, e o designarás para o serviço da tenda da revelação, para que sirva de memorial a favor dos filhos de Israel diante do Senhor, para fazerdes expiação por vossas almas.' },
      { v: 17, en: 'Yahweh spoke to Moses, saying,', pt: 'Disse mais o Senhor a Moisés:' },
      { v: 18, en: '“You shall also make a basin of brass, and its base of brass, in which to wash. You shall put it between the Tent of Meeting and the altar, and you shall put water in it.', pt: 'Farás também uma pia de bronze com a sua base de bronze, para lavatório; e a porás entre a tenda da revelação e o altar, e nela deitarás água,' },
      { v: 19, en: 'Aaron and his sons shall wash their hands and their feet in it.', pt: 'com a qual Arão e seus filhos lavarão as mãos e os pés;' },
      { v: 20, en: 'When they go into the Tent of Meeting, they shall wash with water, that they not die; or when they come near to the altar to minister, to burn an offering made by fire to Yahweh.', pt: 'quando entrarem na tenda da revelação lavar-se-ão com água, para que não morram, ou quando se chegarem ao altar para ministrar, para fazer oferta queimada ao Senhor.' },
      { v: 21, en: 'So they shall wash their hands and their feet, that they not die: and it shall be a statute forever to them, even to him and to his descendants throughout their generations.”', pt: 'Lavarão, pois, as mãos e os pés, para que não morram; e isto lhes será por estatuto perpétuo a ele e à sua descendência pelas suas gerações.' },
      { v: 22, en: 'Moreover Yahweh spoke to Moses, saying,', pt: 'Disse mais o Senhor a Moisés:' },
      { v: 23, en: '“Also take fine spices: of liquid myrrh, five hundred shekels; and of fragrant cinnamon half as much, even two hundred and fifty; and of fragrant cane, two hundred and fifty;', pt: 'Também toma das principais especiarias, da mais pura mirra quinhentos siclos, de canela aromática a metade, a saber, duzentos e cinqüenta siclos, de cálamo aromático duzentos e cinqüenta siclos,' },
      { v: 24, en: 'and of cassia five hundred, after the shekel of the sanctuary; and a hin of olive oil.', pt: 'de cássia quinhentos siclos, segundo o siclo do santuário, e de azeite de oliveiras um him.' },
      { v: 25, en: 'You shall make it into a holy anointing oil, a perfume compounded after the art of the perfumer: it shall be a holy anointing oil.', pt: 'Disto farás um óleo sagrado para as unções, um perfume composto segundo a arte do perfumista; este será o óleo sagrado para as unções.' },
      { v: 26, en: 'You shall use it to anoint the Tent of Meeting, the ark of the testimony,', pt: 'Com ele ungirás a tenda da revelação, a arca do testemunho,' },
      { v: 27, en: 'the table and all its articles, the lamp stand and its accessories, the altar of incense,', pt: 'a mesa com todos os seus utensílios, o candelabro com os seus utensílios, o altar de incenso,' },
      { v: 28, en: 'the altar of burnt offering with all its utensils, and the basin with its base.', pt: 'a altar do holocausto com todos os seus utensílios, o altar de incenso,' },
      { v: 29, en: 'You shall sanctify them, that they may be most holy. Whatever touches them shall be holy.', pt: 'Assim santificarás estas coisas, para que sejam santíssimas; tudo o que as tocar será santo.' },
      { v: 30, en: 'You shall anoint Aaron and his sons, and sanctify them, that they may minister to me in the priest’s office.', pt: 'Também ungirás a Arão e seus filhos, e os santificarás para me administrarem o sacerdócio.' },
      { v: 31, en: 'You shall speak to the children of Israel, saying, ‘This shall be a holy anointing oil to me throughout your generations.', pt: 'E falarás aos filhos de Israel, dizendo: Este me será o óleo sagrado para as unções por todas as vossas gerações.' },
      { v: 32, en: 'It shall not be poured on man’s flesh, and do not make any like it, according to its composition. It is holy. It shall be holy to you.', pt: 'Não se ungirá com ele carne de homem; nem fareis outro de semelhante composição; sagrado é, e para vós será sagrado.' },
      { v: 33, en: 'Whoever compounds any like it, or whoever puts any of it on a stranger, he shall be cut off from his people.’”', pt: 'O homem que compuser um perfume como este, ou que com ele ungir a um estranho, será extirpado do seu povo.' },
      { v: 34, en: 'Yahweh said to Moses, “Take to yourself sweet spices, gum resin, and onycha, and galbanum; sweet spices with pure frankincense: there shall be an equal weight of each;', pt: 'Disse mais o Senhor a Moisés: Toma especiarias aromáticas: estoraque, e ônica, e gálbano, especiarias aromáticas com incenso puro; de cada uma delas tomarás peso igual;' },
      { v: 35, en: 'and you shall make incense of it, a perfume after the art of the perfumer, seasoned with salt, pure and holy:', pt: 'e disto farás incenso, um perfume segundo a arte do perfumista, temperado com sal, puro e santo;' },
      { v: 36, en: 'and you shall beat some of it very small, and put some of it before the testimony in the Tent of Meeting, where I will meet with you. It shall be to you most holy.', pt: 'e uma parte dele reduzirás a pó e o porás diante do testemunho, na tenda da revelação onde eu virei a ti; coisa santíssimá vos será.' },
      { v: 37, en: 'The incense which you shall make, according to its composition you shall not make for yourselves: it shall be to you holy for Yahweh.', pt: 'Ora, o incenso que fareis conforme essa composição, não o fareis para vós mesmos; santo vos será para o Senhor.' },
      { v: 38, en: 'Whoever shall make any like that, to smell of it, he shall be cut off from his people.”', pt: 'O homem que fizer tal como este para o cheirar, será extirpado do seu povo.' },
    ],
    31: [
      { v: 1, en: 'Yahweh spoke to Moses, saying,', pt: 'Depois disse o Senhor a Moisés:' },
      { v: 2, en: '“Behold, I have called by name Bezalel the son of Uri, the son of Hur, of the tribe of Judah:', pt: 'Eis que eu tenho chamado por nome a Bezaleel, filho de îri, filho de Hur, da tribo de Judá,' },
      { v: 3, en: 'and I have filled him with the Spirit of God, in wisdom, and in understanding, and in knowledge, and in all kinds of workmanship,', pt: 'e o enchi do espírito de Deus, no tocante à sabedoria, ao entendimento, à ciência e a todo ofício,' },
      { v: 4, en: 'to devise skillful works, to work in gold, and in silver, and in brass,', pt: 'para inventar obras artísticas, e trabalhar em ouro, em prata e em bronze,' },
      { v: 5, en: 'and in cutting of stones for setting, and in carving of wood, to work in all kinds of workmanship.', pt: 'e em lavramento de pedras para engastar, e em entalhadura de madeira, enfim para trabalhar em todo ofício.' },
      { v: 6, en: 'Behold, I myself have appointed with him Oholiab, the son of Ahisamach, of the tribe of Dan; and in the heart of all who are wise-hearted I have put wisdom, that they may make all that I have commanded you:', pt: 'E eis que eu tenho designado com ele a Aoliabe, filho de Aisamaque, da tribo de Dã, e tenho dado sabedoria ao coração de todos os homens hábeis, para fazerem tudo o que te hei ordenado,' },
      { v: 7, en: 'the Tent of Meeting, the ark of the testimony, the mercy seat that is on it, all the furniture of the Tent,', pt: 'a saber: a tenda da revelação, a arca do testemunho, o propiciatório que estará sobre ela, e todos os móveis da tenda;' },
      { v: 8, en: 'the table and its vessels, the pure lamp stand with all its vessels, the altar of incense,', pt: 'a mesa com os seus utensílios, o candelabro de ouro puro com todos os seus utensílios, o altar do incenso,' },
      { v: 9, en: 'the altar of burnt offering with all its vessels, the basin and its base,', pt: 'o altar do holocausto com todos os seus utensílios, e a pia com a sua base;' },
      { v: 10, en: 'the finely worked garments—the holy garments for Aaron the priest—the garments of his sons to minister in the priest’s office,', pt: 'as vestes finamente tecidas, as vestes sagradas de Arão, o sacerdote, e as de seus filhos, para administrarem o sacerdócio;' },
      { v: 11, en: 'the anointing oil, and the incense of sweet spices for the holy place: according to all that I have commanded you they shall do.”', pt: 'o óleo da unção, e o incenso aromático para o lugar santo; eles farão conforme tudo o que te hei mandado.' },
      { v: 12, en: 'Yahweh spoke to Moses, saying,', pt: 'Disse mais o Senhor a Moisés:' },
      { v: 13, en: '“Speak also to the children of Israel, saying, ‘Most certainly you shall keep my Sabbaths: for it is a sign between me and you throughout your generations; that you may know that I am Yahweh who sanctifies you.', pt: 'Falarás também aos filhos de Israel, dizendo: Certamente guardareis os meus sábados; porquanto isso é um sinal entre mim e vós pelas vossas gerações; para que saibais que eu sou o Senhor, que vos santifica.' },
      { v: 14, en: 'You shall keep the Sabbath therefore; for it is holy to you. Everyone who profanes it shall surely be put to death; for whoever does any work therein, that soul shall be cut off from among his people.', pt: 'Portanto guardareis o sábado, porque santo é para vós; aquele que o profanar certamente será morto; porque qualquer que nele fizer algum trabalho, aquela alma será exterminada do meio do seu povo.' },
      { v: 15, en: 'Six days shall work be done, but on the seventh day is a Sabbath of solemn rest, holy to Yahweh. Whoever does any work on the Sabbath day shall surely be put to death.', pt: 'Seis dias se trabalhará, mas o sétimo dia será o sábado de descanso solene, santo ao Senhor; qualquer que no dia do sábado fizer algum trabalho, certamente será morto.' },
      { v: 16, en: 'Therefore the children of Israel shall keep the Sabbath, to observe the Sabbath throughout their generations, for a perpetual covenant.', pt: 'Guardarão, pois, o sábado os filhos de Israel, celebrando-o nas suas gerações como pacto perpétuo. ,' },
      { v: 17, en: 'It is a sign between me and the children of Israel forever; for in six days Yahweh made heaven and earth, and on the seventh day he rested, and was refreshed.’”', pt: 'Entre mim e os filhos de Israel será ele um sinal para sempre; porque em seis dias fez o Senhor o céu e a terra, e ao sétimo dia descansou, e achou refrigério.' },
      { v: 18, en: 'He gave to Moses, when he finished speaking with him on Mount Sinai, the two tablets of the testimony, stone tablets, written with God’s finger.', pt: 'E deu a Moisés, quando acabou de falar com ele no monte Sinai, as duas tábuas do testemunho, tábuas de pedra, escritas pelo dedo de Deus.' },
    ],
    32: [
      { v: 1, en: 'When the people saw that Moses delayed to come down from the mountain, the people gathered themselves together to Aaron, and said to him, “Come, make us gods, which shall go before us; for as for this Moses, the man who brought us up out of the land of Egypt, we don’t know what has become of him.”', pt: 'Mas o povo, vendo que Moisés tardava em descer do monte, acercou-se de Arão, e lhe disse: Levanta-te, faze-nos um deus que vá adiante de nós; porque, quanto a esse Moisés, o homem que nos tirou da terra do Egito, não sabemos o que lhe aconteceu.' },
      { v: 2, en: 'Aaron said to them, “Take off the golden rings, which are in the ears of your wives, of your sons, and of your daughters, and bring them to me.”', pt: 'E Arão lhes disse: Tirai os pendentes de ouro que estão nas orelhas de vossas mulheres, de vossos filhos e de vossas filhas, e trazei-mos.' },
      { v: 3, en: 'All the people took off the golden rings which were in their ears, and brought them to Aaron.', pt: 'Então todo o povo, tirando os pendentes de ouro que estavam nas suas orelhas, os trouxe a Arão;' },
      { v: 4, en: 'He received what they handed him, fashioned it with an engraving tool, and made it a molten calf. Then they said, “These are your gods, Israel, which brought you up out of the land of Egypt.”', pt: 'ele os recebeu de suas mãos, e com um buril deu forma ao ouro, e dele fez um bezerro de fundição. Então eles exclamaram: Eis aqui, ó Israel, o teu deus, que te tirou da terra do Egito.' },
      { v: 5, en: 'When Aaron saw this, he built an altar before it; and Aaron made a proclamation, and said, “Tomorrow shall be a feast to Yahweh.”', pt: 'E Arão, vendo isto, edificou um altar diante do bezerro e, fazendo uma proclamação, disse: Amanhã haverá festa ao Senhor.' },
      { v: 6, en: 'They rose up early on the next day, and offered burnt offerings, and brought peace offerings; and the people sat down to eat and to drink, and rose up to play.', pt: 'No dia seguinte levantaram-se cedo, ofereceram holocaustos, e trouxeram ofertas pacíficas; e o povo sentou-se a comer e a beber; depois levantou-se para folgar.' },
      { v: 7, en: 'Yahweh spoke to Moses, “Go, get down; for your people, who you brought up out of the land of Egypt, have corrupted themselves!', pt: 'Então disse o Senhor a Moisés: Vai, desce; porque o teu povo, que fizeste subir da terra do Egito, se corrompeu;' },
      { v: 8, en: 'They have turned away quickly out of the way which I commanded them. They have made themselves a molten calf, and have worshiped it, and have sacrificed to it, and said, ‘These are your gods, Israel, which brought you up out of the land of Egypt.’”', pt: 'depressa se desviou do caminho que eu lhe ordenei; eles fizeram para si um bezerro de fundição, e adoraram-no, e lhe ofereceram sacrifícios, e disseram: Eis aqui, ó Israel, o teu deus, que te tirou da terra do Egito.' },
      { v: 9, en: 'Yahweh said to Moses, “I have seen these people, and behold, they are a stiff-necked people.', pt: 'Disse mais o Senhor a Moisés: Tenho observado este povo, e eis que é povo de dura cerviz.' },
      { v: 10, en: 'Now therefore leave me alone, that my wrath may burn hot against them, and that I may consume them; and I will make of you a great nation.”', pt: 'Agora, pois, deixa-me, para que a minha ira se acenda contra eles, e eu os consuma; e eu farei de ti uma grande nação.' },
      { v: 11, en: 'Moses begged Yahweh his God, and said, “Yahweh, why does your wrath burn hot against your people, that you have brought out of the land of Egypt with great power and with a mighty hand?', pt: 'Moisés, porém, suplicou ao Senhor seu Deus, e disse: ç Senhor, por que se acende a tua ira contra o teu povo, que tiraste da terra do Egito com grande força e com forte mão?' },
      { v: 12, en: 'Why should the Egyptians speak, saying, ‘He brought them out for evil, to kill them in the mountains, and to consume them from the surface of the earth?’ Turn from your fierce wrath, and repent of this evil against your people.', pt: 'Por que hão de falar os egípcios, dizendo: Para mal os tirou, para matá-los nos montes, e para destruí-los da face da terra?. Torna-te da tua ardente ira, e arrepende-te deste mal contra o teu povo.' },
      { v: 13, en: 'Remember Abraham, Isaac, and Israel, your servants, to whom you swore by your own self, and said to them, ‘I will multiply your offspring as the stars of the sky, and all this land that I have spoken of I will give to your offspring, and they shall inherit it forever.’”', pt: 'Lembra-te de Abraão, de Isaque, e de Israel, teus servos, aos quais por ti mesmo juraste, e lhes disseste: Multiplicarei os vossos descendentes como as estrelas do céu, e lhes darei toda esta terra de que tenho falado, e eles a possuirão por herança para sempre.' },
      { v: 14, en: 'Yahweh repented of the evil which he said he would do to his people.', pt: 'Então o Senhor se arrependeu do mal que dissera que havia de fazer ao seu povo.' },
      { v: 15, en: 'Moses turned, and went down from the mountain, with the two tablets of the testimony in his hand; tablets that were written on both their sides; on the one side and on the other they were written.', pt: 'E virou-se Moisés, e desceu do monte com as duas tábuas do testemunho na mão, tábuas escritas de ambos os lados; de um e de outro lado estavam escritas.' },
      { v: 16, en: 'The tablets were the work of God, and the writing was the writing of God, engraved on the tablets.', pt: 'E aquelas tábuas eram obra de Deus; também a escritura era a mesma escritura de Deus, esculpida nas tábuas.' },
      { v: 17, en: 'When Joshua heard the noise of the people as they shouted, he said to Moses, “There is the noise of war in the camp.”', pt: 'Ora, ouvindo Josué a voz do povo que jubilava, disse a Moisés: Alarido de guerra há no arraial.' },
      { v: 18, en: 'He said, “It isn’t the voice of those who shout for victory. It is not the voice of those who cry for being overcome; but the noise of those who sing that I hear.”', pt: 'Respondeu-lhe Moisés: Não é alarido dos vitoriosos, nem alarido dos vencidos, mas é a voz dos que cantam que eu ouço.' },
      { v: 19, en: 'As soon as he came near to the camp, he saw the calf and the dancing. Then Moses’ anger grew hot, and he threw the tablets out of his hands, and broke them beneath the mountain.', pt: 'Chegando ele ao arraial e vendo o bezerro e as danças, acendeu-se-lhe a ira, e ele arremessou das mãos as tábuas, e as despedaçou ao pé do monte.' },
      { v: 20, en: 'He took the calf which they had made, and burned it with fire, ground it to powder, and scattered it on the water, and made the children of Israel drink it.', pt: 'Então tomou o bezerro que tinham feito, e queimou-o no fogo; e, moendo-o até que se tornou em pó, o espargiu sobre a água, e deu-o a beber aos filhos de Israel.' },
      { v: 21, en: 'Moses said to Aaron, “What did these people do to you, that you have brought a great sin on them?”', pt: 'E perguntou Moisés a Arão: Que te fez este povo, que sobre ele trouxeste tamanho pecado?.' },
      { v: 22, en: 'Aaron said, “Don’t let the anger of my lord grow hot. You know the people, that they are set on evil.', pt: 'Ao que respondeu Arão: Não se acenda a ira do meu senhor; tu conheces o povo, como ele é inclinado ao mal.' },
      { v: 23, en: 'For they said to me, ‘Make us gods, which shall go before us. As for this Moses, the man who brought us up out of the land of Egypt, we don’t know what has become of him.’', pt: 'Pois eles me disseram: Faze-nos um deus que vá adiante de nós; porque, quanto a esse Moisés, o homem que nos tirou da terra do Egito, não sabemos o que lhe aconteceu.' },
      { v: 24, en: 'I said to them, ‘Whoever has any gold, let them take it off:’ so they gave it to me; and I threw it into the fire, and out came this calf.”', pt: 'Então eu lhes disse: Quem tem ouro, arranque-o. Assim mo deram; e eu o lancei no fogo, e saiu este bezerro.' },
      { v: 25, en: 'When Moses saw that the people had broken loose, (for Aaron had let them loose for a derision among their enemies),', pt: 'Quando, pois, Moisés viu que o povo estava desenfreado (porque Arão o havia desenfreado, para escárnio entre os seus inimigos),' },
      { v: 26, en: 'then Moses stood in the gate of the camp, and said, “Whoever is on Yahweh’s side, come to me!” All the sons of Levi gathered themselves together to him.', pt: 'pôs-se em pé à entrada do arraial, e disse: Quem está ao lado do Senhor, venha a mim. Ao que se ajuntaram a ele todos os filhos de Levi.' },
      { v: 27, en: 'He said to them, “Yahweh says, the God of Israel, ‘Every man put his sword on his thigh, and go back and forth from gate to gate throughout the camp, and every man kill his brother, and every man his companion, and every man his neighbor.’”', pt: 'Então ele lhes disse: Assim diz o Senhor, o Deus de Israel: Cada um ponha a sua espada sobre a coxa; e passai e tornai pelo arraial de porta em porta, e mate cada um a seu irmão, e cada um a seu amigo, e cada um a seu vizinho.' },
      { v: 28, en: 'The sons of Levi did according to the word of Moses: and there fell of the people that day about three thousand men.', pt: 'E os filhos de Levi fizeram conforme a palavra de Moisés; e caíram do povo naquele dia cerca de três mil homens.' },
      { v: 29, en: 'Moses said, “Consecrate yourselves today to Yahweh, yes, every man against his son, and against his brother; that he may give you a blessing today.”', pt: 'Porquanto Moisés tinha dito: Consagrai-vos hoje ao Senhor; porque cada um será contra o seu filho, e contra o seu irmão; para que o Senhor vos conceda hoje uma bênção.' },
      { v: 30, en: 'On the next day, Moses said to the people, “You have sinned a great sin. Now I will go up to Yahweh. Perhaps I shall make atonement for your sin.”', pt: 'No dia seguinte disse Moisés ao povo Vós tendes cometido grande pecado; agora porém subirei ao Senhor; porventura farei expiação por vosso pecado.' },
      { v: 31, en: 'Moses returned to Yahweh, and said, “Oh, this people have sinned a great sin, and have made themselves gods of gold.', pt: 'Assim tornou Moisés ao Senhor, e disse: Oh! este povo cometeu um grande pecado, fazendo para si um deus de ouro.' },
      { v: 32, en: 'Yet now, if you will, forgive their sin—and if not, please blot me out of your book which you have written.”', pt: 'Agora, pois, perdoa o seu pecado; ou se não, risca-me do teu livro, que tens escrito.' },
      { v: 33, en: 'Yahweh said to Moses, “Whoever has sinned against me, him will I blot out of my book.', pt: 'Então disse o Senhor a Moisés: Aquele que tiver pecado contra mim, a este riscarei do meu livro.' },
      { v: 34, en: 'Now go, lead the people to the place of which I have spoken to you. Behold, my angel shall go before you. Nevertheless in the day when I punish, I will punish them for their sin.”', pt: 'Vai pois agora, conduze este povo para o lugar de que te hei dito; eis que o meu anjo irá adiante de ti; porém no dia da minha visitação, sobre eles visitarei o seu pecado.' },
      { v: 35, en: 'Yahweh struck the people, because they made the calf, which Aaron made.', pt: 'Feriu, pois, o Senhor ao povo, por ter feito o bezerro que Arão formara.' },
    ],
    33: [
      { v: 1, en: 'Yahweh spoke to Moses, “Depart, go up from here, you and the people that you have brought up out of the land of Egypt, to the land of which I swore to Abraham, to Isaac, and to Jacob, saying, ‘I will give it to your offspring. ’', pt: 'Disse mais o Senhor a Moisés: Vai, sobe daqui, tu e o povo que fizeste subir da terra do Egito, para a terra a respeito da qual jurei a Abraão, a Isaque, e a Jacó, dizendo: ë tua descendência a darei.' },
      { v: 2, en: 'I will send an angel before you; and I will drive out the Canaanite, the Amorite, and the Hittite, and the Perizzite, the Hivite, and the Jebusite:', pt: 'E enviarei um anjo adiante de ti (e lançarei fora os cananeus, e os amorreus, e os heteus, e os perizeus, e os heveus, e os jebuseus),' },
      { v: 3, en: 'to a land flowing with milk and honey: for I will not go up among you, for you are a stiff-necked people, lest I consume you on the way.”', pt: 'para uma terra que mana leite e mel; porque eu não subirei no meio de ti, porquanto és povo de cerviz dura; para que não te consuma eu no caminho.' },
      { v: 4, en: 'When the people heard this evil news, they mourned: and no one put on his jewelry.', pt: 'E quando o povo ouviu esta má notícia, pôs-se a prantear, e nenhum deles vestiu os seus atavios.' },
      { v: 5, en: 'Yahweh said to Moses, “Tell the children of Israel, ‘You are a stiff-necked people. If I were to go up among you for one moment, I would consume you. Therefore now take off your jewelry from you, that I may know what to do to you.’”', pt: 'Pois o Senhor tinha dito a Moisés: Dize aos filhos de Israel: És um povo de dura cerviz; se por um só momento eu subir no meio de ti, te consumirei; portanto agora despe os teus atavios, para que eu saiba o que te hei de fazer.' },
      { v: 6, en: 'The children of Israel stripped themselves of their jewelry from Mount Horeb onward.', pt: 'Então os filhos de Israel se despojaram dos seus atavios, desde o monte Horebe em diante.' },
      { v: 7, en: 'Now Moses used to take the tent and pitch it outside the camp, far away from the camp, and he called it “The Tent of Meeting.” Everyone who sought Yahweh went out to the Tent of Meeting, which was outside the camp.', pt: 'Ora, Moisés costumava tomar a tenda e armá-la fora do arraial, bem longe do arraial; e chamou-lhe a tenda da revelação. E todo aquele que buscava ao Senhor saía à tenda da revelação, que estava fora do arraial.' },
      { v: 8, en: 'When Moses went out to the Tent, all the people rose up, and stood, everyone at their tent door, and watched Moses, until he had gone into the Tent.', pt: 'Quando Moisés saía à tenda, levantava-se todo o povo e ficava em pé cada um à porta da sua tenda, e olhava a Moisés pelas costas, até entrar ele na tenda.' },
      { v: 9, en: 'When Moses entered into the Tent, the pillar of cloud descended, stood at the door of the Tent, and spoke with Moses.', pt: 'E quando Moisés entrava na tenda, a coluna de nuvem descia e ficava à porta da tenda; e o Senhor falava com Moisés.' },
      { v: 10, en: 'All the people saw the pillar of cloud stand at the door of the Tent, and all the people rose up and worshiped, everyone at their tent door.', pt: 'Assim via todo o povo a coluna de nuvem que estava à porta da tenda, e todo o povo, levantando-se, adorava, cada um à porta da sua tenda.' },
      { v: 11, en: 'Yahweh spoke to Moses face to face, as a man speaks to his friend. He turned again into the camp, but his servant Joshua, the son of Nun, a young man, didn’t depart from the Tent.', pt: 'E falava o Senhor a Moisés face a face, como qualquer fala com o seu amigo. Depois tornava Moisés ao arraial; mas o seu servidor, o mancebo Josué, filho de Num, não se apartava da tenda.' },
      { v: 12, en: 'Moses said to Yahweh, “Behold, you tell me, ‘Bring up this people:’ and you haven’t let me know whom you will send with me. Yet you have said, ‘I know you by name, and you have also found favor in my sight.’', pt: 'E Moisés disse ao Senhor: Eis que tu me dizes: Faze subir a este povo; porém não me fazes saber a quem hás de enviar comigo. Disseste também: Conheço-te por teu nome, e achaste graça aos meus olhos.' },
      { v: 13, en: 'Now therefore, if I have found favor in your sight, please show me now your way, that I may know you, so that I may find favor in your sight: and consider that this nation is your people.”', pt: 'Se eu, pois, tenho achado graça aos teus olhos, rogo-te que agora me mostres os teus caminhos, para que eu te conheça, a fim de que ache graça aos teus olhos; e considera que esta nação é teu povo.' },
      { v: 14, en: 'He said, “My presence will go with you, and I will give you rest.”', pt: 'Respondeu-lhe o Senhor: Eu mesmo irei contigo, e eu te darei descanso.' },
      { v: 15, en: 'He said to him, “If your presence doesn’t go with me, don’t carry us up from here.', pt: 'Então Moisés lhe disse: Se tu mesmo não fores conosco, não nos faças subir daqui.' },
      { v: 16, en: 'For how would people know that I have found favor in your sight, I and your people? Isn’t it that you go with us, so that we are separated, I and your people, from all the people who are on the surface of the earth?”', pt: 'Como, pois, se saberá agora que tenho achado graça aos teus olhos, eu e o teu povo? acaso não é por andares tu conosco, de modo a sermos separados, eu e o teu povo, de todos os povos que há sobre a face da terra;' },
      { v: 17, en: 'Yahweh said to Moses, “I will do this thing also that you have spoken; for you have found favor in my sight, and I know you by name.”', pt: 'Ao que disse o Senhor a Moisés: Farei também isto que tens dito; porquanto achaste graça aos meus olhos, e te conheço pelo teu nome.' },
      { v: 18, en: 'He said, “Please show me your glory.”', pt: 'Moisés disse ainda: Rogo-te que me mostres a tua glória.' },
      { v: 19, en: 'He said, “I will make all my goodness pass before you, and will proclaim Yahweh’s name before you. I will be gracious to whom I will be gracious, and will show mercy on whom I will show mercy.”', pt: 'Respondeu-lhe o Senhor: Eu farei passar toda a minha bondade diante de ti, e te proclamarei o meu nome Jeová; e terei misericórdia de quem eu tiver misericórdia, e me compadecerei de quem me compadecer.' },
      { v: 20, en: 'He said, “You cannot see my face, for man may not see me and live.”', pt: 'E disse mais: Não poderás ver a minha face, porquanto homem nenhum pode ver a minha face e viver.' },
      { v: 21, en: 'Yahweh also said, “Behold, there is a place by me, and you shall stand on the rock.', pt: 'Disse mais o Senhor: Eis aqui um lugar junto a mim; aqui, sobre a penha, te poras.' },
      { v: 22, en: 'It will happen, while my glory passes by, that I will put you in a cleft of the rock, and will cover you with my hand until I have passed by;', pt: 'E quando a minha glória passar, eu te porei numa fenda da penha, e te cobrirei com a minha mão, até que eu haja passado.' },
      { v: 23, en: 'then I will take away my hand, and you will see my back; but my face shall not be seen.”', pt: 'Depois, quando eu tirar a mão, me verás pelas costas; porém a minha face não se verá.' },
    ],
    34: [
      { v: 1, en: 'Yahweh said to Moses, “Chisel two stone tablets like the first. I will write on the tablets the words that were on the first tablets, which you broke.', pt: 'Então disse o Senhor a Moisés: Lavra duas tábuas de pedra, como as primeiras; e eu escreverei nelas as palavras que estavam nas primeiras tábuas, que tu quebraste.' },
      { v: 2, en: 'Be ready by the morning, and come up in the morning to Mount Sinai, and present yourself there to me on the top of the mountain.', pt: 'Prepara-te para amanhã, e pela manhã sobe ao monte Sinai, e apresenta-te a mim ali no cume do monte.' },
      { v: 3, en: 'No one shall come up with you or be seen anywhere on the mountain. Do not let the flocks or herds graze in front of that mountain.”', pt: 'Mas ninguém suba contigo, nem apareça homem algum em todo o monte; nem mesmo se apascentem defronte dele ovelhas ou bois.' },
      { v: 4, en: 'He chiseled two tablets of stone like the first; and Moses rose up early in the morning, and went up to Mount Sinai, as Yahweh had commanded him, and took in his hand two stone tablets.', pt: 'Então Moisés lavrou duas tábuas de pedra, como as primeiras; e, levantando-se de madrugada, subiu ao monte Sinai, como o Senhor lhe tinha ordenado, levando na mão as duas tábuas de pedra.' },
      { v: 5, en: 'Yahweh descended in the cloud, and stood with him there, and proclaimed Yahweh’s name.', pt: 'O Senhor desceu numa nuvem e, pondo-se ali junto a ele, proclamou o nome Jeová.' },
      { v: 6, en: 'Yahweh passed by before him, and proclaimed, “Yahweh! Yahweh, a merciful and gracious God, slow to anger, and abundant in loving kindness and truth,', pt: 'Tendo o Senhor passado perante Moisés, proclamou: Jeovã, Jeová, Deus misericordioso e compassivo, tardio em irar-se e grande em beneficência e verdade;' },
      { v: 7, en: 'keeping loving kindness for thousands, forgiving iniquity and disobedience and sin; and who will by no means clear the guilty, visiting the iniquity of the fathers on the children, and on the children’s children, on the third and on the fourth generation.”', pt: 'que usa de beneficência com milhares; que perdoa a iniqüidade, a transgressão e o pecado; que de maneira alguma terá por inocente o culpado; que visita a iniqüidade dos pais sobre os filhos e sobre os filhos dos filhos até a terceira e quarta geração.' },
      { v: 8, en: 'Moses hurried and bowed his head toward the earth, and worshiped.', pt: 'Então Moisés se apressou a inclinar-se à terra, e adorou,' },
      { v: 9, en: 'He said, “If now I have found favor in your sight, Lord, please let the Lord go among us; although this is a stiff-necked people; pardon our iniquity and our sin, and take us for your inheritance.”', pt: 'dizendo: Senhor, se agora tenho achado graça aos teus olhos, vá o Senhor no meio de nós; porque este é povo de dura cerviz:; e perdoa a nossa iniqüidade e o nosso pecado, e toma-nos por tua herança.' },
      { v: 10, en: 'He said, “Behold, I make a covenant: before all your people I will do marvels, such as have not been worked in all the earth, nor in any nation; and all the people among which you are shall see the work of Yahweh; for it is an awesome thing that I do with you.', pt: 'Então disse o Senhor: Eis que eu faço um pacto; farei diante de todo o teu povo maravilhas quais nunca foram feitas em toda a terra, nem dentro de nação alguma; e todo este povo, no meio do qual estás, verá a obra do Senhor; porque coisa terrível é o que faço contigo.' },
      { v: 11, en: 'Observe that which I command you today. Behold, I drive out before you the Amorite, the Canaanite, the Hittite, the Perizzite, the Hivite, and the Jebusite.', pt: 'Guarda o que eu te ordeno hoje: eis que eu lançarei fora de diante de ti os amorreus, os cananeus, os heteus, os perizeus, os heveus e os jebuseus.' },
      { v: 12, en: 'Be careful, lest you make a covenant with the inhabitants of the land where you are going, lest it be for a snare among you:', pt: 'Guarda-te de fazeres pacto com os habitantes da terra em que hás de entrar, para que isso não seja por laço no meio de ti.' },
      { v: 13, en: 'but you shall break down their altars, and dash in pieces their pillars, and you shall cut down their Asherah poles;', pt: 'Mas os seus altares derrubareis, e as suas colunas quebrareis, e os seus aserins cortareis' },
      { v: 14, en: 'for you shall worship no other god: for Yahweh, whose name is Jealous, is a jealous God.', pt: '(porque não adorarãs a nenhum outro deus; pois o Senhor, cujo nome é Zeloso, é Deus zeloso),' },
      { v: 15, en: '“Don’t make a covenant with the inhabitants of the land, lest they play the prostitute after their gods, and sacrifice to their gods, and one call you and you eat of his sacrifice;', pt: 'para que não faças pacto com os habitantes da terra, a fim de que quando se prostituirem após os seus deuses, e sacrificarem aos seus deuses, tu não sejas convidado por eles, e não comas do seu sacrifício;' },
      { v: 16, en: 'and you take of their daughters to your sons, and their daughters play the prostitute after their gods, and make your sons play the prostitute after their gods.', pt: 'e não tomes mulheres das suas filhas para os teus filhos, para que quando suas filhas se prostituírem após os seus deuses, não façam que também teus filhos se prostituam após os seus deuses.' },
      { v: 17, en: '“You shall make no cast idols for yourselves.', pt: 'Não farás para ti deuses de fundição.' },
      { v: 18, en: '“You shall keep the feast of unleavened bread. Seven days you shall eat unleavened bread, as I commanded you, at the time appointed in the month Abib; for in the month Abib you came out of Egypt.', pt: 'A festa dos pães ázimos guardarás; sete dias comerás pães ázimos, como te ordenei, ao tempo apontado no mês de abibe; porque foi no mês de abibe que saíste do Egito.' },
      { v: 19, en: '“All that opens the womb is mine; and all your livestock that is male, the firstborn of cow and sheep.', pt: 'Tudo o que abre a madre é meu; até todo o teu gado, que seja macho, que abre a madre de vacas ou de ovelhas;' },
      { v: 20, en: 'You shall redeem the firstborn of a donkey with a lamb. If you will not redeem it, then you shall break its neck. You shall redeem all the firstborn of your sons. No one shall appear before me empty.', pt: 'o jumento, porém, que abrir a madre, resgatarás com um cordeiro; mas se não quiseres resgatá-lo, quebrar-lhe-ás a cerviz. Resgatarás todos os primogênitos de teus filhos. E ninguém aparecerá diante de mim com as mãos vazias.' },
      { v: 21, en: '“Six days you shall work, but on the seventh day you shall rest: in plowing time and in harvest you shall rest.', pt: 'Seis dias trabalharás, mas ao sétimo dia descansarás; na aradura e na sega descansarás.' },
      { v: 22, en: '“You shall observe the feast of weeks with the first fruits of wheat harvest, and the feast of harvest at the year’s end.', pt: 'Também guardarás a festa das semanas, que é a festa das primícias da ceifa do trigo, e a festa da colheita no fim do ano.' },
      { v: 23, en: 'Three times in the year all your males shall appear before the Lord Yahweh, the God of Israel.', pt: 'Três vezes no ano todos os teus varões aparecerão perante o Senhor Jeová, Deus do Israel;' },
      { v: 24, en: 'For I will drive out nations before you and enlarge your borders; neither shall any man desire your land when you go up to appear before Yahweh, your God, three times in the year.', pt: 'porque eu lançarei fora as nações de diante de ti, e alargarei as tuas fronteiras; ninguém cobiçará a tua terra, quando subires para aparecer três vezes no ano diante do Senhor teu Deus.' },
      { v: 25, en: '“You shall not offer the blood of my sacrifice with leavened bread. The sacrifice of the feast of the Passover shall not be left to the morning.', pt: 'Não sacrificarás o sangue do meu sacrifício com pão levedado, nem o sacrifício da festa da páscoa ficará da noite para a manhã.' },
      { v: 26, en: '“You shall bring the first of the first fruits of your ground to the house of Yahweh your God. “You shall not boil a young goat in its mother’s milk.”', pt: 'As primeiras das primícias da tua terra trarás à casa do Senhor teu Deus. Não cozerás o cabrito no leite de sua mãe.' },
      { v: 27, en: 'Yahweh said to Moses, “Write you these words: for in accordance with these words I have made a covenant with you and with Israel.”', pt: 'Disse mais o Senhor a Moisés: Escreve estas palavras; porque conforme o teor destas palavras tenho feito pacto contigo e com Israel.' },
      { v: 28, en: 'He was there with Yahweh forty days and forty nights; he neither ate bread, nor drank water. He wrote on the tablets the words of the covenant, the ten commandments.', pt: 'E Moisés esteve ali com o Senhor quarenta dias e quarenta noites; não comeu pão, nem bebeu água, e escreveu nas tábuas as palavras do pacto, os dez mandamentos.' },
      { v: 29, en: 'When Moses came down from Mount Sinai with the two tablets of the testimony in Moses’ hand, when he came down from the mountain, Moses didn’t know that the skin of his face shone by reason of his speaking with him.', pt: 'Quando Moisés desceu do monte Sinai, trazendo nas mãos as duas tsbuas do testemunho, sim, quando desceu do monte, Moisés não sabia que a pele do seu rosto resplandecia, por haver Deus falado com ele.' },
      { v: 30, en: 'When Aaron and all the children of Israel saw Moses, behold, the skin of his face shone; and they were afraid to come near him.', pt: 'Quando, pois, Arão e todos os filhos de Israel olharam para Moisés, eis que a pele do seu rosto resplandecia, pelo que tiveram medo de aproximar-se dele.' },
      { v: 31, en: 'Moses called to them, and Aaron and all the rulers of the congregation returned to him; and Moses spoke to them.', pt: 'Então Moisés os chamou, e Arão e todos os príncipes da congregação tornaram a ele; e Moisés lhes falou.' },
      { v: 32, en: 'Afterward all the children of Israel came near, and he gave them all the commandments that Yahweh had spoken with him on Mount Sinai.', pt: 'Depois chegaram também todos os filhos de Israel, e ele lhes ordenou tudo o que o Senhor lhe falara no monte Sinai.' },
      { v: 33, en: 'When Moses was done speaking with them, he put a veil on his face.', pt: 'Assim que Moisés acabou de falar com eles, pôs um véu sobre o rosto.' },
      { v: 34, en: 'But when Moses went in before Yahweh to speak with him, he took the veil off, until he came out; and he came out, and spoke to the children of Israel that which he was commanded.', pt: 'Mas, entrando Moisés perante o Senhor, para falar com ele, tirava o véu até sair; e saindo, dizia aos filhos de Israel o que lhe era ordenado.' },
      { v: 35, en: 'The children of Israel saw Moses’ face, that the skin of Moses’ face shone: and Moses put the veil on his face again, until he went in to speak with him.', pt: 'Assim, pois, viam os filhos de Israel o rosto de Moisés, e que a pele do seu rosto resplandecia; e tornava Moisés a pôr o véu sobre o seu rosto, até entrar para falar com Deus.' },
    ],
    35: [
      { v: 1, en: 'Moses assembled all the congregation of the children of Israel, and said to them, “These are the words which Yahweh has commanded, that you should do them.', pt: 'Então Moisés convocou toda a congregação dos filhos de Israel, e disse-lhes: Estas são as palavras que o Senhor ordenou que cumprísseis.' },
      { v: 2, en: '‘Six days shall work be done, but on the seventh day there shall be a holy day for you, a Sabbath of solemn rest to Yahweh: whoever does any work in it shall be put to death.', pt: 'Seis dias se trabalhará, mas o sétimo dia vos será santo, sábado de descanso solene ao Senhor; todo aquele que nele fizer qualquer trabalho será morto.' },
      { v: 3, en: 'You shall kindle no fire throughout your habitations on the Sabbath day.’”', pt: 'Não acendereis fogo em nenhuma das vossas moradas no dia do sábado.' },
      { v: 4, en: 'Moses spoke to all the congregation of the children of Israel, saying, “This is the thing which Yahweh commanded, saying,', pt: 'Disse mais Moisés a toda a congregação dos filhos de Israel: Esta é a palavra que o Senhor ordenou dizendo:' },
      { v: 5, en: '‘Take from among you an offering to Yahweh. Whoever is of a willing heart, let him bring it, Yahweh’s offering: gold, silver, brass,', pt: 'Tomai de entre vós uma oferta para o Senhor; cada um cujo coração é voluntariamente disposto a trará por oferta alçada ao Senhor: ouro, prata e bronze,' },
      { v: 6, en: 'blue, purple, scarlet, fine linen, goats’ hair,', pt: 'como também azul, púrpura, carmesim, linho fino, pelos de cabras,' },
      { v: 7, en: 'rams’ skins dyed red, sea cow hides, acacia wood,', pt: 'peles de carneiros tintas de vermelho, peles de golfinhos, madeira de acácia,' },
      { v: 8, en: 'oil for the light, spices for the anointing oil and for the sweet incense,', pt: 'azeite para a luz, especiarias para o óleo da unção e para o incenso aromático,' },
      { v: 9, en: 'onyx stones, and stones to be set for the ephod and for the breastplate.', pt: 'pedras de berilo e pedras de engaste para o éfode e para o peitoral.' },
      { v: 10, en: '“‘Let every wise-hearted man among you come, and make all that Yahweh has commanded:', pt: 'E venham todos os homens hábeis entre vós, e façam tudo o que o Senhor tem ordenado:' },
      { v: 11, en: 'the tabernacle, its outer covering, its roof, its clasps, its boards, its bars, its pillars, and its sockets;', pt: 'o tabernáculo, a sua tenda e a sua coberta, os seus colchetes e as suas tábuas, os seus travessões, as suas colunas e as suas bases;' },
      { v: 12, en: 'the ark, and its poles, the mercy seat, the veil of the screen;', pt: 'a arca e os seus varais, o propiciatório, e o véu e reposteiro;' },
      { v: 13, en: 'the table with its poles and all its vessels, and the show bread;', pt: 'a mesa e os seus varais, todos os seus utensílios, e os pães da proposição;' },
      { v: 14, en: 'the lamp stand also for the light, with its vessels, its lamps, and the oil for the light;', pt: 'o candelabro para a luz, os seus utensílios, as suas lâmpadas, e o azeite para a luz;' },
      { v: 15, en: 'and the altar of incense with its poles, the anointing oil, the sweet incense, the screen for the door, at the door of the tabernacle;', pt: 'o altar do incenso e os seus varais, o óleo da unção e o incenso aromático, e o reposteiro da porta para a entrada do tabernáculo;' },
      { v: 16, en: 'the altar of burnt offering, with its grating of brass, it poles, and all its vessels, the basin and its base;', pt: 'o altar do holocausto com o seu crivo de bronze, os seus varais, e todos os seus utensílios; a pia e a sua base;' },
      { v: 17, en: 'the hangings of the court, its pillars, their sockets, and the screen for the gate of the court;', pt: 'as cortinas do átrio, as suas colunas e as suas bases, o reposteiro para a porta do átrio;' },
      { v: 18, en: 'the pins of the tabernacle, the pins of the court, and their cords;', pt: 'as estacas do tabernáculo, as estacas do atrio, e as suas cordas;' },
      { v: 19, en: 'the finely worked garments, for ministering in the holy place, the holy garments for Aaron the priest, and the garments of his sons, to minister in the priest’s office.’”', pt: 'as vestes finamente tecidas, para o uso no ministério no lugar santo, as vestes sagradas de Arão, o sacerdote, e as vestes de seus filhos, para administrarem o sacerdócio.' },
      { v: 20, en: 'All the congregation of the children of Israel departed from the presence of Moses.', pt: 'Então toda a congregação dos filhos de Israel saiu da presença de Moisés.' },
      { v: 21, en: 'They came, everyone whose heart stirred him up, and everyone whom his spirit made willing, and brought Yahweh’s offering, for the work of the Tent of Meeting, and for all of its service, and for the holy garments.', pt: 'E veio todo homem cujo coração o moveu, e todo aquele cujo espírito o estimulava, e trouxeram a oferta alçada do Senhor para a obra da tenda da revelação, e para todo o serviço dela, e para as vestes sagradas.' },
      { v: 22, en: 'They came, both men and women, as many as were willing-hearted, and brought brooches, earrings, signet rings, and armlets, all jewels of gold; even every man who offered an offering of gold to Yahweh.', pt: 'Vieram, tanto homens como mulheres, todos quantos eram bem dispostos de coração, trazendo broches, pendentes, anéis e braceletes, sendo todos estes jóias de ouro; assim veio todo aquele que queria fazer oferta de ouro ao Senhor.' },
      { v: 23, en: 'Everyone, with whom was found blue, purple, scarlet, fine linen, goats’ hair, rams’ skins dyed red, and sea cow hides, brought them.', pt: 'E todo homem que possuía azul, púrpura, carmesim, linho fino, pelos de cabras, peles de carneiros tintas de vermelho, ou peles de golfinhos, os trazia.' },
      { v: 24, en: 'Everyone who offered an offering of silver and brass brought Yahweh’s offering; and everyone, with whom was found acacia wood for any work of the service, brought it.', pt: 'Todo aquele que tinha prata ou metal para oferecer, o trazia por oferta alçada ao Senhor; e todo aquele que possuía madeira de acácia, a trazia para qualquer obra do serviço.' },
      { v: 25, en: 'All the women who were wise-hearted spun with their hands, and brought that which they had spun, the blue, the purple, the scarlet, and the fine linen.', pt: 'E todas as mulheres hábeis fiavam com as mãos, e traziam o que tinham fiado, o azul e a púrpura, o carmesim e o linho fino.' },
      { v: 26, en: 'All the women whose heart stirred them up in wisdom spun the goats’ hair.', pt: 'E todas as mulheres hàbeis que quisessem fiavam os pelos das cabras.' },
      { v: 27, en: 'The rulers brought the onyx stones and the stones to be set for the ephod and for the breastplate;', pt: 'Os príncipes traziam pedras de berilo e pedras de engaste para o éfode e para o peitoral,' },
      { v: 28, en: 'with the spice and the oil for the light, for the anointing oil, and for the sweet incense.', pt: 'e as especiarias e o azeite para a luz, para o óleo da unção e para o incenso aromático.' },
      { v: 29, en: 'The children of Israel brought a freewill offering to Yahweh; every man and woman, whose heart made them willing to bring for all the work, which Yahweh had commanded to be made by Moses.', pt: 'Trouxe uma oferta todo homem e mulher cujo coração voluntariamente se moveu a trazer alguma coisa para toda a obra que o senhor ordenara se fizesse por intermédio de Moisés; assim trouxeram os filhos de Israel uma oferta voluntária ao Senhor.' },
      { v: 30, en: 'Moses said to the children of Israel, “Behold, Yahweh has called by name Bezalel the son of Uri, the son of Hur, of the tribe of Judah.', pt: 'Depois disse Moisés aos filhos de Israel: Eis que o Senhor chamou por nome a Bezaleel, filho de îri, filho de Hur, da tribo de Judá,' },
      { v: 31, en: 'He has filled him with the Spirit of God, in wisdom, in understanding, in knowledge, and in all kinds of workmanship;', pt: 'e o encheu do espírito de Deus, no tocante à sabedoria, ao entendimento, à ciência e a todo ofício,' },
      { v: 32, en: 'and to make skillful works, to work in gold, in silver, in brass,', pt: 'para inventar obras artísticas, para trabalhar em ouro, em prata e em bronze,' },
      { v: 33, en: 'in cutting of stones for setting, and in carving of wood, to work in all kinds of skillful workmanship.', pt: 'em lavramento de pedras para engastar, em entalhadura de madeira, enfim, para trabalhar em toda obra fina.' },
      { v: 34, en: 'He has put in his heart that he may teach, both he, and Oholiab, the son of Ahisamach, of the tribe of Dan.', pt: 'Também lhe dispôs o coração para ensinar a outros; a ele e a Aoliabe, filho de Aisamaque, da tribo de Dã,' },
      { v: 35, en: 'He has filled them with wisdom of heart, to work all kinds of workmanship, of the engraver, of the skillful workman, and of the embroiderer, in blue, in purple, in scarlet, and in fine linen, and of the weaver, even of those who do any workmanship, and of those who make skillful works.', pt: 'a estes encheu de sabedoria do coração para exercerem todo ofício, seja de gravador, de desenhista, de bordador em azul, púrpura, carmesim e linho fino, de tecelão, enfim, dos que exercem qualquer ofício e dos que inventam obras artísticas.' },
    ],
    36: [
      { v: 1, en: '“Bezalel and Oholiab shall work with every wise-hearted man, in whom Yahweh has put wisdom and understanding to know how to do all the work for the service of the sanctuary, according to all that Yahweh has commanded.”', pt: 'Assim trabalharão Bezaleel e Aoliabe, e todo homem hábil, a quem o Senhor deu sabedoria e entendimento, para saberem exercer todo ofício para o serviço do santuário, conforme tudo o que o Senhor tem ordenado.' },
      { v: 2, en: 'Moses called Bezalel and Oholiab, and every wise-hearted man, in whose heart Yahweh had put wisdom, even everyone whose heart stirred him up to come to the work to do it:', pt: 'Então Moisés chamou a Bezaleel e a Aoliabe, e a todo homem hábil, em cujo coração Deus tinha posto sabedoria, isto é, a todo aquele cujo coração o moveu a se chegar à obra para fazê-la;' },
      { v: 3, en: 'and they received from Moses all the offering which the children of Israel had brought for the work of the service of the sanctuary, with which to make it. They brought yet to him freewill offerings every morning.', pt: 'e receberam de Moisés toda a oferta alçada, que os filhos de Israel tinham do para a obra do serviço do santuário, para fazê-la; e ainda eles lhe traziam cada manhã ofertas voluntárias.' },
      { v: 4, en: 'All the wise men, who performed all the work of the sanctuary, each came from his work which they did.', pt: 'Então todos os sábios que faziam toda a obra do santuário vieram, cada um da obra que fazia,' },
      { v: 5, en: 'They spoke to Moses, saying, “The people bring much more than enough for the service of the work which Yahweh commanded to make.”', pt: 'e disseram a Moisés: O povo traz muito mais do que é necessário para o serviço da obra que o Senhor ordenou se fizesse.' },
      { v: 6, en: 'Moses gave commandment, and they caused it to be proclaimed throughout the camp, saying, “Let neither man nor woman make anything else for the offering for the sanctuary.” So the people were restrained from bringing.', pt: 'Pelo que Moisés deu ordem, a qual fizeram proclamar por todo o arraial, dizendo: Nenhum homem, nem mulher, faça mais obra alguma para a oferta alçada do santuário. Assim o povo foi proibido de trazer mais.' },
      { v: 7, en: 'For the stuff they had was sufficient for all the work to make it, and too much.', pt: 'Porque o material que tinham era bastante para toda a obra, e ainda sobejava.' },
      { v: 8, en: 'All the wise-hearted men among those who did the work made the tabernacle with ten curtains; of fine twined linen, blue, purple, and scarlet, with cherubim, the work of the skillful workman, they made them.', pt: 'Assim todos os homens hábeis, dentre os que trabalhavam na obra, fizeram o tabernáculo de dez cortinas de linho fino torcido, de azul, de púrpura e de carmesim, com querubins, obra de artífice.' },
      { v: 9, en: 'The length of each curtain was twenty-eight cubits, and the width of each curtain four cubits. All the curtains had one measure.', pt: 'O comprimento de cada cortina era de vinte e oito côvados, e a largura de quatro côvados; todas as cortinas eram da mesma medida.' },
      { v: 10, en: 'He coupled five curtains to one another, and the other five curtains he coupled to one another.', pt: 'Ligaram cinco cortinas uma com outra; e as outras cinco da mesma maneira.' },
      { v: 11, en: 'He made loops of blue on the edge of the one curtain from the edge in the coupling. Likewise he made in the edge of the curtain that was outermost in the second coupling.', pt: 'Fizeram laçadas de azul na orla da última cortina do primeiro grupo; assim, também fizeram na orla da primeira cortina do segundo grupo.' },
      { v: 12, en: 'He made fifty loops in the one curtain, and he made fifty loops in the edge of the curtain that was in the second coupling. The loops were opposite to one another.', pt: 'Cinqüenta laçadas fizeram na orla de uma cortina, e cinquenta laçadas na orla da outra, do segundo grupo; as laçadas eram contrapostas uma à outra.' },
      { v: 13, en: 'He made fifty clasps of gold, and coupled the curtains to one another with the clasps: so the tabernacle was a unit.', pt: 'Também fizeram cinqüenta colchetes de ouro, e com estes colchetes uniram as cortinas, uma com outra; e o tabernáculo veio a ser um todo.' },
      { v: 14, en: 'He made curtains of goats’ hair for a covering over the tabernacle. He made them eleven curtains.', pt: 'Fizeram também cortinas de pelos de cabras para servirem de tenda sobre o tabernáculo; onze cortinas fizeram.' },
      { v: 15, en: 'The length of each curtain was thirty cubits, and four cubits the width of each curtain. The eleven curtains had one measure.', pt: 'O comprimento de cada cortina era de trinta côvados, e a largura de quatro côvados; as onze cortinas eram da mesma medida.' },
      { v: 16, en: 'He coupled five curtains by themselves, and six curtains by themselves.', pt: 'uniram cinco destas cortinas à parte, e as outras seis à parte.' },
      { v: 17, en: 'He made fifty loops on the edge of the curtain that was outermost in the coupling, and he made fifty loops on the edge of the curtain which was outermost in the second coupling.', pt: 'Fizeram cinqüenta laçadas na orla da última cortina do primeiro grupo, e cinqüenta laçadas na orla da primeira cortina do segundo grupo.' },
      { v: 18, en: 'He made fifty clasps of brass to couple the tent together, that it might be a unit.', pt: 'Fizeram também cinqüenta colchetes de bronze, para ajuntar a tenda, para que viesse a ser um todo.' },
      { v: 19, en: 'He made a covering for the tent of rams’ skins dyed red, and a covering of sea cow hides above.', pt: 'Fizeram para a tenda uma cobertura de peles de carneiros tintas de vermelho, e por cima desta uma cobertura de peles de golfinhos.' },
      { v: 20, en: 'He made the boards for the tabernacle of acacia wood, standing up.', pt: 'Também fizeram, de madeira de acácia, as tábuas para o tabernáculo, as quais foram colocadas verticalmente.' },
      { v: 21, en: 'Ten cubits was the length of a board, and a cubit and a half the width of each board.', pt: 'O comprimento de cada tábua era de dez côvados, e a largura de um côvado e meio.' },
      { v: 22, en: 'Each board had two tenons, joined to one another. He made all the boards of the tabernacle this way.', pt: 'Cada tábua tinha duas couceiras, unidas uma à outra; assim fizeram com todas as tábuas do tabernáculo.' },
      { v: 23, en: 'He made the boards for the tabernacle: twenty boards for the south side southward.', pt: 'Assim, pois, fizeram as tábuas para o tabernáculo; vinte tábuas para o lado que dá para o sul;' },
      { v: 24, en: 'He made forty sockets of silver under the twenty boards; two sockets under one board for its two tenons, and two sockets under another board for its two tenons.', pt: 'e fizeram quarenta bases de prata para se pôr debaixo das vinte tábuas: duas bases debaixo de uma tábua para as suas duas couceiras, e duas debaixo de outra, para as duas couceiras dela.' },
      { v: 25, en: 'For the second side of the tabernacle, on the north side, he made twenty boards,', pt: 'Também para o segundo lado do tabernáculo, o que dá para o norte, fizeram vinte tábuas,' },
      { v: 26, en: 'and their forty sockets of silver; two sockets under one board, and two sockets under another board.', pt: 'com as suas quarenta bases de prata, duas bases debaixo de uma tábua, e duas bases debaixo de outra.' },
      { v: 27, en: 'For the far part of the tabernacle westward he made six boards.', pt: 'Para o lado posterior do tabernáculo, o que dá para o ocidente, fizeram seis tábuas.' },
      { v: 28, en: 'He made two boards for the corners of the tabernacle in the far part.', pt: 'E para os dois cantos do tabernáculo no lado posterior, fizeram mais duas tábuas.' },
      { v: 29, en: 'They were double beneath, and in the same way they were all the way to its top to one ring. He did this to both of them in the two corners.', pt: 'Por baixo eram duplas, do mesmo modo se estendendo até a primeira argola, em cima; assim fizeram com as duas tábuas nos dois cantos.' },
      { v: 30, en: 'There were eight boards, and their sockets of silver, sixteen sockets; under every board two sockets.', pt: 'Assim havia oito tábuas com as suas bases de prata, a saber, dezesseis bases, duas debaixo de cada tábua.' },
      { v: 31, en: 'He made bars of acacia wood; five for the boards of the one side of the tabernacle,', pt: 'Fizeram também travessões de madeira de acácia: cinco travessões para as tábuas de um lado do tabernáculo,' },
      { v: 32, en: 'and five bars for the boards of the other side of the tabernacle, and five bars for the boards of the tabernacle for the hinder part westward.', pt: 'e cinco para as tábuas do outro lado do tabernáculo, e outros cinco para as tábuas do tabernáculo no lado posterior, o que dá para o ocidente.' },
      { v: 33, en: 'He made the middle bar to pass through in the middle of the boards from the one end to the other.', pt: 'Fizeram que o travessão do meio passasse ao meio das tábuas duma extremidade até a outra.' },
      { v: 34, en: 'He overlaid the boards with gold, and made their rings of gold as places for the bars, and overlaid the bars with gold.', pt: 'E cobriram as tábuas de ouro, e de ouro fizeram as suas argolas como lugares para os travessoes; também os travessões cobriu de ouro.' },
      { v: 35, en: 'He made the veil of blue, purple, scarlet, and fine twined linen: with cherubim. He made it the work of a skillful workman.', pt: 'Fizeram então o véu de azul, púrpura, carmesim e linho fino torcido; com querubins, obra de artífice, o fizeram.' },
      { v: 36, en: 'He made four pillars of acacia for it, and overlaid them with gold. Their hooks were of gold. He cast four sockets of silver for them.', pt: 'E fizeram-lhe quatro colunas de madeira de acácia e as cobriram de ouro; e seus colchetes fizeram de ouro; e fundiram-lhes quatro bases de prata.' },
      { v: 37, en: 'He made a screen for the door of the tent, of blue, purple, scarlet, and fine twined linen, the work of an embroiderer;', pt: 'Fizeram também para a porta da tenda um reposteiro de azul, púrpura, carmesim e linho fino torcido, obra de bordador,' },
      { v: 38, en: 'and the five pillars of it with their hooks. He overlaid their capitals and their fillets with gold, and their five sockets were of brass.', pt: 'com as suas cinco colunas e os seus colchetes; e de ouro cobriu os seus capitéis e as suas faixas; e as suas cinco bases eram de bronze.' },
    ],
    37: [
      { v: 1, en: 'Bezalel made the ark of acacia wood. Its length was two and a half cubits, and its width a cubit and a half, and a cubit and a half its height.', pt: 'Fez também Bezaleel a arca de madeira de acácia; o seu comprimento era de dois côvados e meio, a sua largura de um côvado e meio, e a sua altura de um côvado e meio.' },
      { v: 2, en: 'He overlaid it with pure gold inside and outside, and made a molding of gold for it around it.', pt: 'Cobriu-a de ouro puro por dentro e por fora, fez-lhe uma moldura de ouro ao redor,' },
      { v: 3, en: 'He cast four rings of gold for it, in its four feet; even two rings on its one side, and two rings on its other side.', pt: 'e fundiu-lhe quatro argolas de ouro nos seus quatro cantos, duas argolas num lado e duas no outro.' },
      { v: 4, en: 'He made poles of acacia wood, and overlaid them with gold.', pt: 'Também fez varais de madeira de acácia, e os cobriu de ouro;' },
      { v: 5, en: 'He put the poles into the rings on the sides of the ark, to bear the ark.', pt: 'e meteu os varais pelas argolas aos lados da arca, para se levar a arca.' },
      { v: 6, en: 'He made a mercy seat of pure gold. Its length was two and a half cubits, and a cubit and a half its width.', pt: 'Fez também um propiciatório de ouro puro; o seu comprimento era de dois côvados e meio, e a sua largura de um côvado e meio.' },
      { v: 7, en: 'He made two cherubim of gold. He made them of beaten work, at the two ends of the mercy seat;', pt: 'Fez também dois querubins de ouro; de ouro batido os fez nas duas extremidades do propiciatório,' },
      { v: 8, en: 'one cherub at the one end, and one cherub at the other end. He made the cherubim of one piece with the mercy seat at its two ends.', pt: 'um querubim numa extremidade, e o outro querubim na outra; de uma só peça com o propiciatório fez os querubins nas duas extremidades dele.' },
      { v: 9, en: 'The cherubim spread out their wings on high, covering the mercy seat with their wings, with their faces toward one another. The faces of the cherubim were toward the mercy seat.', pt: 'E os querubins estendiam as suas asas por cima do propiciatório, cobrindo-o com as asas, tendo as faces voltadas um para o outro; para o propiciatório estavam voltadas as faces dos querubins.' },
      { v: 10, en: 'He made the table of acacia wood. Its length was two cubits, and its width was a cubit, and its height was a cubit and a half.', pt: 'Fez também a mesa de madeira de acácia; o seu comprimento era de dois côvados, a sua largura de um côvado, e a sua altura de um côvado e meio.' },
      { v: 11, en: 'He overlaid it with pure gold, and made a gold molding around it.', pt: 'cobriu-a de ouro puro, e fez-lhe uma moldura de ouro ao redor.' },
      { v: 12, en: 'He made a border of a hand width around it, and made a golden molding on its border around it.', pt: 'Fez-lhe também ao redor uma guarnição de quatro dedos de largura, e ao redor na guarnição fez uma moldura de ouro.' },
      { v: 13, en: 'He cast four rings of gold for it, and put the rings in the four corners that were on its four feet.', pt: 'Fundiu-lhe também nos quatro cantos que estavam sobre os seus quatro pés.' },
      { v: 14, en: 'The rings were close by the border, the places for the poles to carry the table.', pt: 'Junto da guarnição estavam as argolas para os lugares dos varais, para se levar a mesa.' },
      { v: 15, en: 'He made the poles of acacia wood, and overlaid them with gold, to carry the table.', pt: 'Fez também estes varais de madeira de acácia, e os cobriu de ouro, para se levar a mesa.' },
      { v: 16, en: 'He made the vessels which were on the table, its dishes, its spoons, its bowls, and its pitchers with which to pour out, of pure gold.', pt: 'E de ouro puro fez os utensílios que haviam de estar sobre a mesa, os seus pratos e as suas colheres, as suas tigelas e os seus cântaros, com que se haviam de oferecer as libações.' },
      { v: 17, en: 'He made the lamp stand of pure gold. He made the lamp stand of beaten work. Its base, its shaft, its cups, its buds, and its flowers were of one piece with it.', pt: 'Fez também o candelabro de ouro puro; de ouro batido fez o candelabro, tanto o seu pedestal como a sua haste; os seus copos, os seus cálices e as suas corolas formavam com ele uma só peça.' },
      { v: 18, en: 'There were six branches going out of its sides: three branches of the lamp stand out of its one side, and three branches of the lamp stand out of its other side:', pt: 'Dos seus lados saíam seis braços: três de um lado do candelabro e três do outro lado.' },
      { v: 19, en: 'three cups made like almond blossoms in one branch, a bud and a flower, and three cups made like almond blossoms in the other branch, a bud and a flower: so for the six branches going out of the lamp stand.', pt: 'Em um braço havia três copos a modo de flores de amêndoa, com cálice e corola; igualmente no outro braço três copos a modo de flores de amêndoa, com cálice e corola; assim se fez com os seis braços que saíam do candelabro.' },
      { v: 20, en: 'In the lamp stand were four cups made like almond blossoms, its buds and its flowers;', pt: 'Mas na haste central havia quatro copos a modo de flores de amêndoa, com os seus cálices e as suas corolas;' },
      { v: 21, en: 'and a bud under two branches of one piece with it, and a bud under two branches of one piece with it, and a bud under two branches of one piece with it, for the six branches going out of it.', pt: 'também havia um cálice debaixo de dois braços, formando com a haste uma só peça, e outro cálice debaixo de dois outros braços, de uma só peça com a haste, e ainda outro cálice debaixo de dois outros braços, de uma só peça com a haste; e assim se fez para os seis braços que saíam da haste.' },
      { v: 22, en: 'Their buds and their branches were of one piece with it. The whole thing was one beaten work of pure gold.', pt: 'Os seus cálices e os seus braços formavam uma só peça com a haste; o todo era uma obra batida de ouro puro.' },
      { v: 23, en: 'He made its seven lamps, and its snuffers, and its snuff dishes, of pure gold.', pt: 'Também de ouro puro lhe fez as lâmpadas, em número de sete, com os seus espevitadores e os seus cinzeiros.' },
      { v: 24, en: 'He made it of a talent of pure gold, with all its vessels.', pt: 'De um talento de ouro puro fez o candelabro e todos os seus utensilios.' },
      { v: 25, en: 'He made the altar of incense of acacia wood. It was square: its length was a cubit, and its width a cubit. Its height was two cubits. Its horns were of one piece with it.', pt: 'De madeira de acácia fez o altar do incenso; de um côvado era o seu comprimento, e de um côvado a sua largura, quadrado, e de dois côvados a sua altura; as suas pontas formavam uma só peça com ele.' },
      { v: 26, en: 'He overlaid it with pure gold, its top, its sides around it, and its horns. He made a gold molding around it.', pt: 'Cobriu-o de ouro puro, tanto a face superior como as suas paredes ao redor, e as suas pontas, e fez-lhe uma moldura de ouro ao redor.' },
      { v: 27, en: 'He made two golden rings for it under its molding crown, on its two ribs, on its two sides, for places for poles with which to carry it.', pt: 'Fez-lhe também duas argolas de ouro debaixo da sua moldura, nos dois cantos de ambos os lados, como lugares dos varais, para com eles se levar o altar.' },
      { v: 28, en: 'He made the poles of acacia wood, and overlaid them with gold.', pt: 'E os varais fez de madeira de acácia, e os cobriu de ouro.' },
      { v: 29, en: 'He made the holy anointing oil and the pure incense of sweet spices, after the art of the perfumer.', pt: 'Também fez o óleo sagrado da unção, e o incenso aromático, puro, qual obra do perfumista.' },
    ],
    38: [
      { v: 1, en: 'He made the altar of burnt offering of acacia wood. It was square. Its length was five cubits, its width was five cubits, and its height was three cubits.', pt: 'Fez também o altar do holocausto de madeira de acácia; de cinco côvados era o seu comprimento e de cinco côvados a sua largura, quadrado, e de três côvados a sua altura.' },
      { v: 2, en: 'He made its horns on its four corners. Its horns were of one piece with it, and he overlaid it with brass.', pt: 'E fez-lhe pontas nos seus quatro cantos; as suas pontas formavam uma só peça com ele; e cobriu-o de bronze.' },
      { v: 3, en: 'He made all the vessels of the altar, the pots, the shovels, the basins, the forks, and the fire pans. He made all its vessels of brass.', pt: 'Fez também todos os utensílios do altar: os cinzeiros, as pás, as bacias, os garfos e os braseiros; todos os seus utensílios fez de bronze.' },
      { v: 4, en: 'He made for the altar a grating of a network of brass, under the ledge around it beneath, reaching halfway up.', pt: 'Fez também para o altar um crivo de bronze em forma de rede, em baixo da borda ao redor, chegando ele até o meio do altar.' },
      { v: 5, en: 'He cast four rings for the four ends of brass grating, to be places for the poles.', pt: 'E fundiu quatro argolas para as quatro extremidades do crivo de bronze, como lugares dos varais.' },
      { v: 6, en: 'He made the poles of acacia wood, and overlaid them with brass.', pt: 'E fez os varais de madeira de acácia, e os cobriu de bronze.' },
      { v: 7, en: 'He put the poles into the rings on the sides of the altar, with which to carry it. He made it hollow with planks.', pt: 'E meteu os varais pelas argolas aos lados do altar, para com eles se levar o altar; fê-lo oco, de tábuas.' },
      { v: 8, en: 'He made the basin of brass, and its base of brass, out of the mirrors of the ministering women who ministered at the door of the Tent of Meeting.', pt: 'Fez também a pia de bronze com a sua base de bronze, dos espelhos das mulheres que se reuniam e ministravam à porta da tenda da revelação.' },
      { v: 9, en: 'He made the court: for the south side southward the hangings of the court were of fine twined linen, one hundred cubits;', pt: 'Fez também o átrio. Para o lado meridional as cortinas eram de linho fino torcido, de cem côvados de comprimento.' },
      { v: 10, en: 'their pillars were twenty, and their sockets twenty, of brass; the hooks of the pillars and their fillets were of silver.', pt: 'As suas colunas eram vinte, e vinte as suas bases, todas de bronze; os colchetes das colunas e as suas faixas eram de prata.' },
      { v: 11, en: 'For the north side one hundred cubits, their pillars twenty, and their sockets twenty, of brass; the hooks of the pillars, and their fillets, of silver.', pt: 'Para o lado setentrional as cortinas eram de cem côvados; as suas colunas eram vinte, e vinte as suas bases, todas de bronze; os colchetes das colunas e as suas faixas eram de prata.' },
      { v: 12, en: 'For the west side were hangings of fifty cubits, their pillars ten, and their sockets ten; the hooks of the pillars, and their fillets, of silver.', pt: 'Para o lado ocidental as cortinas eram de cinquenta covados; as suas colunas eram dez, e as suas bases dez; os colchetes das colunas e as suas faixas eram de prata.' },
      { v: 13, en: 'For the east side eastward fifty cubits.', pt: 'E para o lado oriental eram as cortinas de cinqüenta côvados.' },
      { v: 14, en: 'The hangings for the one side were fifteen cubits; their pillars three, and their sockets three;', pt: 'As cortinas para um lado da porta eram de quinze côvados; as suas colunas eram três e as suas bases três.' },
      { v: 15, en: 'and so for the other side: on this hand and that hand by the gate of the court were hangings of fifteen cubits; their pillars three, and their sockets three.', pt: 'Do mesmo modo para o outro lado; de um e de outro lado da porta do átrio havia cortinas de quinze côvados; as suas colunas eram três e as suas bases três.' },
      { v: 16, en: 'All the hangings around the court were of fine twined linen.', pt: 'Todas as cortinas do átrio ao redor eram de linho fino torcido.' },
      { v: 17, en: 'The sockets for the pillars were of brass. The hooks of the pillars and their fillets were of silver; and the overlaying of their capitals, of silver; and all the pillars of the court were filleted with silver.', pt: 'As bases das colunas eram de bronze; os colchetes das colunas e as suas faixas eram de prata; o revestimento dos seus capitéis era de prata; e todas as colunas do átrio eram cingidas de faixas de prata.' },
      { v: 18, en: 'The screen for the gate of the court was the work of the embroiderer, of blue, purple, scarlet, and fine twined linen. Twenty cubits was the length, and the height in the width was five cubits, like to the hangings of the court.', pt: 'O reposteiro da porta do átrio era de azul, púrpura, carmesim e linho fino torcido, obra de bordador; o comprimento era de vinte côvados, e a altura, na largura, de cinco côvados, conforme a altura das cortinas do átrio.' },
      { v: 19, en: 'Their pillars were four, and their sockets four, of brass; their hooks of silver, and the overlaying of their capitals, and their fillets, of silver.', pt: 'As suas colunas eram quatro, e quatro as suas bases, todas de bronze; os seus colchetes eram de prata, como também o revestimento dos capitéis, e as suas faixas.' },
      { v: 20, en: 'All the pins of the tabernacle, and around the court, were of brass.', pt: 'E todas as estacas do tabernáculo e do átrio ao redor eram de bronze.' },
      { v: 21, en: 'This is the amount of material used for the tabernacle, even the Tabernacle of the Testimony, as they were counted, according to the commandment of Moses, for the service of the Levites, by the hand of Ithamar, the son of Aaron the priest.', pt: 'Esta é a enumeração das coisas para o tabernáculo, a saber, o tabernáculo do testemunho, que por ordem de Moisés foram contadas para o ministério dos levitas, por intermédio de Itamar, filho de Arão, o sacerdote.' },
      { v: 22, en: 'Bezalel the son of Uri, the son of Hur, of the tribe of Judah, made all that Yahweh commanded Moses.', pt: 'Fez, pois, Bezaleel, filho de îri, filho de Hur, da tribo de Judá, tudo quanto o Senhor tinha ordenado a Moisés;' },
      { v: 23, en: 'With him was Oholiab, the son of Ahisamach, of the tribe of Dan, an engraver, and a skillful workman, and an embroiderer in blue, in purple, in scarlet, and in fine linen.', pt: 'e com ele Aoliabe, filho de Aisamaque, da tribo de Dã, gravador, desenhista, e bordador em azul, púrpura, carmesim e linho fino.' },
      { v: 24, en: 'All the gold that was used for the work in all the work of the sanctuary, even the gold of the offering, was twenty-nine talents, and seven hundred thirty shekels, after the shekel of the sanctuary.', pt: 'Todo o ouro gasto na obra, em toda a obra do santuário, a saber, o ouro da oferta, foi vinte e nove talentos e setecentos e trinta siclos, conforme o siclo do santuário.' },
      { v: 25, en: 'The silver of those who were counted of the congregation was one hundred talents, and one thousand seven hundred seventy-five shekels, after the shekel of the sanctuary:', pt: 'A prata dos arrolados da congregação montou em cem talentos e mil setecentos setenta e cinco siclos, conforme o siclo do santuário;' },
      { v: 26, en: 'a beka a head, that is, half a shekel, after the shekel of the sanctuary, for everyone who passed over to those who were counted, from twenty years old and upward, for six hundred three thousand five hundred fifty men.', pt: 'um beca para cada cabeça, isto é, meio siclo, conforme o siclo do santuário, de todo aquele que passava para os arrolados, da idade de vinte anos e acima, que foram seiscentos e três mil quinhentos e cinqüenta.' },
      { v: 27, en: 'The one hundred talents of silver were for casting the sockets of the sanctuary, and the sockets of the veil; one hundred sockets for the one hundred talents, a talent for a socket.', pt: 'E houve cem talentos de prata para fundir as bases do santuário e as bases do véu; para cem bases eram cem talentos, um talento para cada base.' },
      { v: 28, en: 'Of the one thousand seven hundred seventy-five shekels he made hooks for the pillars, overlaid their capitals, and made fillets for them.', pt: 'Mas dos mil setecentos e setenta e cinco siclos, fez colchetes para as colunas, e cobriu os seus capitéis e fez-lhes as faixas.' },
      { v: 29, en: 'The brass of the offering was seventy talents, and two thousand four hundred shekels.', pt: 'E o bronze da oferta foi setenta talentos e dois mil e quatrocentos siclos.' },
      { v: 30, en: 'With this he made the sockets to the door of the Tent of Meeting, the bronze altar, the bronze grating for it, all the vessels of the altar,', pt: 'Dele fez as bases da porta da tenda da revelação, o altar de bronze, e o crivo de bronze para ele, todos os utensílios do altar,' },
      { v: 31, en: 'the sockets around the court, the sockets of the gate of the court, all the pins of the tabernacle, and all the pins around the court.', pt: 'as bases do átrio ao redor e as bases da porta do átrio, todas as estacas do tabernáculo e todas as estacas do átrio ao redor.' },
    ],
    39: [
      { v: 1, en: 'Of the blue, purple, and scarlet, they made finely worked garments, for ministering in the holy place, and made the holy garments for Aaron; as Yahweh commanded Moses.', pt: 'Fizeram também de azul, púrpura e carmesim as vestes, finamente tecidas, para ministrar no lugar santo, e fizeram as vestes sagradas para Arão, como o Senhor ordenara a Moisés.' },
      { v: 2, en: 'He made the ephod of gold, blue, purple, scarlet, and fine twined linen.', pt: 'Assim se fez o éfode de ouro, azul, púrpura, carmesim e linho fino torcido;' },
      { v: 3, en: 'They beat the gold into thin plates, and cut it into wires, to work it in with the blue, the purple, the scarlet, and the fine linen, the work of the skillful workman.', pt: 'bateram o ouro em lâminas delgadas, as quais cortaram em fios, para entretecê-lo no azul, na púrpura, no carmesim e no linho fino, em obra de desenhista;' },
      { v: 4, en: 'They made shoulder straps for it, joined together. At the two ends it was joined together.', pt: 'fizeram-lhe ombreiras que se uniam; assim pelos seus dois cantos superiores foi ele unido.' },
      { v: 5, en: 'The skillfully woven band that was on it, with which to fasten it on, was of the same piece, like its work; of gold, of blue, purple, scarlet, and fine twined linen; as Yahweh commanded Moses.', pt: 'E o cinto da obra esmerada do éfode, que estava sobre ele, formava com ele uma só peça e era de obra semelhante, de ouro, azul, púrpura, carmesim e linho fino torcido, como o Senhor ordenara a Moisés.' },
      { v: 6, en: 'They worked the onyx stones, enclosed in settings of gold, engraved with the engravings of a signet, according to the names of the children of Israel.', pt: 'Também prepararam as pedras de berilo, engastadas em ouro, lavradas como a gravura de um selo, com os nomes dos filhos de Israel;' },
      { v: 7, en: 'He put them on the shoulder straps of the ephod, to be stones of memorial for the children of Israel, as Yahweh commanded Moses.', pt: 'as quais puseram sobre as ombreiras do éfode para servirem de pedras de memorial para os filhos de Israel, como o Senhor ordenara a Moisés.' },
      { v: 8, en: 'He made the breastplate, the work of a skillful workman, like the work of the ephod; of gold, of blue, purple, scarlet, and fine twined linen.', pt: 'Fez-se também o peitoral de obra de desenhista, semelhante à obra do éfode, de ouro, azul, púrpura, carmesim e linho fino torcido.' },
      { v: 9, en: 'It was square. They made the breastplate double. Its length was a span, and its width a span, being double.', pt: 'Quadrado e duplo fizeram o peitoral; o seu comprimento era de um palmo, e a sua largura de um palmo, sendo ele dobrado. f' },
      { v: 10, en: 'They set in it four rows of stones. A row of ruby, topaz, and beryl was the first row;', pt: 'E engastaram nele quatro fileiras de pedras: a primeira delas era de um sárdio, um topázio e uma esmeralda;' },
      { v: 11, en: 'and the second row, a turquoise, a sapphire, and an emerald;', pt: 'a segunda fileira era de uma granada, uma safira e um ônix;' },
      { v: 12, en: 'and the third row, a jacinth, an agate, and an amethyst;', pt: 'a terceira fileira era de um jacinto, uma ágata e uma ametista;' },
      { v: 13, en: 'and the fourth row, a chrysolite, an onyx, and a jasper. They were enclosed in gold settings.', pt: 'e a quarta fileira era de uma crisólita, um berilo e um jaspe; eram elas engastadas nos seus engastes de ouro.' },
      { v: 14, en: 'The stones were according to the names of the children of Israel, twelve, according to their names; like the engravings of a signet, everyone according to his name, for the twelve tribes.', pt: 'Estas pedras, pois, eram doze, segundo os nomes dos filhos de Israel; eram semelhantes a gravuras de selo, cada uma com o nome de uma das doze tribos.' },
      { v: 15, en: 'They made on the breastplate chains like cords, of braided work of pure gold.', pt: 'Também fizeram sobre o peitoral cadeiazinhas, semelhantes a cordas, obra de trança, de ouro puro.' },
      { v: 16, en: 'They made two settings of gold, and two gold rings, and put the two rings on the two ends of the breastplate.', pt: 'Fizeram também dois engastes de ouro e duas argolas de ouro, e fixaram as duas argolas nas duas extremidades do peitoral.' },
      { v: 17, en: 'They put the two braided chains of gold in the two rings at the ends of the breastplate.', pt: 'E meteram as duas cadeiazinhas de trança de ouro nas duas argolas, nas extremidades do peitoral.' },
      { v: 18, en: 'The other two ends of the two braided chains they put on the two settings, and put them on the shoulder straps of the ephod, in its front.', pt: 'E as outras duas pontas das duas cadeiazinhas de trança meteram nos dois engastes, e as puseram sobre as ombreiras do éfode, na parte dianteira dele.' },
      { v: 19, en: 'They made two rings of gold, and put them on the two ends of the breastplate, on its edge, which was toward the side of the ephod inward.', pt: 'Fizeram outras duas argolas de ouro, que puseram nas duas extremidades do peitoral, na sua borda que estava junto ao éfode por dentro.' },
      { v: 20, en: 'They made two more rings of gold, and put them on the two shoulder straps of the ephod underneath, in its front, close by its coupling, above the skillfully woven band of the ephod.', pt: 'Fizeram mais duas argolas de ouro, que puseram nas duas ombreiras do éfode, debaixo, na parte dianteira dele, junto à sua costura, acima do cinto de obra esmerada do éfode.' },
      { v: 21, en: 'They bound the breastplate by its rings to the rings of the ephod with a lace of blue, that it might be on the skillfully woven band of the ephod, and that the breastplate might not come loose from the ephod, as Yahweh commanded Moses.', pt: 'E ligaram o peitoral, pelas suas argolas, às argolas do éfode por meio de um cordão azul, para que estivesse sobre o cinto de obra esmerada do éfode, e o peitoral não se separasse do éfode, como o Senhor ordenara a Moisés.' },
      { v: 22, en: 'He made the robe of the ephod of woven work, all of blue.', pt: 'Fez-se também o manto do éfode de obra tecida, todo de azul,' },
      { v: 23, en: 'The opening of the robe in the middle of it was like the opening of a coat of mail, with a binding around its opening, that it should not be torn.', pt: 'e a abertura do manto no meio dele, como a abertura de cota de malha; esta abertura tinha um debrum em volta, para que não se rompesse.' },
      { v: 24, en: 'They made on the skirts of the robe pomegranates of blue, purple, scarlet, and twined linen.', pt: 'Nas abas do manto fizeram romãs de azul, púrpura e carmesim, de fio torcido.' },
      { v: 25, en: 'They made bells of pure gold, and put the bells between the pomegranates around the skirts of the robe, between the pomegranates;', pt: 'Fizeram também campainhas de ouro puro, pondo as campainhas nas abas do manto ao redor, entremeadas com as romãs;' },
      { v: 26, en: 'a bell and a pomegranate, a bell and a pomegranate, around the skirts of the robe, to minister in, as Yahweh commanded Moses.', pt: 'uma campainha e uma romã, outra campainha e outra romã, nas abas do manto ao redor, para uso no ministério, como o Senhor ordenara a Moisés.' },
      { v: 27, en: 'They made the coats of fine linen of woven work for Aaron, and for his sons,', pt: 'Fizeram também as túnicas de linho fino, de obra tecida, para Arão e para seus filhos,' },
      { v: 28, en: 'and the turban of fine linen, and the linen headbands of fine linen, and the linen breeches of fine twined linen,', pt: 'e a mitra de linho fino, e o ornato das tiaras de linho fino, e os calções de linho fino torcido,' },
      { v: 29, en: 'and the sash of fine twined linen, and blue, and purple, and scarlet, the work of the embroiderer, as Yahweh commanded Moses.', pt: 'e o cinto de linho fino torcido, e de azul, púrpura e carmesim, obra de bordador, como o Senhor ordenara a Moisés.' },
      { v: 30, en: 'They made the plate of the holy crown of pure gold, and wrote on it a writing, like the engravings of a signet: “HOLY TO YAHWEH”.', pt: 'Fizeram também, de ouro puro, a lâmina da coroa sagrada, e nela gravaram uma inscrição como a gravura de um selo: SANTO AO SENHOR.' },
      { v: 31, en: 'They tied to it a lace of blue, to fasten it on the turban above, as Yahweh commanded Moses.', pt: 'E a ela ataram um cordão azul, para prendê-la à parte superior da mitra, como o Senhor ordenara a Moisés.' },
      { v: 32, en: 'Thus all the work of the tabernacle of the Tent of Meeting was finished. The children of Israel did according to all that Yahweh commanded Moses; so they did.', pt: 'Assim se acabou toda a obra do tabernáculo da tenda da revelação; e os filhos de Israel fizeram conforme tudo o que o Senhor ordenara a Moisés; assim o fizeram.' },
      { v: 33, en: 'They brought the tabernacle to Moses, the tent, with all its furniture, its clasps, its boards, its bars, its pillars, its sockets,', pt: 'Depois trouxeram a Moisés o tabernáculo, a tenda e todos os seus utensílios, os seus colchetes, as suas tábuas, os seus travessões, as suas colunas e as suas bases;' },
      { v: 34, en: 'the covering of rams’ skins dyed red, the covering of sea cow hides, the veil of the screen,', pt: 'e a cobertura de peles de carneiros tintas de vermelho, e a cobertura de peles de golfinhos, e o véu do reposteiro;' },
      { v: 35, en: 'the ark of the testimony with its poles, the mercy seat,', pt: 'a arca do testemunho com os seus varais, e o propiciatório;' },
      { v: 36, en: 'the table, all its vessels, the show bread,', pt: 'a mesa com todos os seus utensílios, e os pães da proposição;' },
      { v: 37, en: 'the pure lamp stand, its lamps, even the lamps to be set in order, all its vessels, the oil for the light,', pt: 'o candelabro puro com suas lâmpadas todas em ordem, com todos os seus utensílios, e o azeite para a luz;' },
      { v: 38, en: 'the golden altar, the anointing oil, the sweet incense, the screen for the door of the Tent,', pt: 'também o altar de ouro, o óleo da unção e o incenso aromático, e o reposteiro para a porta da tenda;' },
      { v: 39, en: 'the bronze altar, its grating of brass, its poles, all of its vessels, the basin and its base,', pt: 'o altar de bronze e o seu crivo de bronze, os seus varais, e todos os seus utensílios; a pia e a sua base;' },
      { v: 40, en: 'the hangings of the court, its pillars, its sockets, the screen for the gate of the court, its cords, its pins, all the instruments of the service of the tabernacle, for the Tent of Meeting,', pt: 'as cortinas do átrio, as suas colunas e as suas bases, e o reposteiro para a porta do átrio, as suas cordas e as suas estacas, e todos os utensílios do serviço do tabernáculo, para a tenda da revelação;' },
      { v: 41, en: 'the finely worked garments for ministering in the holy place, the holy garments for Aaron the priest, and the garments of his sons, to minister in the priest’s office.', pt: 'as vestes finamente tecidas para uso no ministério no lugar santo, e as vestes sagradas para Arão, o sacerdote, e as vestes para seus filhos, para administrarem o sacerdócio.' },
      { v: 42, en: 'According to all that Yahweh commanded Moses, so the children of Israel did all the work.', pt: 'Conforme tudo o que o Senhor ordenara a Moisés, assim fizeram os filhos de Israel toda a obra.' },
      { v: 43, en: 'Moses saw all the work, and behold, they had done it as Yahweh had commanded, even so had they done it: and Moses blessed them.', pt: 'Viu, pois, Moisés toda a obra, e eis que a tinham feito; como o Senhor ordenara, assim a fizeram; então Moisés os abençoou.' },
    ],
    40: [
      { v: 1, en: 'Yahweh spoke to Moses, saying,', pt: 'Depois disse o Senhor a Moisés:' },
      { v: 2, en: '“On the first day of the first month you shall raise up the tabernacle of the Tent of Meeting.', pt: 'No primeiro mês, no primeiro dia do mês, levantarás o tabernáculo da tenda da revelação,' },
      { v: 3, en: 'You shall put the ark of the testimony in it, and you shall screen the ark with the veil.', pt: 'e porás nele a arca do testemunho, e resguardaras a arca com o véu.' },
      { v: 4, en: 'You shall bring in the table, and set in order the things that are on it. You shall bring in the lamp stand, and light its lamps.', pt: 'Depois colocarás nele a mesa, e porás em ordem o que se deve pôr em ordem nela; também colocarás nele o candelabro, e acenderás as suas lâmpadas.' },
      { v: 5, en: 'You shall set the golden altar for incense before the ark of the testimony, and put the screen of the door to the tabernacle.', pt: 'E porás o altar de ouro para o incenso diante da arca do testemunho; então pendurarás o reposteiro da porta do tabernáculo.' },
      { v: 6, en: '“You shall set the altar of burnt offering before the door of the tabernacle of the Tent of Meeting.', pt: 'E porás o altar do holocausto diante da porta do tabernáculo da tenda da revelação.' },
      { v: 7, en: 'You shall set the basin between the Tent of Meeting and the altar, and shall put water therein.', pt: 'E porás a pia entre a tenda da revelação e o altar, e nela deitarás água.' },
      { v: 8, en: 'You shall set up the court around it, and hang up the screen of the gate of the court.', pt: 'Depois levantarás as cortinas do átrio ao redor, e pendurarás o reposteiro da porta do átrio.' },
      { v: 9, en: '“You shall take the anointing oil, and anoint the tabernacle, and all that is in it, and shall make it holy, and all its furniture: and it will be holy.', pt: 'Então tomarás o óleo da unção e ungirás o tabernáculo, e tudo o que há nele; e o santificarás, a ele e a todos os seus móveis; e será santo.' },
      { v: 10, en: 'You shall anoint the altar of burnt offering, with all its vessels, and sanctify the altar: and the altar will be most holy.', pt: 'Ungirás também o altar do holocausto, e todos os seus utensílios, e santificarás o altar; e o altar será santíssimo.' },
      { v: 11, en: 'You shall anoint the basin and its base, and sanctify it.', pt: 'Então ungirás a pia e a sua base, e a santificarás.' },
      { v: 12, en: '“You shall bring Aaron and his sons to the door of the Tent of Meeting, and shall wash them with water.', pt: 'E farás chegar Arão e seus filhos à porta da tenda da revelação, e os lavarás com água.' },
      { v: 13, en: 'You shall put on Aaron the holy garments; and you shall anoint him, and sanctify him, that he may minister to me in the priest’s office.', pt: 'E vestirás Arão das vestes sagradas, e o ungirás, e o santificarás, para que me administre o sacerdócio.' },
      { v: 14, en: 'You shall bring his sons, and put coats on them.', pt: 'Também farás chegar seus filhos, e os vestirás de túnicas,' },
      { v: 15, en: 'You shall anoint them, as you anointed their father, that they may minister to me in the priest’s office. Their anointing shall be to them for an everlasting priesthood throughout their generations.”', pt: 'e os ungirás como ungiste a seu pai, para que me administrem o sacerdócio, e a sua unção lhes será por sacerdócio perpétuo pelas suas gerações.' },
      { v: 16, en: 'Moses did so. According to all that Yahweh commanded him, so he did.', pt: 'E Moisés fez conforme tudo o que o Senhor lhe ordenou; assim o fez.' },
      { v: 17, en: 'In the first month in the second year, on the first day of the month, the tabernacle was raised up.', pt: 'E no primeiro mês do segundo ano, no primeiro dia do mês, o tabernáculo foi levantado.' },
      { v: 18, en: 'Moses raised up the tabernacle, and laid its sockets, and set up its boards, and put in its bars, and raised up its pillars.', pt: 'Levantou, pois, Moisés o tabernáculo: lançou as suas bases; armou as suas tábuas e nestas meteu os seus travessões; levantou as suas colunas;' },
      { v: 19, en: 'He spread the covering over the tent, and put the roof of the tabernacle above on it, as Yahweh commanded Moses.', pt: 'estendeu a tenda por cima do tabernáculo, e pôs a cobertura da tenda sobre ela, em cima, como o Senhor lhe ordenara.' },
      { v: 20, en: 'He took and put the testimony into the ark, and set the poles on the ark, and put the mercy seat above on the ark.', pt: 'Então tomou o testemunho e pô-lo na arca, ajustou à arca os varais, e pôs-lhe o propiciatório em cima.' },
      { v: 21, en: 'He brought the ark into the tabernacle, and set up the veil of the screen, and screened the ark of the testimony, as Yahweh commanded Moses.', pt: 'Depois introduziu a arca no tabernáculo, e pendurou o véu do reposteiro, e assim resguardou a arca do testemunho, como o Senhor lhe ordenara.' },
      { v: 22, en: 'He put the table in the Tent of Meeting, on the side of the tabernacle northward, outside of the veil.', pt: 'Pôs também a mesa na tenda da revelação, ao lado do tabernáculo para o norte, fora do véu,' },
      { v: 23, en: 'He set the bread in order on it before Yahweh, as Yahweh commanded Moses.', pt: 'e sobre ela pôs em ordem o pão perante o Senhor, como o Senhor lhe ordenara.' },
      { v: 24, en: 'He put the lamp stand in the Tent of Meeting, opposite the table, on the side of the tabernacle southward.', pt: 'Pôs também na tenda da revelação o candelabro defronte da mesa, ao lado do tabernáculo para o sul,' },
      { v: 25, en: 'He lit the lamps before Yahweh, as Yahweh commanded Moses.', pt: 'e acendeu as lâmpadas perante o Senhor, como o Senhor lhe ordenara.' },
      { v: 26, en: 'He put the golden altar in the Tent of Meeting before the veil;', pt: 'Pôs o altar de ouro na tenda da revelação diante do véu,' },
      { v: 27, en: 'and he burned incense of sweet spices on it, as Yahweh commanded Moses.', pt: 'e sobre ele queimou o incenso de especiarias aromáticas, como o Senhor lhe ordenara.' },
      { v: 28, en: 'He put up the screen of the door to the tabernacle.', pt: 'Pendurou o reposteiro à: porta do tabernáculo,' },
      { v: 29, en: 'He set the altar of burnt offering at the door of the tabernacle of the Tent of Meeting, and offered on it the burnt offering and the meal offering, as Yahweh commanded Moses.', pt: 'e pôs o altar do holocausto à porta do tabernáculo da tenda da revelação, e sobre ele ofereceu o holocausto e a oferta de cereais, como o Senhor lhe ordenara.' },
      { v: 30, en: 'He set the basin between the Tent of Meeting and the altar, and put water therein, with which to wash.', pt: 'Depois: colocou a pia entre a tenda da revelação e o altar, e nela deitou água para a as abluções.' },
      { v: 31, en: 'Moses, Aaron, and his sons washed their hands and their feet there.', pt: 'E junto dela Moisés, e Arão e seus filhos lavaram as mãos e os pés.' },
      { v: 32, en: 'When they went into the Tent of Meeting, and when they came near to the altar, they washed, as Yahweh commanded Moses.', pt: 'Quando entravam na tenda da revelação, e quando chegavam ao altar, lavavam-se, como o Senhor ordenara a Moises.' },
      { v: 33, en: 'He raised up the court around the tabernacle and the altar, and set up the screen of the gate of the court. So Moses finished the work.', pt: 'Levantou também as cortinas do átrio ao redor do tabernáculo e do altar e pendurou o reposteiro da porta do átrio. Assim Moisés acabou a obra.' },
      { v: 34, en: 'Then the cloud covered the Tent of Meeting, and Yahweh’s glory filled the tabernacle.', pt: 'Então a nuvem cobriu a tenda da revelação, e a glória do Senhor encheu o tabernáculo;' },
      { v: 35, en: 'Moses wasn’t able to enter into the Tent of Meeting, because the cloud stayed on it, and Yahweh’s glory filled the tabernacle.', pt: 'de maneira que Moisés não podia entrar na tenda da revelação, porquanto a nuvem repousava sobre ela, e a glória do Senhor enchia o tabernáculo.' },
      { v: 36, en: 'When the cloud was taken up from over the tabernacle, the children of Israel went onward, throughout all their journeys;', pt: 'Quando, pois, a nuvem se levantava de sobre o tabernáculo, prosseguiam os filhos de Israel, em todas as suas jornadas;' },
      { v: 37, en: 'but if the cloud wasn’t taken up, then they didn’t travel until the day that it was taken up.', pt: 'se a nuvem, porém, não se levantava, não caminhavam até o dia em que ela se levantasse.' },
      { v: 38, en: 'For the cloud of Yahweh was on the tabernacle by day, and there was fire in the cloud by night, in the sight of all the house of Israel, throughout all their journeys.', pt: 'Porquanto a nuvem do Senhor estava de dia sobre o tabernáculo, e o fogo estava de noite sobre ele, perante os olhos de toda a casa de Israel, em todas as suas jornadas.' },
    ],
  },
};

export default book;
